--
-- TOC entry 921 (class 1255 OID 56552)
-- Name: _edge_webhook_post(text, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public._edge_webhook_post(p_function_name text, p_secret_name text, p_payload jsonb) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_secret text;
  v_id bigint;
BEGIN
  -- Validate secret existence at enqueue-time so triggers fail fast if misconfigured.
  v_secret := public._vault_secret(p_secret_name);

  IF v_secret IS NULL OR length(v_secret) < 10 THEN
    RAISE EXCEPTION 'Missing Vault secret % for edge webhook', p_secret_name;
  END IF;

  INSERT INTO public.edge_webhook_outbox(function_name, secret_name, payload, status, next_attempt_at)
  VALUES (p_function_name, p_secret_name, COALESCE(p_payload, '{}'::jsonb), 'pending', now())
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


