--
-- TOC entry 1021 (class 1255 OID 63359)
-- Name: admin_cash_agent_next_doc_no_v1(uuid, text, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_cash_agent_next_doc_no_v1(p_agent_id uuid, p_kind text, p_day date DEFAULT CURRENT_DATE) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_code text;
  v_day date := coalesce(p_day, current_date);
  v_seq integer;
  v_kind text := lower(coalesce(p_kind, ''));
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not v_is_admin then
    raise exception 'not_authorized';
  end if;
  if p_agent_id is null then
    raise exception 'invalid_agent';
  end if;
  if v_kind not in ('receipt', 'payout') then
    raise exception 'invalid_kind';
  end if;

  select ca.code into v_code
  from public.cash_agents ca
  where ca.id = p_agent_id and ca.is_active = true
  limit 1;

  if not found then
    raise exception 'agent_not_found_or_inactive';
  end if;

  insert into public.agent_daily_counters(agent_id, day)
  values (p_agent_id, v_day)
  on conflict (agent_id, day) do nothing;

  -- Lock the counter row for update
  select
    case when v_kind = 'receipt' then adc.next_receipt_seq else adc.next_payout_seq end
  into v_seq
  from public.agent_daily_counters adc
  where adc.agent_id = p_agent_id and adc.day = v_day
  for update;

  if v_kind = 'receipt' then
    update public.agent_daily_counters
      set next_receipt_seq = next_receipt_seq + 1,
          updated_at = now()
      where agent_id = p_agent_id and day = v_day;
    return v_code || '-' || to_char(v_day, 'YYYYMMDD') || '-R' || lpad(v_seq::text, 4, '0');
  else
    update public.agent_daily_counters
      set next_payout_seq = next_payout_seq + 1,
          updated_at = now()
      where agent_id = p_agent_id and day = v_day;
    return v_code || '-' || to_char(v_day, 'YYYYMMDD') || '-P' || lpad(v_seq::text, 4, '0');
  end if;
end;
$$;


ALTER FUNCTION public.admin_cash_agent_next_doc_no_v1(p_agent_id uuid, p_kind text, p_day date) OWNER TO postgres;

--
-- TOC entry 676 (class 1255 OID 63362)
