--
-- TOC entry 1215 (class 1255 OID 63366)
-- Name: admin_cashbox_close_day_v1(uuid, date, integer, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_cashbox_close_day_v1(p_agent_id uuid, p_day date, p_counted_cash_iqd integer, p_note text, p_idempotency_key text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_day date := coalesce(p_day, current_date);
  v_expected bigint;
  v_id uuid;
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not v_is_admin then
    raise exception 'not_authorized';
  end if;
  if p_agent_id is null then
    raise exception 'invalid_agent';
  end if;
  if p_counted_cash_iqd is null or p_counted_cash_iqd < 0 then
    raise exception 'invalid_amount';
  end if;

  if p_idempotency_key is not null then
    select c.id into v_id
    from public.cashbox_daily_closings c
    where c.idempotency_key = p_idempotency_key
    limit 1;
    if found then
      return v_id;
    end if;
  end if;

  select
    coalesce(sum(sr.amount_iqd),0)::bigint
    - coalesce((select sum(sp.amount_iqd)::bigint from public.settlement_payouts sp where sp.agent_id = p_agent_id and (sp.paid_at AT TIME ZONE 'UTC')::date = v_day),0)
  into v_expected
  from public.settlement_receipts sr
  where sr.agent_id = p_agent_id and (sr.received_at AT TIME ZONE 'UTC')::date = v_day;

  insert into public.cashbox_daily_closings(agent_id, day, counted_cash_iqd, expected_net_iqd, variance_iqd, note, closed_by, idempotency_key)
  values (p_agent_id, v_day, p_counted_cash_iqd, v_expected, (p_counted_cash_iqd::bigint - v_expected), nullif(btrim(p_note), ''), v_uid, p_idempotency_key)
  on conflict (agent_id, day) do update
    set counted_cash_iqd = excluded.counted_cash_iqd,
        expected_net_iqd = excluded.expected_net_iqd,
        variance_iqd = excluded.variance_iqd,
        note = excluded.note,
        closed_by = excluded.closed_by,
        closed_at = now(),
        idempotency_key = excluded.idempotency_key
  returning id into v_id;

  return v_id;
end;
$$;


ALTER FUNCTION public.admin_cashbox_close_day_v1(p_agent_id uuid, p_day date, p_counted_cash_iqd integer, p_note text, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 1548 (class 1255 OID 63365)
-- Name: admin_cashbox_reconciliation_v1(uuid, date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_cashbox_reconciliation_v1(p_agent_id uuid, p_date_from date, p_date_to date) RETURNS TABLE(day date, receipts_iqd bigint, receipts_count bigint, payouts_iqd bigint, payouts_count bigint, expected_net_iqd bigint, counted_cash_iqd integer, variance_iqd bigint, closed_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_from date := coalesce(p_date_from, current_date - 13);
  v_to date := coalesce(p_date_to, current_date);
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not v_is_admin then
    raise exception 'not_authorized';
  end if;
  if p_agent_id is null then
    raise exception 'invalid_agent';
  end if;
  if v_to < v_from then
    raise exception 'invalid_range';
  end if;

  return query
  with days as (
    select generate_series(v_from, v_to, interval '1 day')::date as day
  ),
  r as (
    select ((sr.received_at AT TIME ZONE 'UTC')::date) as day, sum(sr.amount_iqd)::bigint as receipts_iqd, count(*)::bigint as receipts_count
    from public.settlement_receipts sr
    where sr.agent_id = p_agent_id
    group by 1
  ),
  p as (
    select ((sp.paid_at AT TIME ZONE 'UTC')::date) as day, sum(sp.amount_iqd)::bigint as payouts_iqd, count(*)::bigint as payouts_count
    from public.settlement_payouts sp
    where sp.agent_id = p_agent_id
    group by 1
  )
  select
    d.day,
    coalesce(r.receipts_iqd, 0) as receipts_iqd,
    coalesce(r.receipts_count, 0) as receipts_count,
    coalesce(p.payouts_iqd, 0) as payouts_iqd,
    coalesce(p.payouts_count, 0) as payouts_count,
    coalesce(r.receipts_iqd, 0) - coalesce(p.payouts_iqd, 0) as expected_net_iqd,
    c.counted_cash_iqd,
    c.variance_iqd,
    c.closed_at
  from days d
  left join r on r.day = d.day
  left join p on p.day = d.day
  left join public.cashbox_daily_closings c on c.agent_id = p_agent_id and c.day = d.day
  order by d.day desc;
end;
$$;


ALTER FUNCTION public.admin_cashbox_reconciliation_v1(p_agent_id uuid, p_date_from date, p_date_to date) OWNER TO postgres;

--
-- TOC entry 1731 (class 1255 OID 62323)
-- Name: admin_clone_pricing_config_v1(uuid, text, timestamp with time zone, boolean, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_clone_pricing_config_v1(p_source_id uuid, p_name text, p_effective_from timestamp with time zone DEFAULT now(), p_active boolean DEFAULT true, p_set_default boolean DEFAULT false) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_role text;
  v_new_id uuid;
  v_src record;
begin
  v_role := coalesce(auth.jwt() ->> 'role', '');
  if v_role <> 'service_role' and not public.is_admin() then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  select * into v_src
  from public.pricing_configs
  where id = p_source_id;

  if v_src.id is null then
    raise exception 'source pricing_config not found';
  end if;

  insert into public.pricing_configs (
    name,
    version,
    effective_from,
    effective_to,
    is_default,
    active,
    currency,
    base_fare_iqd,
    per_km_iqd,
    per_min_iqd,
    minimum_fare_iqd,
    max_surge_multiplier
  ) values (
    nullif(btrim(coalesce(p_name, '')), ''),
    coalesce(v_src.version, 1) + 1,
    coalesce(p_effective_from, now()),
    null,
    coalesce(p_set_default, false),
    coalesce(p_active, true),
    coalesce(v_src.currency, 'IQD'),
    v_src.base_fare_iqd,
    v_src.per_km_iqd,
    v_src.per_min_iqd,
    v_src.minimum_fare_iqd,
    v_src.max_surge_multiplier
  ) returning id into v_new_id;

  if coalesce(p_set_default, false) then
    perform public.admin_set_default_pricing_config_v1(v_new_id);
  end if;

  return v_new_id;
end;
$$;


ALTER FUNCTION public.admin_clone_pricing_config_v1(p_source_id uuid, p_name text, p_effective_from timestamp with time zone, p_active boolean, p_set_default boolean) OWNER TO postgres;

