--
-- TOC entry 728 (class 1255 OID 62307)
-- Name: admin_create_service_area_bbox_v3(text, text, double precision, double precision, double precision, double precision, integer, boolean, uuid, integer, numeric, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_create_service_area_bbox_v3(p_name text, p_governorate text, p_min_lat double precision, p_min_lng double precision, p_max_lat double precision, p_max_lng double precision, p_priority integer DEFAULT 0, p_is_active boolean DEFAULT true, p_pricing_config_id uuid DEFAULT NULL::uuid, p_min_base_fare_iqd integer DEFAULT NULL::integer, p_surge_multiplier numeric DEFAULT NULL::numeric, p_surge_reason text DEFAULT NULL::text, p_cash_rounding_step_iqd integer DEFAULT NULL::integer) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions'
    AS $$
declare
  v_id uuid;
  v_role text;
begin
  v_role := coalesce(auth.jwt() ->> 'role', '');
  if v_role <> 'service_role' and not public.is_admin() then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  insert into public.service_areas (
    name, governorate, is_active, priority, pricing_config_id,
    min_base_fare_iqd, surge_multiplier, surge_reason,
    cash_rounding_step_iqd,
    geom
  )
  values (
    p_name,
    p_governorate,
    coalesce(p_is_active, true),
    coalesce(p_priority, 0),
    p_pricing_config_id,
    p_min_base_fare_iqd,
    greatest(coalesce(p_surge_multiplier, 1.0), 1.0),
    nullif(btrim(coalesce(p_surge_reason, '')), ''),
    greatest(coalesce(p_cash_rounding_step_iqd, 250), 1),
    extensions.ST_Multi(extensions.ST_MakeEnvelope(p_min_lng, p_min_lat, p_max_lng, p_max_lat, 4326))
  )
  on conflict (name, governorate) do update
    set is_active = excluded.is_active,
        priority = excluded.priority,
        pricing_config_id = excluded.pricing_config_id,
        min_base_fare_iqd = excluded.min_base_fare_iqd,
        surge_multiplier = excluded.surge_multiplier,
        surge_reason = excluded.surge_reason,
        cash_rounding_step_iqd = excluded.cash_rounding_step_iqd,
        geom = excluded.geom,
        updated_at = now()
  returning id into v_id;

  return v_id;
end;
$$;


