--
-- TOC entry 1321 (class 1255 OID 44423)
-- Name: admin_grant_user(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_grant_user(p_user uuid, p_note text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
begin
  if not (select public.is_admin()) then
    raise exception 'forbidden';
  end if;

  if p_user is null then
    raise exception 'missing_user_id';
  end if;

  insert into public.admin_users (user_id, created_by, note)
  values (p_user, (select auth.uid()), p_note)
  on conflict (user_id) do update
    set note = coalesce(excluded.note, public.admin_users.note);

  insert into public.admin_audit_log (actor_id, action, target_user_id, note)
  values ((select auth.uid()), 'grant_admin', p_user, p_note);
end;
$$;


ALTER FUNCTION public.admin_grant_user(p_user uuid, p_note text) OWNER TO postgres;

--
-- TOC entry 816 (class 1255 OID 65018)
-- Name: admin_grant_user_v1(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_grant_user_v1(p_user uuid, p_note text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
BEGIN
  -- Reuse the existing audited implementation.
  PERFORM public.admin_grant_user(p_user => p_user, p_note => p_note);
  RETURN jsonb_build_object('ok', true);
EXCEPTION
  WHEN others THEN
    -- Surface the original error message for UI mapping.
    RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION public.admin_grant_user_v1(p_user uuid, p_note text) OWNER TO postgres;

