CREATE FUNCTION public.admin_maps_provider_capability_list_v1() RETURNS TABLE(provider_code text, capability text, enabled boolean, unit_label text, note text, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'not_authenticated';
  END IF;
  IF NOT (SELECT public.is_admin()) THEN
    RAISE EXCEPTION 'not_authorized';
  END IF;

  RETURN QUERY
  SELECT mc.provider_code, mc.capability, mc.enabled, mc.unit_label, mc.note, mc.updated_at
  FROM public.maps_provider_capabilities mc
  ORDER BY mc.provider_code, mc.capability;
