CREATE FUNCTION public.admin_maps_provider_set_v2(p_provider_code text, p_priority integer, p_enabled boolean, p_language text, p_region text, p_monthly_soft_cap_units integer, p_monthly_hard_cap_units integer, p_cache_enabled boolean DEFAULT false, p_cache_ttl_seconds integer DEFAULT NULL::integer, p_note text DEFAULT NULL::text) RETURNS void
