--
-- TOC entry 820 (class 1255 OID 66271)
-- Name: admin_maps_requests_stats_v1(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_maps_requests_stats_v1() RETURNS TABLE(provider_code text, capability text, requests_1h integer, requests_24h integer, billed_units_1h bigint, billed_units_24h bigint, cache_hits_1h integer, cache_hits_24h integer, errors_1h integer, errors_24h integer, rate_limited_1h integer, rate_limited_24h integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not (select public.is_admin()) then
    raise exception 'not_authorized';
  end if;

  return query
  select
    mc.provider_code,
    mc.capability,
    coalesce(count(l.*) filter (where l.created_at >= now() - interval '1 hour'), 0)::int as requests_1h,
    coalesce(count(l.*), 0)::int as requests_24h,
    coalesce(sum(l.billed_units) filter (where l.created_at >= now() - interval '1 hour'), 0)::bigint as billed_units_1h,
    coalesce(sum(l.billed_units), 0)::bigint as billed_units_24h,
    coalesce(count(l.*) filter (where l.created_at >= now() - interval '1 hour' and l.cache_hit = true), 0)::int as cache_hits_1h,
    coalesce(count(l.*) filter (where l.cache_hit = true), 0)::int as cache_hits_24h,
    coalesce(count(l.*) filter (where l.created_at >= now() - interval '1 hour' and l.http_status >= 400), 0)::int as errors_1h,
    coalesce(count(l.*) filter (where l.http_status >= 400), 0)::int as errors_24h,
    coalesce(count(l.*) filter (where l.created_at >= now() - interval '1 hour' and l.http_status = 429), 0)::int as rate_limited_1h,
    coalesce(count(l.*) filter (where l.http_status = 429), 0)::int as rate_limited_24h
  from public.maps_provider_capabilities mc
  join public.maps_providers mp on mp.provider_code = mc.provider_code
  left join public.maps_requests_log l
    on l.provider_code = mc.provider_code
   and l.capability = mc.capability
   and l.created_at >= now() - interval '24 hours'
   and not (l.http_status = 424 and coalesce(l.error_code, '') = 'missing_provider_key')
  group by mc.provider_code, mc.capability
  order by mc.provider_code, mc.capability;
end;
$$;


ALTER FUNCTION public.admin_maps_requests_stats_v1() OWNER TO postgres;

--
-- TOC entry 1352 (class 1255 OID 39765)
-- Name: admin_mark_stale_drivers_offline(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_mark_stale_drivers_offline(p_stale_after_seconds integer DEFAULT 120, p_limit integer DEFAULT 500) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog'
    AS $$
DECLARE
  v_count integer := 0;
  v_limit integer;
BEGIN
  v_limit := greatest(1, least(coalesce(p_limit, 500), 5000));

  WITH stale AS (
    SELECT d.id
    FROM public.drivers d
    JOIN public.driver_locations dl ON dl.driver_id = d.id
    WHERE d.status = 'available'
      AND dl.updated_at < now() - make_interval(secs => greatest(1, coalesce(p_stale_after_seconds, 120)))
    ORDER BY dl.updated_at ASC
    LIMIT v_limit
  )
  UPDATE public.drivers d
  SET status = 'offline'
  WHERE d.id IN (SELECT id FROM stale);

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION public.admin_mark_stale_drivers_offline(p_stale_after_seconds integer, p_limit integer) OWNER TO postgres;

