--
-- TOC entry 1646 (class 1255 OID 63193)
-- Name: admin_merchant_commission_list_v1(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_merchant_commission_list_v1(p_limit integer DEFAULT 200, p_offset integer DEFAULT 0) RETURNS TABLE(merchant_id uuid, business_name text, specific_rate_bps integer, specific_flat_fee_iqd bigint, effective_rate_bps integer, effective_flat_fee_iqd bigint, updated_at timestamp with time zone, is_default boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_default public.merchant_commission_configs;
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'admin_only';
  END IF;

  SELECT * INTO v_default
  FROM public.merchant_commission_configs c
  WHERE c.is_active = true
    AND c.merchant_id IS NULL
  ORDER BY c.updated_at DESC
  LIMIT 1;

  RETURN QUERY
    SELECT
      NULL::uuid AS merchant_id,
      'DEFAULT'::text AS business_name,
      v_default.rate_bps AS specific_rate_bps,
      v_default.flat_fee_iqd AS specific_flat_fee_iqd,
      COALESCE(v_default.rate_bps, 0) AS effective_rate_bps,
      COALESCE(v_default.flat_fee_iqd, 0) AS effective_flat_fee_iqd,
      COALESCE(v_default.updated_at, now()) AS updated_at,
      true AS is_default
    UNION ALL
    SELECT
      m.id AS merchant_id,
      m.business_name,
      c.rate_bps AS specific_rate_bps,
      c.flat_fee_iqd AS specific_flat_fee_iqd,
      COALESCE(c.rate_bps, COALESCE(v_default.rate_bps, 0)) AS effective_rate_bps,
      COALESCE(c.flat_fee_iqd, COALESCE(v_default.flat_fee_iqd, 0)) AS effective_flat_fee_iqd,
      COALESCE(c.updated_at, COALESCE(v_default.updated_at, now())) AS updated_at,
      false AS is_default
    FROM public.merchants m
    LEFT JOIN LATERAL (
      SELECT c2.*
      FROM public.merchant_commission_configs c2
      WHERE c2.is_active = true
        AND c2.merchant_id = m.id
      ORDER BY c2.updated_at DESC
      LIMIT 1
    ) c ON true
    ORDER BY is_default DESC, updated_at DESC
    LIMIT greatest(1, least(coalesce(p_limit, 200), 500))
    OFFSET greatest(coalesce(p_offset, 0), 0);
END;
$$;


ALTER FUNCTION public.admin_merchant_commission_list_v1(p_limit integer, p_offset integer) OWNER TO postgres;

