--
-- TOC entry 1604 (class 1255 OID 63194)
-- Name: admin_merchant_commission_set_v1(uuid, integer, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_merchant_commission_set_v1(p_merchant_id uuid, p_rate_bps integer, p_flat_fee_iqd bigint) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'admin_only';
  END IF;

  IF p_rate_bps IS NULL OR p_rate_bps < 0 OR p_rate_bps > 10000 THEN
    RAISE EXCEPTION 'invalid_rate_bps';
  END IF;

  IF p_flat_fee_iqd IS NULL OR p_flat_fee_iqd < 0 THEN
    RAISE EXCEPTION 'invalid_flat_fee';
  END IF;

  IF p_merchant_id IS NULL THEN
    UPDATE public.merchant_commission_configs
    SET is_active = false
    WHERE merchant_id IS NULL
      AND is_active = true;

    INSERT INTO public.merchant_commission_configs (merchant_id, rate_bps, flat_fee_iqd, is_active)
    VALUES (NULL, p_rate_bps, p_flat_fee_iqd, true);

    RETURN;
  END IF;

  INSERT INTO public.merchant_commission_configs (merchant_id, rate_bps, flat_fee_iqd, is_active)
  VALUES (p_merchant_id, p_rate_bps, p_flat_fee_iqd, true)
  ON CONFLICT (merchant_id) WHERE merchant_id IS NOT NULL
  DO UPDATE SET
    rate_bps = EXCLUDED.rate_bps,
    flat_fee_iqd = EXCLUDED.flat_fee_iqd,
    is_active = true,
    updated_at = now();

  RETURN;
END;
$$;


ALTER FUNCTION public.admin_merchant_commission_set_v1(p_merchant_id uuid, p_rate_bps integer, p_flat_fee_iqd bigint) OWNER TO postgres;

--
-- TOC entry 1380 (class 1255 OID 63382)
-- Name: admin_merchant_commission_set_v2(uuid, integer, bigint, integer, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_merchant_commission_set_v2(p_merchant_id uuid, p_rate_bps integer, p_flat_fee_iqd bigint, p_cod_handling_rate_bps integer, p_cod_handling_flat_fee_iqd bigint) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'not_authorized';
  END IF;

  IF p_rate_bps IS NULL OR p_rate_bps < 0 OR p_rate_bps > 10000 THEN
    RAISE EXCEPTION 'invalid_rate_bps';
  END IF;
  IF p_flat_fee_iqd IS NULL OR p_flat_fee_iqd < 0 THEN
    RAISE EXCEPTION 'invalid_flat_fee';
  END IF;
  IF p_cod_handling_rate_bps IS NULL OR p_cod_handling_rate_bps < 0 OR p_cod_handling_rate_bps > 10000 THEN
    RAISE EXCEPTION 'invalid_cod_handling_rate_bps';
  END IF;
  IF p_cod_handling_flat_fee_iqd IS NULL OR p_cod_handling_flat_fee_iqd < 0 THEN
    RAISE EXCEPTION 'invalid_cod_handling_flat_fee';
  END IF;

  IF p_merchant_id IS NULL THEN
    -- Default row
    UPDATE public.merchant_commission_configs
    SET is_active = false, updated_at = now()
    WHERE merchant_id IS NULL AND is_active = true;

    INSERT INTO public.merchant_commission_configs (
      merchant_id,
      rate_bps,
      flat_fee_iqd,
      cod_handling_rate_bps,
      cod_handling_flat_fee_iqd,
      is_active
    ) VALUES (
      NULL,
      p_rate_bps,
      p_flat_fee_iqd,
      p_cod_handling_rate_bps,
      p_cod_handling_flat_fee_iqd,
      true
    );

    RETURN;
  END IF;

  UPDATE public.merchant_commission_configs
  SET is_active = false, updated_at = now()
  WHERE merchant_id = p_merchant_id AND is_active = true;

  INSERT INTO public.merchant_commission_configs (
    merchant_id,
    rate_bps,
    flat_fee_iqd,
    cod_handling_rate_bps,
    cod_handling_flat_fee_iqd,
    is_active
  ) VALUES (
    p_merchant_id,
    p_rate_bps,
    p_flat_fee_iqd,
    p_cod_handling_rate_bps,
    p_cod_handling_flat_fee_iqd,
    true
  );
END;
$$;


