--
-- TOC entry 918 (class 1255 OID 63412)
-- Name: admin_platform_fee_set_v1(text, uuid, integer, integer, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_platform_fee_set_v1(p_product_code text, p_service_area_id uuid, p_rate_bps integer, p_flat_fee_iqd integer, p_active boolean DEFAULT true) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_product text;
  v_rate integer;
  v_flat integer;
  v_active boolean;
  v_id uuid;
BEGIN
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not (select public.is_admin()) then
    raise exception 'not_authorized';
  end if;

  v_product := coalesce(nullif(btrim(p_product_code), ''), 'standard');
  v_rate := coalesce(p_rate_bps, 0);
  v_flat := coalesce(p_flat_fee_iqd, 0);
  v_active := coalesce(p_active, true);

  if v_rate < 0 or v_rate > 5000 then
    raise exception 'invalid_rate_bps';
  end if;
  if v_flat < 0 then
    raise exception 'invalid_flat_fee_iqd';
  end if;

  -- Deactivate any prior active config for the same key.
  update public.platform_fee_configs
  set active = false,
      updated_at = now()
  where product_code = v_product
    and (
      (service_area_id is null and p_service_area_id is null)
      or service_area_id = p_service_area_id
    )
    and active = true;

  insert into public.platform_fee_configs(
    product_code,
    service_area_id,
    rate_bps,
    flat_fee_iqd,
    active
  ) values (
    v_product,
    p_service_area_id,
    v_rate,
    v_flat,
    v_active
  )
  returning id into v_id;

  return v_id;
END;
$$;


ALTER FUNCTION public.admin_platform_fee_set_v1(p_product_code text, p_service_area_id uuid, p_rate_bps integer, p_flat_fee_iqd integer, p_active boolean) OWNER TO postgres;

--
-- TOC entry 749 (class 1255 OID 63136)
-- Name: admin_reconciliation_daily_v1(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_reconciliation_daily_v1(p_days integer DEFAULT 14) RETURNS TABLE(day date, cash_ride_collections_iqd bigint, cash_ride_platform_fees_iqd bigint, cod_driver_due_iqd bigint, cod_commission_iqd bigint, receipts_iqd bigint, payouts_iqd bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_days int := greatest(1, least(coalesce(p_days, 14), 90));
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not v_is_admin then
    raise exception 'not_authorized';
  end if;

  return query
  with days as (
    select (current_date - (g.i * interval '1 day'))::date as day
    from generate_series(0, v_days - 1) as g(i)
  ),
  cash_col as (
    select cc.created_at::date as day,
           coalesce(sum(cc.collected_amount_iqd - cc.change_given_iqd), 0)::bigint as amt
    from public.cash_collections cc
    where cc.created_at >= (current_date - (v_days * interval '1 day'))
    group by 1
  ),
  fees as (
    select e.created_at::date as day,
           coalesce(sum(-e.delta_iqd), 0)::bigint as amt
    from public.settlement_entries e
    join public.settlement_accounts a on a.id = e.account_id
    where e.created_at >= (current_date - (v_days * interval '1 day'))
      and a.party_type = 'driver'::public.settlement_party_type
      and e.reason = 'cash_ride_platform_fee'
    group by 1
  ),
  cod_due as (
    select e.created_at::date as day,
           coalesce(sum(-e.delta_iqd), 0)::bigint as amt
    from public.settlement_entries e
    join public.settlement_accounts a on a.id = e.account_id
    where e.created_at >= (current_date - (v_days * interval '1 day'))
      and a.party_type = 'driver'::public.settlement_party_type
      and e.reason = 'merchant_cod_goods_due'
    group by 1
  ),
  cod_comm as (
    select e.created_at::date as day,
           coalesce(sum(-e.delta_iqd), 0)::bigint as amt
    from public.settlement_entries e
    join public.settlement_accounts a on a.id = e.account_id
    where e.created_at >= (current_date - (v_days * interval '1 day'))
      and a.party_type = 'merchant'::public.settlement_party_type
      and e.reason = 'merchant_cod_commission'
    group by 1
  ),
  receipts as (
    select r.received_at::date as day,
           coalesce(sum(r.amount_iqd), 0)::bigint as amt
    from public.settlement_receipts r
    where r.received_at >= (current_date - (v_days * interval '1 day'))
    group by 1
  ),
  payouts as (
    select p.paid_at::date as day,
           coalesce(sum(p.amount_iqd), 0)::bigint as amt
    from public.settlement_payouts p
    where p.paid_at >= (current_date - (v_days * interval '1 day'))
    group by 1
  )
  select d.day,
         coalesce(cash_col.amt, 0)::bigint as cash_ride_collections_iqd,
         coalesce(fees.amt, 0)::bigint as cash_ride_platform_fees_iqd,
         coalesce(cod_due.amt, 0)::bigint as cod_driver_due_iqd,
         coalesce(cod_comm.amt, 0)::bigint as cod_commission_iqd,
         coalesce(receipts.amt, 0)::bigint as receipts_iqd,
         coalesce(payouts.amt, 0)::bigint as payouts_iqd
  from days d
  left join cash_col on cash_col.day = d.day
  left join fees on fees.day = d.day
  left join cod_due on cod_due.day = d.day
  left join cod_comm on cod_comm.day = d.day
  left join receipts on receipts.day = d.day
  left join payouts on payouts.day = d.day
  order by d.day desc;

end;
$$;


ALTER FUNCTION public.admin_reconciliation_daily_v1(p_days integer) OWNER TO postgres;

--
-- TOC entry 1376 (class 1255 OID 39766)
-- Name: admin_record_ride_refund(uuid, integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_record_ride_refund(p_ride_id uuid, p_refund_amount_iqd integer DEFAULT NULL::integer, p_reason text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, extensions'
    AS $$
declare
  v_receipt public.ride_receipts%rowtype;
  v_payment public.payments%rowtype;
  v_total integer;
  v_prev_refunded integer;
  v_add integer;
  v_new_total integer;
  v_ref_id text;
begin
  -- authz
  if not public.is_admin() then
    raise exception 'not_admin' using errcode = '42501';
  end if;

  -- lock receipt
  select * into v_receipt
  from public.ride_receipts
  where ride_id = p_ride_id
  for update;

  if not found then
    raise exception 'receipt_not_found' using errcode = 'P0002';
  end if;

  v_total := coalesce(v_receipt.total_iqd, 0);
  v_prev_refunded := coalesce(v_receipt.refunded_iqd, 0);

  if p_refund_amount_iqd is null then
    v_add := greatest(v_total - v_prev_refunded, 0);
  else
    v_add := greatest(least(p_refund_amount_iqd, v_total - v_prev_refunded), 0);
  end if;

  if v_add <= 0 then
    return jsonb_build_object(
      'ride_id', p_ride_id,
      'refunded_iqd', v_prev_refunded,
      'added_iqd', 0,
      'status', 'no_op',
      'reason', p_reason
    );
  end if;

  v_new_total := v_prev_refunded + v_add;

  -- lock latest succeeded payment
  select * into v_payment
  from public.payments
  where ride_id = p_ride_id and status = 'succeeded'::public.payment_status
  order by created_at desc
  limit 1
  for update;

  if not found then
    raise exception 'payment_not_found' using errcode = 'P0002';
  end if;

  v_ref_id := coalesce(v_payment.provider_refund_id, 'manual_refund:' || gen_random_uuid()::text);

  update public.payments
  set provider_refund_id = v_ref_id,
      refunded_at = now(),
      refund_amount_iqd = v_new_total,
      updated_at = now()
  where id = v_payment.id;

  return jsonb_build_object(
    'ride_id', p_ride_id,
    'payment_id', v_payment.id,
    'provider_refund_id', v_ref_id,
    'added_iqd', v_add,
    'refunded_iqd', v_new_total,
    'reason', p_reason
  );
end;
$$;


ALTER FUNCTION public.admin_record_ride_refund(p_ride_id uuid, p_refund_amount_iqd integer, p_reason text) OWNER TO postgres;

--
-- TOC entry 1081 (class 1255 OID 45082)
-- Name: admin_release_stuck_reserved_drivers(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_release_stuck_reserved_drivers(p_stale_after_seconds integer DEFAULT 120, p_limit integer DEFAULT 100) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_count integer := 0;
  v_limit integer;
  v_cutoff timestamptz;
BEGIN
  v_limit := greatest(1, least(coalesce(p_limit, 100), 500));
  v_cutoff := now() - make_interval(secs => greatest(30, coalesce(p_stale_after_seconds, 120)));

  -- Find drivers in 'reserved' state who are NOT currently assigned to any ride request
  -- that is still in 'matched' state (i.e., waiting for accept).
  -- These are orphaned reservations from failed matching attempts.
  WITH stuck AS (
    SELECT d.id
    FROM public.drivers d
    WHERE d.status = 'reserved'
      AND d.updated_at < v_cutoff
      AND NOT EXISTS (
        SELECT 1 FROM public.ride_requests rr
        WHERE rr.assigned_driver_id = d.id
          AND rr.status = 'matched'
      )
    ORDER BY d.updated_at ASC
    LIMIT v_limit
    FOR UPDATE OF d SKIP LOCKED
  )
  UPDATE public.drivers d
  SET status = 'available',
      updated_at = now()
  WHERE d.id IN (SELECT id FROM stuck);

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION public.admin_release_stuck_reserved_drivers(p_stale_after_seconds integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 9765 (class 0 OID 0)
-- Dependencies: 1081
-- Name: FUNCTION admin_release_stuck_reserved_drivers(p_stale_after_seconds integer, p_limit integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.admin_release_stuck_reserved_drivers(p_stale_after_seconds integer, p_limit integer) IS 'Releases drivers stuck in reserved state (from failed matching) back to available. Should be run periodically by expire-rides job.';


--
-- TOC entry 663 (class 1255 OID 44424)
-- Name: admin_revoke_user(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_revoke_user(p_user uuid, p_note text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
declare
  remaining_admins integer;
begin
  if not (select public.is_admin()) then
    raise exception 'forbidden';
  end if;

  if p_user is null then
    raise exception 'missing_user_id';
  end if;

  -- Prevent removing the last remaining admin (avoid lockout).
  with admin_set as (
    select p.id
    from public.profiles p
    where coalesce(p.is_admin, false) = true
    union
    select au.user_id as id
    from public.admin_users au
  )
  select count(*) into remaining_admins
  from admin_set
  where id <> p_user;

  if remaining_admins < 1 then
    raise exception 'cannot_remove_last_admin';
  end if;

  delete from public.admin_users where user_id = p_user;

  insert into public.admin_audit_log (actor_id, action, target_user_id, note)
  values ((select auth.uid()), 'revoke_admin', p_user, p_note);
end;
$$;


ALTER FUNCTION public.admin_revoke_user(p_user uuid, p_note text) OWNER TO postgres;

--
-- TOC entry 603 (class 1255 OID 65019)
-- Name: admin_revoke_user_v1(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_revoke_user_v1(p_user uuid, p_note text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
BEGIN
  PERFORM public.admin_revoke_user(p_user => p_user, p_note => p_note);
  RETURN jsonb_build_object('ok', true);
EXCEPTION
  WHEN others THEN
    RETURN jsonb_build_object('ok', false, 'error', SQLERRM);
END;
$$;


ALTER FUNCTION public.admin_revoke_user_v1(p_user uuid, p_note text) OWNER TO postgres;

--
-- TOC entry 1054 (class 1255 OID 43882)
-- Name: admin_ridecheck_escalate(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_ridecheck_escalate(p_event_id uuid, p_note text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_ride_id uuid;
  v_incident_id uuid;
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  SELECT ride_id INTO v_ride_id FROM public.ridecheck_events WHERE id = p_event_id;
  IF v_ride_id IS NULL THEN
    RAISE EXCEPTION 'not_found';
  END IF;

  UPDATE public.ridecheck_events
    SET status = 'escalated',
        updated_at = now(),
        metadata = metadata || jsonb_build_object('admin_note', left(coalesce(p_note,''), 800), 'escalated_by', auth.uid(), 'escalated_at', now())
  WHERE id = p_event_id;

  INSERT INTO public.ride_incidents (ride_id, reporter_id, reporter_type, category, severity, status, description, metadata)
  VALUES (
    v_ride_id,
    auth.uid(),
    'admin',
    'ridecheck',
    'high',
    'open',
    COALESCE(NULLIF(left(p_note, 800), ''), 'RideCheck event escalated by admin.'),
    jsonb_build_object('ridecheck_event_id', p_event_id)
  )
  RETURNING id INTO v_incident_id;

  RETURN v_incident_id;
END;
$$;


ALTER FUNCTION public.admin_ridecheck_escalate(p_event_id uuid, p_note text) OWNER TO postgres;

--
-- TOC entry 1611 (class 1255 OID 43881)
-- Name: admin_ridecheck_resolve(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
