CREATE FUNCTION public.admin_ridecheck_resolve(p_event_id uuid, p_note text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
BEGIN
  IF NOT public.is_admin(auth.uid()) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  UPDATE public.ridecheck_events
    SET status = 'resolved',
        resolved_at = now(),
        updated_at = now(),
        metadata = metadata || jsonb_build_object('admin_note', left(coalesce(p_note,''), 800), 'resolved_by', auth.uid(), 'resolved_at', now())
  WHERE id = p_event_id;

  RETURN FOUND;
END;
$$;


ALTER FUNCTION public.admin_ridecheck_resolve(p_event_id uuid, p_note text) OWNER TO postgres;

--
-- TOC entry 1401 (class 1255 OID 62322)
-- Name: admin_set_default_pricing_config_v1(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_set_default_pricing_config_v1(p_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_role text;
begin
  v_role := coalesce(auth.jwt() ->> 'role', '');
  if v_role <> 'service_role' and not public.is_admin() then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  -- Clear any existing default then set exactly one.
  update public.pricing_configs set is_default = false where is_default = true;
  update public.pricing_configs set is_default = true where id = p_id;

  if not found then
    raise exception 'pricing_config not found';
  end if;
end;
$$;


ALTER FUNCTION public.admin_set_default_pricing_config_v1(p_id uuid) OWNER TO postgres;

