-- TOC entry 1292 (class 1255 OID 62231)
-- Name: admin_set_merchant_status(uuid, public.merchant_status, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_set_merchant_status(p_merchant_id uuid, p_status public.merchant_status, p_note text DEFAULT NULL::text) RETURNS public.merchants
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_row public.merchants;
begin
  if not (select is_admin()) then
    raise exception 'Admin only';
  end if;

  perform set_config('app.merchant_status_note', coalesce(p_note, ''), true);

  update public.merchants
  set status = p_status
  where id = p_merchant_id
  returning * into v_row;

  if not found then
    raise exception 'Merchant not found';
  end if;

  return v_row;
end;
$$;


