--
-- TOC entry 1493 (class 1255 OID 63189)
-- Name: admin_settlement_approve_payment_request_v1(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_approve_payment_request_v1(p_request_id uuid, p_admin_note text DEFAULT NULL::text, p_reference_override text DEFAULT NULL::text) RETURNS TABLE(id uuid, status text, processed_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_req public.settlement_payment_requests;
  v_idem text;
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'admin_only';
  END IF;

  SELECT * INTO v_req
  FROM public.settlement_payment_requests r
  WHERE r.id = p_request_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'request_not_found';
  END IF;

  IF v_req.status <> 'requested'::public.settlement_request_status THEN
    RETURN QUERY SELECT v_req.id, v_req.status::text, v_req.processed_at;
    RETURN;
  END IF;

  v_idem := 'approve_payment_request:' || v_req.id::text;

  PERFORM public.admin_settlement_record_receipt_v1(
    v_req.party_type,
    v_req.party_id,
    v_req.amount_iqd,
    v_req.method,
    COALESCE(NULLIF(trim(p_reference_override), ''), v_req.reference),
    v_idem
  );

  UPDATE public.settlement_payment_requests
  SET status = 'approved'::public.settlement_request_status,
      processed_by = auth.uid(),
      processed_at = now(),
      admin_note = NULLIF(trim(COALESCE(p_admin_note, '')), '')
  WHERE id = v_req.id
  RETURNING * INTO v_req;

  RETURN QUERY SELECT v_req.id, v_req.status::text, v_req.processed_at;
END;
$$;


ALTER FUNCTION public.admin_settlement_approve_payment_request_v1(p_request_id uuid, p_admin_note text, p_reference_override text) OWNER TO postgres;

--
-- TOC entry 1723 (class 1255 OID 63191)
-- Name: admin_settlement_approve_payout_request_v1(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_approve_payout_request_v1(p_request_id uuid, p_admin_note text DEFAULT NULL::text, p_reference_override text DEFAULT NULL::text) RETURNS TABLE(id uuid, status text, processed_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_req public.settlement_payout_requests;
  v_idem text;
  v_bal bigint;
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'admin_only';
  END IF;

  SELECT * INTO v_req
  FROM public.settlement_payout_requests r
  WHERE r.id = p_request_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'request_not_found';
  END IF;

  IF v_req.status <> 'requested'::public.settlement_request_status THEN
    RETURN QUERY SELECT v_req.id, v_req.status::text, v_req.processed_at;
    RETURN;
  END IF;

  SELECT COALESCE(sa.balance_iqd, 0) INTO v_bal
  FROM public.settlement_accounts sa
  WHERE sa.party_type = v_req.party_type
    AND sa.party_id = v_req.party_id
    AND sa.currency = 'IQD'
  LIMIT 1;

  IF v_bal < v_req.amount_iqd THEN
    RAISE EXCEPTION 'insufficient_balance';
  END IF;

  v_idem := 'approve_payout_request:' || v_req.id::text;

  PERFORM public.admin_settlement_record_payout_v1(
    v_req.party_type,
    v_req.party_id,
    v_req.amount_iqd,
    v_req.method,
    COALESCE(NULLIF(trim(p_reference_override), ''), v_req.reference),
    v_idem
  );

  UPDATE public.settlement_payout_requests
  SET status = 'approved'::public.settlement_request_status,
      processed_by = auth.uid(),
      processed_at = now(),
      admin_note = NULLIF(trim(COALESCE(p_admin_note, '')), '')
  WHERE id = v_req.id
  RETURNING * INTO v_req;

  RETURN QUERY SELECT v_req.id, v_req.status::text, v_req.processed_at;
END;
$$;


ALTER FUNCTION public.admin_settlement_approve_payout_request_v1(p_request_id uuid, p_admin_note text, p_reference_override text) OWNER TO postgres;

--
-- TOC entry 1248 (class 1255 OID 63072)
-- Name: admin_settlement_list_accounts_v1(public.settlement_party_type, boolean, bigint, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_list_accounts_v1(p_party_type public.settlement_party_type DEFAULT NULL::public.settlement_party_type, p_only_negative boolean DEFAULT true, p_min_abs_balance_iqd bigint DEFAULT 0, p_limit integer DEFAULT 200, p_offset integer DEFAULT 0) RETURNS TABLE(party_type public.settlement_party_type, party_id uuid, balance_iqd bigint, currency text, updated_at timestamp with time zone, last_entry_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  RETURN QUERY
    SELECT
      a.party_type,
      a.party_id,
      a.balance_iqd,
      a.currency,
      a.updated_at,
      le.last_entry_at
    FROM public.settlement_accounts a
    LEFT JOIN LATERAL (
      SELECT max(e.created_at) AS last_entry_at
      FROM public.settlement_entries e
      WHERE e.account_id = a.id
    ) le ON true
    WHERE a.currency = 'IQD'
      AND (p_party_type IS NULL OR a.party_type = p_party_type)
      AND (NOT coalesce(p_only_negative, true) OR a.balance_iqd < 0)
      AND abs(a.balance_iqd) >= coalesce(p_min_abs_balance_iqd, 0)
    ORDER BY a.balance_iqd ASC, a.updated_at DESC
    LIMIT greatest(1, least(coalesce(p_limit, 200), 500))
    OFFSET greatest(coalesce(p_offset, 0), 0);
END;
$$;


ALTER FUNCTION public.admin_settlement_list_accounts_v1(p_party_type public.settlement_party_type, p_only_negative boolean, p_min_abs_balance_iqd bigint, p_limit integer, p_offset integer) OWNER TO postgres;

--
-- TOC entry 1170 (class 1255 OID 63073)
