--

CREATE FUNCTION public.admin_settlement_list_entries_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, created_at timestamp with time zone, delta_iqd bigint, reason text, ref_type text, ref_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  RETURN QUERY
    SELECT e.id, e.created_at, e.delta_iqd, e.reason, e.ref_type, e.ref_id
    FROM public.settlement_entries e
    JOIN public.settlement_accounts a ON a.id = e.account_id
    WHERE a.party_type = p_party_type
      AND a.party_id = p_party_id
      AND a.currency = 'IQD'
    ORDER BY e.created_at DESC
    LIMIT greatest(1, least(coalesce(p_limit, 100), 500))
    OFFSET greatest(coalesce(p_offset, 0), 0);
END;
$$;


