-- TOC entry 1460 (class 1255 OID 63135)
-- Name: admin_settlement_record_payout_v1(public.settlement_party_type, uuid, integer, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_record_payout_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text, p_reference text, p_idempotency_key text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_id uuid;
begin
  select r.id into v_id
  from public.admin_settlement_record_payout_v2(
    p_party_type,
    p_party_id,
    p_amount_iqd,
    p_method,
    p_reference,
    null,
    current_date,
    p_idempotency_key
  ) as r
  limit 1;
  return v_id;
end;
$$;


ALTER FUNCTION public.admin_settlement_record_payout_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text, p_reference text, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 681 (class 1255 OID 63364)
-- Name: admin_settlement_record_payout_v2(public.settlement_party_type, uuid, integer, text, text, uuid, date, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_record_payout_v2(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text, p_reference text, p_agent_id uuid, p_day date, p_idempotency_key text) RETURNS TABLE(id uuid, payout_no text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_id uuid;
  v_payout_no text;
begin
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;
  if not v_is_admin then
    raise exception 'not_authorized';
  end if;
  if p_amount_iqd is null or p_amount_iqd <= 0 then
    raise exception 'invalid_amount';
  end if;

  if p_idempotency_key is not null then
    return query
      select sp.id, sp.payout_no
      from public.settlement_payouts sp
      where sp.idempotency_key = p_idempotency_key
      limit 1;
    if found then
      return;
    end if;
  end if;

  if p_agent_id is not null then
    v_payout_no := public.admin_cash_agent_next_doc_no_v1(p_agent_id, 'payout', coalesce(p_day, current_date));
  end if;

  insert into public.settlement_payouts (party_type, party_id, amount_iqd, method, reference, paid_by, agent_id, payout_no, idempotency_key)
  values (p_party_type, p_party_id, p_amount_iqd, coalesce(p_method, 'cash'), nullif(btrim(p_reference), ''), v_uid, p_agent_id, v_payout_no, p_idempotency_key)
  returning id into v_id;

  perform public.settlement_post_entry(
    p_party_type,
    p_party_id,
    -p_amount_iqd::bigint,
    'admin_payout',
    'settlement_payout',
    v_id,
    case when p_idempotency_key is null then null else 'payout_entry:' || p_idempotency_key end
  );

  return query select v_id, v_payout_no;
end;
$$;


ALTER FUNCTION public.admin_settlement_record_payout_v2(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text, p_reference text, p_agent_id uuid, p_day date, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 1679 (class 1255 OID 63074)
-- Name: admin_settlement_record_receipt_v1(public.settlement_party_type, uuid, integer, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_record_receipt_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text DEFAULT 'cash'::text, p_reference text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text) RETURNS TABLE(receipt_id uuid, entry_id uuid, new_balance_iqd bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_receipt public.settlement_receipts;
  v_entry public.settlement_entries;
  v_sa public.settlement_accounts;
  v_entry_idem text;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF coalesce(p_amount_iqd, 0) <= 0 THEN
    RAISE EXCEPTION 'invalid_amount';
  END IF;

  IF p_idempotency_key IS NOT NULL THEN
    SELECT * INTO v_receipt
    FROM public.settlement_receipts
    WHERE idempotency_key = p_idempotency_key
    LIMIT 1;

    IF FOUND THEN
      v_entry_idem := 'receipt:' || v_receipt.id::text;

      SELECT * INTO v_entry
      FROM public.settlement_entries
      WHERE idempotency_key = v_entry_idem
      LIMIT 1;

      SELECT * INTO v_sa
      FROM public.settlement_accounts
      WHERE party_type = v_receipt.party_type AND party_id = v_receipt.party_id AND currency = 'IQD'
      LIMIT 1;

      RETURN QUERY SELECT v_receipt.id, v_entry.id, coalesce(v_sa.balance_iqd, 0);
      RETURN;
    END IF;
  END IF;

  INSERT INTO public.settlement_receipts (
    party_type, party_id, amount_iqd, method, reference, received_by, received_at, idempotency_key
  ) VALUES (
    p_party_type, p_party_id, p_amount_iqd, coalesce(nullif(p_method, ''), 'cash'), p_reference, auth.uid(), now(), p_idempotency_key
  )
  RETURNING * INTO v_receipt;

  v_entry_idem := 'receipt:' || v_receipt.id::text;

  SELECT * INTO v_entry
  FROM public.settlement_post_entry(
    p_party_type,
    p_party_id,
    p_amount_iqd::bigint,
    'settlement_receipt',
    'receipt',
    v_receipt.id,
    v_entry_idem
  );

  SELECT * INTO v_sa
  FROM public.settlement_accounts
  WHERE party_type = p_party_type AND party_id = p_party_id AND currency = 'IQD'
  LIMIT 1;

  RETURN QUERY SELECT v_receipt.id, v_entry.id, coalesce(v_sa.balance_iqd, 0);
END;
$$;


ALTER FUNCTION public.admin_settlement_record_receipt_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_amount_iqd integer, p_method text, p_reference text, p_idempotency_key text) OWNER TO postgres;

