--
-- TOC entry 1772 (class 1255 OID 63190)
-- Name: admin_settlement_reject_payment_request_v1(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_settlement_reject_payment_request_v1(p_request_id uuid, p_admin_note text DEFAULT NULL::text) RETURNS TABLE(id uuid, status text, processed_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_req public.settlement_payment_requests;
BEGIN
  IF NOT (SELECT is_admin()) THEN
    RAISE EXCEPTION 'admin_only';
  END IF;

  UPDATE public.settlement_payment_requests
  SET status = 'rejected'::public.settlement_request_status,
      processed_by = auth.uid(),
      processed_at = now(),
      admin_note = NULLIF(trim(COALESCE(p_admin_note, '')), '')
  WHERE id = p_request_id
    AND status = 'requested'::public.settlement_request_status
  RETURNING * INTO v_req;

  IF NOT FOUND THEN
    SELECT * INTO v_req FROM public.settlement_payment_requests WHERE id = p_request_id;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'request_not_found';
    END IF;
  END IF;

  RETURN QUERY SELECT v_req.id, v_req.status::text, v_req.processed_at;
END;
$$;


