--
-- TOC entry 1102 (class 1255 OID 41368)
-- Name: dispatch_accept_ride(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dispatch_accept_ride(p_request_id uuid, p_driver_id uuid) RETURNS TABLE(ride_id uuid, ride_status public.ride_status, request_status public.ride_request_status, wallet_hold_id uuid, rider_id uuid, driver_id uuid, started_at timestamp with time zone, completed_at timestamp with time zone, fare_amount_iqd integer, currency text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
DECLARE
  rr record;
  r record;
  v_hold_id uuid;
  v_quote bigint;
  v_pin_required boolean;
  v_pay public.ride_payment_method;
  v_cash_enabled boolean;
  v_cash_limit integer;
  v_driver_balance bigint;
BEGIN
  SELECT * INTO rr
  FROM public.ride_requests req
  WHERE req.id = p_request_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ride_request_not_found';
  END IF;

  IF rr.assigned_driver_id IS DISTINCT FROM p_driver_id THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF rr.status <> 'matched' THEN
    RAISE EXCEPTION 'request_not_matched';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.drivers d WHERE d.id = p_driver_id AND d.status = 'reserved') THEN
    RAISE EXCEPTION 'driver_not_reserved';
  END IF;

  v_quote := COALESCE(rr.quote_amount_iqd, 0)::bigint;
  IF v_quote <= 0 THEN
    RAISE EXCEPTION 'invalid_quote';
  END IF;

  v_pay := COALESCE(rr.payment_method, 'wallet'::public.ride_payment_method);

  -- Cash exposure enforcement (only for cash rides).
  IF v_pay = 'cash'::public.ride_payment_method THEN
    SELECT d.cash_enabled, d.cash_exposure_limit_iqd
      INTO v_cash_enabled, v_cash_limit
    FROM public.drivers d
    WHERE d.id = p_driver_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'driver_not_found';
    END IF;

    IF NOT coalesce(v_cash_enabled, true) THEN
      RAISE EXCEPTION 'driver_cash_disabled';
    END IF;

    SELECT coalesce(sa.balance_iqd, 0)
      INTO v_driver_balance
    FROM public.settlement_accounts sa
    WHERE sa.party_type = 'driver'::public.settlement_party_type
      AND sa.party_id = p_driver_id
      AND sa.currency = 'IQD'
    LIMIT 1;

    IF coalesce(v_driver_balance, 0) < (-coalesce(v_cash_limit, 0))::bigint THEN
      RAISE EXCEPTION 'driver_cash_limit_exceeded';
    END IF;
  END IF;

  UPDATE public.ride_requests
    SET status = 'accepted',
        payment_status = CASE WHEN v_pay = 'wallet'::public.ride_payment_method THEN 'authorized'::public.ride_payment_status ELSE 'unpaid'::public.ride_payment_status END
  WHERE id = rr.id AND status = 'matched';

  v_pin_required := public.is_pickup_pin_required_v1(rr.rider_id, p_driver_id);

  INSERT INTO public.rides (
    request_id, rider_id, driver_id, status, version,
    started_at, completed_at, fare_amount_iqd, currency, product_code,
    payment_method, payment_status,
    cash_expected_amount_iqd,
    pickup_pin_required, pickup_pin_verified_at, pickup_pin_fail_count, pickup_pin_locked_until, pickup_pin_last_attempt_at
  )
  VALUES (
    rr.id, rr.rider_id, p_driver_id, 'assigned', 0,
    NULL, NULL, v_quote::int, rr.currency, rr.product_code,
    v_pay,
    CASE WHEN v_pay = 'wallet'::public.ride_payment_method THEN 'authorized'::public.ride_payment_status ELSE 'unpaid'::public.ride_payment_status END,
    CASE WHEN v_pay = 'cash'::public.ride_payment_method THEN v_quote::int ELSE NULL END,
    v_pin_required, NULL, 0, NULL, NULL
  )
  ON CONFLICT (request_id) DO UPDATE
    SET driver_id = EXCLUDED.driver_id,
        fare_amount_iqd = EXCLUDED.fare_amount_iqd,
        currency = EXCLUDED.currency,
        product_code = EXCLUDED.product_code,
        payment_method = EXCLUDED.payment_method,
        payment_status = EXCLUDED.payment_status,
        cash_expected_amount_iqd = EXCLUDED.cash_expected_amount_iqd,
        pickup_pin_required = public.is_pickup_pin_required_v1(rr.rider_id, EXCLUDED.driver_id),
        pickup_pin_verified_at = NULL,
        pickup_pin_fail_count = 0,
        pickup_pin_locked_until = NULL,
        pickup_pin_last_attempt_at = NULL
  RETURNING * INTO r;

  v_hold_id := NULL;
  IF v_pay = 'wallet'::public.ride_payment_method THEN
    v_hold_id := public.wallet_hold_upsert_for_ride(r.rider_id, r.id, COALESCE(r.fare_amount_iqd, v_quote)::bigint);
  END IF;

  PERFORM public.transition_driver(p_driver_id, 'on_trip'::public.driver_status, p_driver_id, 'accept_ride');

  RETURN QUERY
    SELECT r.id, r.status, 'accepted'::public.ride_request_status, v_hold_id, r.rider_id, r.driver_id, r.started_at, r.completed_at, r.fare_amount_iqd, r.currency;
END;
$$;


