--
-- TOC entry 790 (class 1255 OID 44950)
-- Name: driver_claim_order_delivery(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.driver_claim_order_delivery(p_delivery_id uuid) RETURNS public.merchant_order_deliveries
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_uid uuid;
  v_row public.merchant_order_deliveries;
  v_delivery public.merchant_order_deliveries;
  v_cash_enabled boolean;
  v_cash_limit integer;
  v_balance bigint;
begin
  v_uid := (select auth.uid());
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  if not exists (select 1 from public.drivers d where d.id = v_uid) then
    raise exception 'not_a_driver';
  end if;

  select * into v_delivery
  from public.merchant_order_deliveries d
  where d.id = p_delivery_id;

  if not found then
    raise exception 'delivery_not_found';
  end if;

  if coalesce(v_delivery.payment_method_snapshot, 'cod'::public.merchant_order_payment_method) = 'cod'::public.merchant_order_payment_method then
    select d.cash_enabled, d.cash_exposure_limit_iqd
      into v_cash_enabled, v_cash_limit
    from public.drivers d
    where d.id = v_uid;

    if not coalesce(v_cash_enabled, true) then
      raise exception 'driver_cash_disabled';
    end if;

    v_cash_limit := greatest(0, coalesce(v_cash_limit, 0));
    select coalesce(sa.balance_iqd, 0)
      into v_balance
    from public.settlement_accounts sa
    where sa.party_type = 'driver'::public.settlement_party_type and sa.party_id = v_uid and sa.currency = 'IQD'
    limit 1;

    if coalesce(v_balance, 0) < (-v_cash_limit)::bigint then
      raise exception 'driver_cash_exposure_exceeded';
    end if;
  end if;

  update public.merchant_order_deliveries
    set driver_id = v_uid,
        status = 'assigned'::public.merchant_order_delivery_status,
        assigned_at = coalesce(assigned_at, now())
  where id = p_delivery_id
    and status = 'requested'::public.merchant_order_delivery_status
    and driver_id is null
  returning * into v_row;

  if not found then
    raise exception 'delivery_not_available';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION public.driver_claim_order_delivery(p_delivery_id uuid) OWNER TO postgres;

--
-- TOC entry 1184 (class 1255 OID 56460)
-- Name: driver_hotspots_v1(integer, integer, integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.driver_hotspots_v1(p_hours integer DEFAULT 3, p_limit integer DEFAULT 5, p_grid_m integer DEFAULT 500, p_service_area_id uuid DEFAULT NULL::uuid) RETURNS TABLE(lat double precision, lng double precision, requests_count integer, rides_count integer, score numeric)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'extensions'
    AS $$
  WITH params AS (
    SELECT
      greatest(1, least(p_hours, 24))::int AS hours,
      greatest(1, least(p_limit, 50))::int AS lim,
      greatest(100, least(p_grid_m, 5000))::int AS grid_m,
      p_service_area_id AS service_area_id
  ),
  req AS (
    SELECT
      extensions.st_snaptogrid(
        extensions.st_transform((rr.pickup_loc::geometry), 3857),
        (SELECT grid_m FROM params)
      ) AS cell,
      1 AS requests_count,
      0 AS rides_count
    FROM public.ride_requests rr, params
    WHERE rr.created_at >= now() - ((SELECT hours FROM params) || ' hours')::interval
      AND ((SELECT service_area_id FROM params) IS NULL OR rr.service_area_id = (SELECT service_area_id FROM params))
  ),
  rid AS (
    SELECT
      extensions.st_snaptogrid(
        extensions.st_transform((rr.pickup_loc::geometry), 3857),
        (SELECT grid_m FROM params)
      ) AS cell,
      0 AS requests_count,
      1 AS rides_count
    FROM public.rides r
    JOIN public.ride_requests rr ON rr.id = r.request_id
    CROSS JOIN params
    WHERE r.created_at >= now() - ((SELECT hours FROM params) || ' hours')::interval
      AND ((SELECT service_area_id FROM params) IS NULL OR rr.service_area_id = (SELECT service_area_id FROM params))
  ),
  unioned AS (
    SELECT * FROM req
    UNION ALL
    SELECT * FROM rid
  ),
  agg AS (
    SELECT
      cell,
      sum(requests_count)::int AS requests_count,
      sum(rides_count)::int AS rides_count
    FROM unioned
    GROUP BY cell
  ),
  with_centroid AS (
    SELECT
      extensions.st_transform(extensions.st_centroid(cell), 4326) AS cgeom,
      requests_count,
      rides_count
    FROM agg
  )
  SELECT
    extensions.st_y(cgeom) AS lat,
    extensions.st_x(cgeom) AS lng,
    requests_count,
    rides_count,
    (requests_count + rides_count)::numeric AS score
  FROM with_centroid
  ORDER BY score DESC, requests_count DESC, rides_count DESC
  LIMIT (SELECT lim FROM params);
$$;


ALTER FUNCTION public.driver_hotspots_v1(p_hours integer, p_limit integer, p_grid_m integer, p_service_area_id uuid) OWNER TO postgres;

--
-- TOC entry 1695 (class 1255 OID 41844)
-- Name: driver_leaderboard_refresh_day(date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.driver_leaderboard_refresh_day(p_day date DEFAULT NULL::date) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
declare
  v_day date := coalesce(p_day, (now() at time zone 'utc')::date);
begin
  -- Ensure stats exist
  perform public.driver_stats_rollup_day(v_day);

  -- Score: trips + (earnings in thousands)
  with base as (
    select
      day,
      driver_id,
      trips_count,
      earnings_iqd,
      (trips_count::numeric + (earnings_iqd::numeric / 1000.0)) as score
    from public.driver_stats_daily
    where day = v_day
  ),
  ranked as (
    select
      b.*,
      dense_rank() over (order by b.score desc, b.trips_count desc, b.earnings_iqd desc, b.driver_id) as rnk
    from base b
  )
  insert into public.driver_leaderboard_daily (day, driver_id, trips_count, earnings_iqd, score, rank, updated_at)
  select day, driver_id, trips_count, earnings_iqd, score, rnk, now()
  from ranked
  on conflict (day, driver_id) do update
    set trips_count = excluded.trips_count,
        earnings_iqd = excluded.earnings_iqd,
        score = excluded.score,
        rank = excluded.rank,
        updated_at = now();
end;
$$;


ALTER FUNCTION public.driver_leaderboard_refresh_day(p_day date) OWNER TO postgres;

--
-- TOC entry 1537 (class 1255 OID 64998)
-- Name: driver_location_upsert_user_v1(double precision, double precision, text, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.driver_location_upsert_user_v1(p_lat double precision, p_lng double precision, p_vehicle_type text, p_accuracy_m numeric DEFAULT NULL::numeric, p_heading numeric DEFAULT NULL::numeric, p_speed_mps numeric DEFAULT NULL::numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_vehicle text;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  -- Location updates are driver-scoped. Fail fast with a stable error code.
  IF NOT EXISTS (SELECT 1 FROM public.drivers d WHERE d.id = v_uid) THEN
    RAISE EXCEPTION 'not_a_driver';
  END IF;

  IF p_lat IS NULL OR p_lng IS NULL OR p_lat < -90 OR p_lat > 90 OR p_lng < -180 OR p_lng > 180 THEN
    RAISE EXCEPTION 'invalid_coordinates';
  END IF;

  -- Normalize and validate vehicle type.
  v_vehicle := lower(left(coalesce(p_vehicle_type, ''), 32));
  IF v_vehicle = '' THEN
    RAISE EXCEPTION 'invalid_vehicle_type';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM unnest(enum_range(NULL::public.driver_vehicle_type)) AS t(val)
    WHERE t.val::text = v_vehicle
  ) THEN
    RAISE EXCEPTION 'invalid_vehicle_type';
  END IF;

  -- Upsert current location. Optional fields are only updated when provided.
  INSERT INTO public.driver_locations(
    driver_id,
    lat,
    lng,
    accuracy_m,
    heading,
    speed_mps,
    vehicle_type
  ) VALUES (
    v_uid,
    p_lat,
    p_lng,
    p_accuracy_m,
    p_heading,
    p_speed_mps,
    v_vehicle
  )
  ON CONFLICT (driver_id)
  DO UPDATE SET
    lat = EXCLUDED.lat,
    lng = EXCLUDED.lng,
    accuracy_m = COALESCE(EXCLUDED.accuracy_m, public.driver_locations.accuracy_m),
    heading = COALESCE(EXCLUDED.heading, public.driver_locations.heading),
    speed_mps = COALESCE(EXCLUDED.speed_mps, public.driver_locations.speed_mps),
    vehicle_type = EXCLUDED.vehicle_type;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION public.driver_location_upsert_user_v1(p_lat double precision, p_lng double precision, p_vehicle_type text, p_accuracy_m numeric, p_heading numeric, p_speed_mps numeric) OWNER TO postgres;

