-- TOC entry 1574 (class 1255 OID 63070)
-- Name: driver_settlement_get_my_account_v1(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.driver_settlement_get_my_account_v1() RETURNS TABLE(balance_iqd bigint, currency text, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_sa public.settlement_accounts;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT * INTO v_sa
  FROM public.settlement_accounts sa
  WHERE sa.party_type = 'driver'::public.settlement_party_type
    AND sa.party_id = v_uid
    AND sa.currency = 'IQD'
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN QUERY SELECT 0::bigint, 'IQD'::text, now();
    RETURN;
  END IF;

  RETURN QUERY SELECT v_sa.balance_iqd, v_sa.currency, v_sa.updated_at;
END;
$$;


