--
-- TOC entry 1443 (class 1255 OID 65017)
-- Name: drivers_nearby_user_v1(uuid, double precision, double precision, integer, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.drivers_nearby_user_v1(p_request_id uuid DEFAULT NULL::uuid, p_pickup_lat double precision DEFAULT NULL::double precision, p_pickup_lng double precision DEFAULT NULL::double precision, p_radius_m integer DEFAULT 5000, p_limit_n integer DEFAULT 25, p_required_capacity integer DEFAULT 4, p_stale_after_s integer DEFAULT 120) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_user uuid;
  v_lat double precision;
  v_lng double precision;
  v_radius integer;
  v_limit integer;
  v_capacity integer;
  v_stale integer;
  v_result jsonb;
  v_allowed boolean;
  v_remaining integer;
  v_reset_at text;
  v_drivers jsonb;
  v_stats jsonb;
BEGIN
  v_user := auth.uid();
  IF v_user IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'unauthorized');
  END IF;

  v_radius := greatest(100, least(coalesce(p_radius_m, 5000), 50000));
  v_limit := greatest(1, least(coalesce(p_limit_n, 25), 200));
  v_capacity := greatest(1, least(coalesce(p_required_capacity, 4), 8));
  v_stale := greatest(10, least(coalesce(p_stale_after_s, 120), 600));

  IF p_request_id IS NOT NULL THEN
    SELECT rr.pickup_lat, rr.pickup_lng
      INTO v_lat, v_lng
    FROM public.ride_requests rr
    WHERE rr.id = p_request_id
      AND rr.rider_id = v_user
    LIMIT 1;

    IF v_lat IS NULL OR v_lng IS NULL THEN
      RETURN jsonb_build_object('ok', false, 'error', 'not_found');
    END IF;
  ELSE
    v_lat := p_pickup_lat;
    v_lng := p_pickup_lng;
    IF v_lat IS NULL OR v_lng IS NULL THEN
      RETURN jsonb_build_object('ok', false, 'error', 'missing_pickup');
    END IF;
  END IF;

  IF v_lat < -90 OR v_lat > 90 OR v_lng < -180 OR v_lng > 180 THEN
    RETURN jsonb_build_object('ok', false, 'error', 'invalid_pickup');
  END IF;

  -- Delegate to the indexed SECURITY DEFINER function that also enforces rate limiting.
  SELECT public.nearby_available_drivers_v2(
    p_pickup_lat => v_lat,
    p_pickup_lng => v_lng,
    p_radius_m => v_radius,
    p_stale_after_s => v_stale,
    p_limit => v_limit,
    p_required_capacity => v_capacity
  )
  INTO v_result;

  v_allowed := COALESCE((v_result ->> 'allowed')::boolean, true);
  v_remaining := COALESCE((v_result ->> 'remaining')::integer, 0);
  v_reset_at := COALESCE(v_result ->> 'reset_at', (now() + interval '1 minute')::text);

  IF NOT v_allowed THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'rate_limited',
      'remaining', v_remaining,
      'reset_at', v_reset_at
    );
  END IF;

  v_drivers := COALESCE(v_result -> 'drivers', '[]'::jsonb);
  v_stats := COALESCE(v_result -> 'stats', '{}'::jsonb);

  RETURN jsonb_build_object(
    'ok', true,
    'request', jsonb_build_object(
      'request_id', p_request_id,
      'pickup', jsonb_build_object(
        'lat', v_lat,
        'lng', v_lng,
        'radius_m', v_radius,
        'limit_n', v_limit,
        'required_capacity', v_capacity
      )
    ),
    'stats', v_stats,
    'drivers', v_drivers,
    'rate_limit', jsonb_build_object(
      'remaining', v_remaining,
      'reset_at', v_reset_at
    )
  );
END;
$$;


ALTER FUNCTION public.drivers_nearby_user_v1(p_request_id uuid, p_pickup_lat double precision, p_pickup_lng double precision, p_radius_m integer, p_limit_n integer, p_required_capacity integer, p_stale_after_s integer) OWNER TO postgres;

--
-- TOC entry 817 (class 1255 OID 55141)
-- Name: drivers_prevent_available_with_active_match(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.drivers_prevent_available_with_active_match() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NEW.status = 'available'::public.driver_status
     AND (OLD.status IS DISTINCT FROM NEW.status) THEN
    IF EXISTS (
      SELECT 1
      FROM public.ride_requests rr
      WHERE rr.assigned_driver_id = NEW.id
        AND rr.status = 'matched'
        AND (rr.match_deadline IS NULL OR rr.match_deadline > now())
    ) THEN
      RAISE EXCEPTION 'driver_has_active_match';
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.drivers_prevent_available_with_active_match() OWNER TO postgres;

--
-- TOC entry 716 (class 1255 OID 64979)
-- Name: edge_webhook_outbox_claim(integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.edge_webhook_outbox_claim(p_limit integer DEFAULT 20, p_lock_id uuid DEFAULT gen_random_uuid()) RETURNS TABLE(id bigint, function_name text, payload jsonb, secret_name text, secret text, attempts integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
BEGIN
  IF auth.role() IS DISTINCT FROM 'service_role' THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  RETURN QUERY
  WITH due AS (
    SELECT o.id
    FROM public.edge_webhook_outbox o
    WHERE o.status IN ('pending','failed')
      AND o.next_attempt_at <= now()
    ORDER BY o.next_attempt_at ASC, o.id ASC
    LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 20), 200))
    FOR UPDATE SKIP LOCKED
  )
  UPDATE public.edge_webhook_outbox o
  SET status = 'processing',
      lock_id = p_lock_id,
      locked_at = now(),
      attempts = o.attempts + 1
  FROM due
  WHERE o.id = due.id
  RETURNING
    o.id,
    o.function_name,
    o.payload,
    o.secret_name,
    public._vault_secret(o.secret_name) AS secret,
    o.attempts;
END;
$$;


ALTER FUNCTION public.edge_webhook_outbox_claim(p_limit integer, p_lock_id uuid) OWNER TO postgres;

--
-- TOC entry 1795 (class 1255 OID 64980)
-- Name: edge_webhook_outbox_mark(bigint, uuid, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.edge_webhook_outbox_mark(p_outbox_id bigint, p_lock_id uuid, p_status text, p_error text DEFAULT NULL::text, p_http_status integer DEFAULT NULL::integer, p_retry_seconds integer DEFAULT NULL::integer) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_retry interval;
BEGIN
  IF auth.role() IS DISTINCT FROM 'service_role' THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF p_status NOT IN ('sent','failed','pending') THEN
    RAISE EXCEPTION 'invalid_status';
  END IF;

  v_retry := make_interval(secs => GREATEST(1, LEAST(COALESCE(p_retry_seconds, 60), 3600)));

  UPDATE public.edge_webhook_outbox
  SET status = CASE WHEN p_status = 'pending' THEN 'pending' ELSE p_status END,
      last_error = p_error,
      last_http_status = p_http_status,
      last_dispatched_at = now(),
      next_attempt_at = CASE
        WHEN p_status = 'failed' THEN now() + v_retry
        WHEN p_status = 'pending' THEN now()
        ELSE next_attempt_at
      END,
      lock_id = NULL,
      locked_at = NULL
  WHERE id = p_outbox_id
    AND lock_id = p_lock_id;
END;
$$;


ALTER FUNCTION public.edge_webhook_outbox_mark(p_outbox_id bigint, p_lock_id uuid, p_status text, p_error text, p_http_status integer, p_retry_seconds integer) OWNER TO postgres;

--
-- TOC entry 818 (class 1255 OID 64988)
-- Name: edge_webhook_outbox_prune(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.edge_webhook_outbox_prune(p_max_age_days integer DEFAULT 14, p_batch integer DEFAULT 5000) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_days integer;
  v_batch integer;
  v_deleted integer;
BEGIN
  IF auth.role() IS DISTINCT FROM 'service_role' THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  v_days := GREATEST(1, LEAST(COALESCE(p_max_age_days, 14), 365));
  v_batch := GREATEST(1, LEAST(COALESCE(p_batch, 5000), 50000));

  WITH doomed AS (
    SELECT id
    FROM public.edge_webhook_outbox
    WHERE status IN ('sent','failed')
      AND created_at < now() - make_interval(days => v_days)
    ORDER BY id ASC
    LIMIT v_batch
  )
  DELETE FROM public.edge_webhook_outbox o
  USING doomed d
  WHERE o.id = d.id;

  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;


ALTER FUNCTION public.edge_webhook_outbox_prune(p_max_age_days integer, p_batch integer) OWNER TO postgres;

--
-- TOC entry 792 (class 1255 OID 40629)
-- Name: enqueue_notification_outbox(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.enqueue_notification_outbox() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
begin
  -- Respect per-notification channel gating.
  -- If the notification payload explicitly sets data.push=false, do NOT enqueue to notification_outbox.
  -- (The row still exists for in-app UX; push delivery is suppressed.)
  if (new.data ? 'push') and coalesce(nullif(new.data->>'push','')::boolean, true) = false then
    return new;
  end if;

  insert into public.notification_outbox (notification_id, user_id, device_token_id, payload)
  select
    new.id,
    new.user_id,
    dt.id,
    jsonb_build_object(
      'title', new.title,
      'body', new.body,
      'type', new.kind,
      'data', coalesce(new.data, '{}'::jsonb),
      'notification_id', new.id::text
    )
  from public.device_tokens dt
  where dt.user_id = new.user_id and dt.enabled = true;

  return new;
end;
$$;


ALTER FUNCTION public.enqueue_notification_outbox() OWNER TO postgres;

--
-- TOC entry 1003 (class 1255 OID 40783)
-- Name: ensure_referral_code(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ensure_referral_code(p_user_id uuid DEFAULT NULL::uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_uid uuid := coalesce(p_user_id, (select auth.uid()));
  v_code text;
  v_try int := 0;
begin
  if v_uid is null then
    raise exception 'unauthorized';
  end if;

  select code into v_code from public.referral_codes where user_id = v_uid;
  if found then
    return v_code;
  end if;

  loop
    v_try := v_try + 1;
    v_code := upper(substring(replace(encode(gen_random_bytes(6), 'base32'), '=', '') from 1 for 8));

    begin
      insert into public.referral_codes(code, user_id)
      values (v_code, v_uid);
      return v_code;
    exception when unique_violation then
      if v_try > 10 then
        raise exception 'could_not_generate_code';
      end if;
    end;
  end loop;
end;
$$;


ALTER FUNCTION public.ensure_referral_code(p_user_id uuid) OWNER TO postgres;

