--
-- TOC entry 1594 (class 1255 OID 55139)
-- Name: expire_matched_ride_requests_v1(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.expire_matched_ride_requests_v1(p_limit integer DEFAULT 200) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
DECLARE
  v_count integer := 0;
  v_driver_ids uuid[] := '{}'::uuid[];
BEGIN
  WITH expired AS (
    SELECT id, assigned_driver_id
    FROM public.ride_requests
    WHERE status = 'matched'
      AND match_deadline IS NOT NULL
      AND match_deadline <= now()
    ORDER BY match_deadline ASC
    LIMIT p_limit
    FOR UPDATE SKIP LOCKED
  ), upd AS (
    UPDATE public.ride_requests rr
      SET status = 'requested',
          assigned_driver_id = NULL,
          match_deadline = NULL,
          matched_at = NULL,
          updated_at = now()
    FROM expired e
    WHERE rr.id = e.id
    RETURNING e.assigned_driver_id AS driver_id
  )
  SELECT
    count(*)::integer,
    coalesce(array_agg(distinct driver_id), '{}'::uuid[])
  INTO v_count, v_driver_ids
  FROM upd;

  -- Best-effort: release drivers stuck in reserved due to expired matches.
  IF v_count > 0 AND array_length(v_driver_ids, 1) IS NOT NULL THEN
    UPDATE public.drivers d
      SET status = 'available'::public.driver_status,
          updated_at = now()
    WHERE d.id = ANY(v_driver_ids)
      AND d.status = 'reserved'::public.driver_status
      AND NOT EXISTS (
        SELECT 1 FROM public.rides r
        WHERE r.driver_id = d.id
          AND r.status IN ('assigned','arrived','in_progress')
      )
      AND NOT EXISTS (
        SELECT 1 FROM public.ride_requests rr2
        WHERE rr2.assigned_driver_id = d.id
          AND rr2.status = 'matched'
          AND (rr2.match_deadline IS NULL OR rr2.match_deadline > now())
      );
  END IF;

  RETURN v_count;
END;
$$;


ALTER FUNCTION public.expire_matched_ride_requests_v1(p_limit integer) OWNER TO postgres;

