--
-- TOC entry 1024 (class 1255 OID 63971)
-- Name: family_invite_teen(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.family_invite_teen(p_family_id uuid, p_invite_email text, p_invite_token text) RETURNS public.family_members
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
declare
  v_member public.family_members;
  v_token_hash text;
begin
  -- Verify caller is guardian of this family
  if not exists (
    select 1 from public.family_members
    where family_id = p_family_id
      and user_id = auth.uid()
      and role = 'guardian'
      and status = 'active'
  ) then
    raise exception 'forbidden';
  end if;

  -- Hash the invite token
  v_token_hash := encode(extensions.digest(p_invite_token, 'sha256'), 'hex');

  -- Create pending invite
  insert into public.family_members (
    family_id, role, status, invite_token_hash, invite_expires_at, invite_email
  ) values (
    p_family_id, 'teen', 'invited', v_token_hash, now() + interval '7 days', p_invite_email
  )
  returning * into v_member;

  return v_member;
end;
$$;


ALTER FUNCTION public.family_invite_teen(p_family_id uuid, p_invite_email text, p_invite_token text) OWNER TO postgres;

