--
-- TOC entry 1030 (class 1255 OID 63973)
-- Name: family_update_policy(uuid, uuid, boolean, boolean, jsonb, jsonb, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.family_update_policy(p_family_id uuid, p_teen_user_id uuid, p_destination_lock_enabled boolean DEFAULT NULL::boolean, p_pickup_pin_enabled boolean DEFAULT NULL::boolean, p_allowed_hours jsonb DEFAULT NULL::jsonb, p_geofence_allowlist jsonb DEFAULT NULL::jsonb, p_spend_cap_daily numeric DEFAULT NULL::numeric) RETURNS public.teen_policies
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_policy public.teen_policies;
begin
  -- Verify caller is guardian of this family
  if not exists (
    select 1 from public.family_members
    where family_id = p_family_id
      and user_id = auth.uid()
      and role = 'guardian'
      and status = 'active'
  ) then
    raise exception 'forbidden';
  end if;

  update public.teen_policies
  set destination_lock_enabled = coalesce(p_destination_lock_enabled, destination_lock_enabled),
      pickup_pin_enabled = coalesce(p_pickup_pin_enabled, pickup_pin_enabled),
      allowed_hours = coalesce(p_allowed_hours, allowed_hours),
      geofence_allowlist = coalesce(p_geofence_allowlist, geofence_allowlist),
      spend_cap_daily = coalesce(p_spend_cap_daily, spend_cap_daily),
      updated_at = now()
  where family_id = p_family_id
    and teen_user_id = p_teen_user_id
  returning * into v_policy;

  if not found then
    raise exception 'policy_not_found';
  end if;

  return v_policy;
end;
$$;


