--
-- TOC entry 1095 (class 1255 OID 63768)
-- Name: fraud_find_collusion_candidates(interval, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fraud_find_collusion_candidates(p_since interval DEFAULT '7 days'::interval, p_min_count integer DEFAULT 5, p_max_trip_distance_m integer DEFAULT 2000) RETURNS TABLE(driver_id uuid, rider_id uuid, ride_count integer, first_ride_at timestamp with time zone, last_ride_at timestamp with time zone)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
  with pairs as (
    select
      r.driver_id,
      rr.rider_id,
      count(*)::int as ride_count,
      min(r.created_at) as first_ride_at,
      max(r.created_at) as last_ride_at
    from public.rides r
    join public.ride_requests rr on rr.id = r.request_id
    where r.status = 'completed'
      and r.created_at >= now() - p_since
      and extensions.st_distance(rr.pickup_loc, rr.dropoff_loc) <= p_max_trip_distance_m
    group by r.driver_id, rr.rider_id
  )
  select * from pairs
  where ride_count >= p_min_count
  order by ride_count desc, last_ride_at desc
$$;


ALTER FUNCTION public.fraud_find_collusion_candidates(p_since interval, p_min_count integer, p_max_trip_distance_m integer) OWNER TO postgres;

--
-- TOC entry 770 (class 1255 OID 63767)
-- Name: fraud_find_route_deviation_candidates(integer, interval); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fraud_find_route_deviation_candidates(p_min_streak integer DEFAULT 3, p_seen_since interval DEFAULT '00:30:00'::interval) RETURNS TABLE(ride_id uuid, rider_id uuid, driver_id uuid, distance_increase_streak integer, last_seen_at timestamp with time zone)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
  select s.ride_id, r.rider_id, r.driver_id, s.distance_increase_streak, s.last_seen_at
  from public.ridecheck_state s
  join public.rides r on r.id = s.ride_id
  where s.distance_increase_streak >= p_min_streak
    and s.last_seen_at >= now() - p_seen_since
    and r.status in ('in_progress','arrived','assigned')
$$;


ALTER FUNCTION public.fraud_find_route_deviation_candidates(p_min_streak integer, p_seen_since interval) OWNER TO postgres;

