CREATE FUNCTION public.fraud_get_active_action(p_action_type text, p_subject_kind public.fraud_subject_kind, p_subject_key text) RETURNS TABLE(id uuid, reason text, severity integer, expires_at timestamp with time zone, metadata jsonb)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
  select a.id, a.reason, a.severity, a.expires_at, a.metadata
  from public.fraud_enforcement_actions a
