-- Name: fraud_log_event(text, public.fraud_subject_kind, text, integer, integer, text, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fraud_log_event(p_reason text, p_subject_kind public.fraud_subject_kind, p_subject_key text, p_severity integer DEFAULT 1, p_score integer DEFAULT 0, p_dedupe_key text DEFAULT NULL::text, p_ip_prefix text DEFAULT NULL::text, p_device_hash text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS public.fraud_events
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  out public.fraud_events;
begin
  perform public._fraud_require_service_role();

  insert into public.fraud_events (
    reason, subject_kind, subject_key, severity, score, dedupe_key, ip_prefix, device_hash, metadata
  ) values (
    p_reason, p_subject_kind, p_subject_key, greatest(1, least(5, p_severity)), p_score, p_dedupe_key, p_ip_prefix, p_device_hash, coalesce(p_metadata, '{}'::jsonb)
  )
  on conflict (dedupe_key) where (dedupe_key is not null)
  do update set metadata = public.fraud_events.metadata || excluded.metadata
  returning * into out;

  return out;
end
$$;


