-- TOC entry 937 (class 1255 OID 66239)
-- Name: geo_cache_get_v1(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.geo_cache_get_v1(p_cache_key text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_now timestamptz := now();
  v_json jsonb;
BEGIN
  SELECT gc.response_json
  INTO v_json
  FROM public.geo_cache gc
  WHERE gc.cache_key = p_cache_key
    AND gc.expires_at > v_now;

  RETURN v_json;
END;
$$;


ALTER FUNCTION public.geo_cache_get_v1(p_cache_key text) OWNER TO postgres;

--
-- TOC entry 1409 (class 1255 OID 66240)
-- Name: geo_cache_put_v1(text, text, text, jsonb, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.geo_cache_put_v1(p_cache_key text, p_provider_code text, p_capability text, p_response jsonb, p_ttl_seconds integer) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_provider text := lower(btrim(p_provider_code));
  v_cap text := lower(btrim(p_capability));
  v_ttl int := greatest(1, least(coalesce(p_ttl_seconds, 300), 2592000)); -- max 30 days
  v_expires timestamptz := now() + make_interval(secs => v_ttl);
BEGIN
  IF v_provider NOT IN ('google','mapbox','here') THEN
    RAISE EXCEPTION 'invalid_provider_code';
  END IF;
  IF v_cap NOT IN ('directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'invalid_capability';
  END IF;

  INSERT INTO public.geo_cache(cache_key, provider_code, capability, response_json, expires_at)
  VALUES (p_cache_key, v_provider, v_cap, p_response, v_expires)
  ON CONFLICT (cache_key)
  DO UPDATE SET
    provider_code = EXCLUDED.provider_code,
    capability = EXCLUDED.capability,
    response_json = EXCLUDED.response_json,
    expires_at = EXCLUDED.expires_at,
    updated_at = now();
END;
$$;


ALTER FUNCTION public.geo_cache_put_v1(p_cache_key text, p_provider_code text, p_capability text, p_response jsonb, p_ttl_seconds integer) OWNER TO postgres;

