-- TOC entry 1162 (class 1255 OID 64568)
-- Name: get_active_shift(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_active_shift(p_driver_id uuid DEFAULT NULL::uuid) RETURNS TABLE(shift_id uuid, status public.shift_status, scheduled_start timestamp with time zone, scheduled_end timestamp with time zone, actual_start timestamp with time zone, target_earnings_iqd bigint, target_trips integer, trips_completed integer, earnings_iqd bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
  select
    s.id as shift_id,
    s.status,
    s.scheduled_start,
    s.scheduled_end,
    s.actual_start,
    s.target_earnings_iqd,
    s.target_trips,
    coalesce(p.trips_completed, 0) as trips_completed,
    coalesce(p.earnings_iqd, 0) as earnings_iqd
  from public.driver_shifts s
  left join public.shift_progress p on p.shift_id = s.id
  where s.driver_id = coalesce(p_driver_id, auth.uid())
    and s.status in ('scheduled', 'active')
  order by s.scheduled_start asc
  limit 1
$$;


