--
-- TOC entry 606 (class 1255 OID 64246)
-- Name: get_applicable_pricing_rules(bigint, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_applicable_pricing_rules(p_subtotal_iqd bigint, p_region text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, code text, name text, delivery_fee_iqd bigint, delivery_fee_waived boolean, service_fee_pct numeric, small_order_fee_iqd bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_has_membership boolean := false;
  v_membership_plan_codes text[];
begin
  -- Check if user has active membership
  if p_user_id is not null then
    select true, array_agg(mp.code)
    into v_has_membership, v_membership_plan_codes
    from public.memberships m
    join public.membership_plans mp on mp.id = m.plan_id
    where m.user_id = p_user_id
      and m.status = 'active'
      and (m.expires_at is null or m.expires_at > now());
  end if;

  return query
  select
    pr.id,
    pr.code,
    pr.name,
    pr.delivery_fee_iqd,
    pr.delivery_fee_waived,
    pr.service_fee_pct,
    pr.small_order_fee_iqd
  from public.pricing_rules pr
  where pr.is_active = true
    and (pr.valid_from is null or pr.valid_from <= now())
    and (pr.valid_until is null or pr.valid_until > now())
    and (pr.min_subtotal_iqd is null or p_subtotal_iqd >= pr.min_subtotal_iqd)
    and (pr.max_subtotal_iqd is null or p_subtotal_iqd <= pr.max_subtotal_iqd)
    and (pr.regions is null or p_region = any(pr.regions))
    and (
      pr.requires_membership = false
      or (v_has_membership and (pr.membership_plan_codes is null or pr.membership_plan_codes && v_membership_plan_codes))
    )
  order by pr.priority desc
  limit 5;
end;
$$;


ALTER FUNCTION public.get_applicable_pricing_rules(p_subtotal_iqd bigint, p_region text, p_user_id uuid) OWNER TO postgres;

--
-- TOC entry 1276 (class 1255 OID 40788)
-- Name: get_assigned_driver(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_assigned_driver(p_ride_id uuid) RETURNS TABLE(driver_id uuid, display_name text, rating_avg numeric, rating_count integer, vehicle_make text, vehicle_model text, vehicle_color text, plate_number text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_uid uuid := (select auth.uid());
  v_ride record;
begin
  if v_uid is null then
    raise exception 'unauthorized';
  end if;

  select r.id, r.rider_id, r.driver_id into v_ride
  from public.rides r
  where r.id = p_ride_id;

  if not found then
    raise exception 'ride_not_found';
  end if;

  if v_ride.rider_id <> v_uid and v_ride.driver_id <> v_uid and not (select public.is_admin()) then
    raise exception 'forbidden';
  end if;

  return query
  select
    d.id,
    pp.display_name,
    d.rating_avg,
    d.rating_count,
    dv.make,
    dv.model,
    dv.color,
    dv.plate_number
  from public.drivers d
  left join public.public_profiles pp on pp.id = d.id
  left join lateral (
    select make, model, color, plate_number
    from public.driver_vehicles
    where driver_id = d.id
    order by updated_at desc nulls last, created_at desc
    limit 1
  ) dv on true
  where d.id = v_ride.driver_id;
end;
$$;


ALTER FUNCTION public.get_assigned_driver(p_ride_id uuid) OWNER TO postgres;

--
-- TOC entry 1373 (class 1255 OID 62232)
-- Name: get_driver_leaderboard(public.driver_rank_period, date, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_driver_leaderboard(p_period public.driver_rank_period DEFAULT 'weekly'::public.driver_rank_period, p_period_start date DEFAULT NULL::date, p_limit integer DEFAULT 50) RETURNS TABLE(rank integer, driver_id uuid, display_name text, rating_avg numeric, score_iqd bigint, rides_completed integer)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
  with params as (
    select
      coalesce(p_period, 'weekly'::public.driver_rank_period) as period,
      coalesce(
        p_period_start,
        case
          when coalesce(p_period, 'weekly'::public.driver_rank_period) = 'weekly'::public.driver_rank_period then date_trunc('week', now())::date
          else date_trunc('month', now())::date
        end
      ) as period_start,
      greatest(1, least(coalesce(p_limit, 50), 200)) as lim
  )
  select
    s.rank,
    s.driver_id,
    pp.display_name,
    d.rating_avg,
    s.score_iqd,
    s.rides_completed
  from params p
  join public.driver_rank_snapshots s
    on s.period = p.period and s.period_start = p.period_start
  join public.drivers d on d.id = s.driver_id
  left join public.public_profiles pp on pp.id = s.driver_id
  order by s.rank
  limit (select lim from params);
$$;


ALTER FUNCTION public.get_driver_leaderboard(p_period public.driver_rank_period, p_period_start date, p_limit integer) OWNER TO postgres;

--
-- TOC entry 751 (class 1255 OID 63976)
-- Name: get_guardian_trip_info(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_guardian_trip_info(p_trip_id uuid, p_guardian_id uuid) RETURNS TABLE(trip_id uuid, status text, eta_minutes integer, driver_first_name text, vehicle_make text, vehicle_model text, vehicle_color text, current_lat double precision, current_lng double precision)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
begin
  -- Verify guardian has access to this trip
  if not exists (
    select 1 from public.trip_guardian_links tgl
    where tgl.trip_id = p_trip_id
      and tgl.guardian_user_id = p_guardian_id
      and tgl.guardian_live_tracking_enabled = true
  ) then
    raise exception 'forbidden';
  end if;

  return query
  select
    r.id as trip_id,
    r.status::text,
    null::integer as eta_minutes,  -- would be computed from route
    coalesce(split_part(u.raw_user_meta_data->>'full_name', ' ', 1), 'Driver') as driver_first_name,
    v.make as vehicle_make,
    v.model as vehicle_model,
    v.color as vehicle_color,
    dl.lat as current_lat,
    dl.lng as current_lng
  from public.rides r
  join public.drivers d on d.id = r.driver_id
  join auth.users u on u.id = d.id
  left join public.driver_vehicles v on v.driver_id = d.id and coalesce(v.is_active, true) = true
  left join public.driver_locations dl on dl.driver_id = d.id
  where r.id = p_trip_id;
end;
$$;


ALTER FUNCTION public.get_guardian_trip_info(p_trip_id uuid, p_guardian_id uuid) OWNER TO postgres;

