-- TOC entry 1550 (class 1255 OID 64566)
-- Name: get_nearby_hotspots(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_hotspots(p_lat double precision, p_lng double precision, p_radius_km integer DEFAULT 10) RETURNS TABLE(zone_id text, zone_name text, center_lat double precision, center_lng double precision, distance_km double precision, demand_level integer, expected_wait_minutes integer, surge_multiplier numeric)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
  with distanced as (
    select
      h.zone_id,
      h.zone_name,
      h.center_lat,
      h.center_lng,
      (6371 * acos(
        cos(radians(p_lat)) * cos(radians(h.center_lat)) *
        cos(radians(h.center_lng) - radians(p_lng)) +
        sin(radians(p_lat)) * sin(radians(h.center_lat))
      )) as dist_km,
      h.demand_level,
      h.expected_wait_minutes,
      h.surge_multiplier,
      h.valid_until
    from public.demand_hotspots h
  )
  select
    zone_id,
    zone_name,
    center_lat,
    center_lng,
    dist_km as distance_km,
    demand_level,
    expected_wait_minutes,
    surge_multiplier
  from distanced
  where valid_until > now()
    and dist_km <= p_radius_km
  order by demand_level desc, dist_km asc
  limit 10
$$;


ALTER FUNCTION public.get_nearby_hotspots(p_lat double precision, p_lng double precision, p_radius_km integer) OWNER TO postgres;

