--
-- TOC entry 1304 (class 1255 OID 44399)
-- Name: guard_profiles_sensitive_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.guard_profiles_sensitive_update() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
begin
  -- Allow privileged DB roles and service role operations
  if current_user in ('service_role','postgres','supabase_admin') then
    return new;
  end if;

  -- Block any change to admin/rating fields from client context
  if new.is_admin is distinct from old.is_admin then
    raise exception 'cannot_change_is_admin';
  end if;

  if new.rating_avg is distinct from old.rating_avg
     or new.rating_count is distinct from old.rating_count then
    raise exception 'cannot_change_rating_fields';
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.guard_profiles_sensitive_update() OWNER TO postgres;

--
-- TOC entry 791 (class 1255 OID 65026)
-- Name: guardian_trip_track_user_v1(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.guardian_trip_track_user_v1(p_trip_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_uid uuid;
  r record;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT * INTO r
  FROM public.get_guardian_trip_info(p_trip_id, v_uid)
  LIMIT 1;

  IF NOT FOUND OR r.trip_id IS NULL THEN
    RAISE EXCEPTION 'trip_not_found';
  END IF;

  RETURN jsonb_build_object(
    'trip', jsonb_build_object(
      'id', r.trip_id,
      'status', r.status,
      'eta_minutes', r.eta_minutes,
      'driver', jsonb_build_object(
        'first_name', r.driver_first_name,
        'vehicle', jsonb_build_object(
          'make', r.vehicle_make,
          'model', r.vehicle_model,
          'color', r.vehicle_color
        )
      ),
      'location', jsonb_build_object(
        'lat', r.current_lat,
        'lng', r.current_lng
      )
    )
  );
END;
$$;


ALTER FUNCTION public.guardian_trip_track_user_v1(p_trip_id uuid) OWNER TO postgres;

