--
-- TOC entry 845 (class 1255 OID 39782)
-- Name: is_admin(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_admin() RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
  uid uuid;
  v boolean := false;

  admin_col text := null;      -- 'user_id' or 'id'
  admin_has_active boolean := false;
  profiles_has_is_admin boolean := false;
begin
  uid := (select auth.uid());
  if uid is null then
    return false;
  end if;

  -- profiles.is_admin (if present)
  if to_regclass('public.profiles') is not null then
    select exists (
      select 1
      from pg_attribute
      where attrelid = 'public.profiles'::regclass
        and attname = 'is_admin'
        and attnum > 0
        and not attisdropped
    ) into profiles_has_is_admin;

    if profiles_has_is_admin then
      execute 'select coalesce(is_admin,false) from public.profiles where id = $1'
        into v
        using uid;
      if v then
        return true;
      end if;
    end if;
  end if;

  -- admin_users membership (schema-tolerant)
  if to_regclass('public.admin_users') is not null then
    -- which principal column?
    if exists (select 1 from information_schema.columns
              where table_schema='public' and table_name='admin_users' and column_name='user_id') then
      admin_col := 'user_id';
    elsif exists (select 1 from information_schema.columns
                  where table_schema='public' and table_name='admin_users' and column_name='id') then
      admin_col := 'id';
    end if;

    -- does it have is_active?
    select exists (select 1 from information_schema.columns
                  where table_schema='public' and table_name='admin_users' and column_name='is_active')
      into admin_has_active;

    if admin_col is not null then
      if admin_has_active then
        execute format('select exists(select 1 from public.admin_users where %I = $1 and is_active = true)', admin_col)
          into v
          using uid;
      else
        execute format('select exists(select 1 from public.admin_users where %I = $1)', admin_col)
          into v
          using uid;
      end if;

      if v then
        return true;
      end if;
    end if;
  end if;

  return false;
end;
$_$;


ALTER FUNCTION public.is_admin() OWNER TO postgres;

--
-- TOC entry 1245 (class 1255 OID 43965)
-- Name: is_admin(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_admin(p_user uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO ''
    AS $$
  select
    exists(
      select 1
      from public.admin_users au
      where au.user_id = p_user
    )
    or coalesce(
      (select p.is_admin from public.profiles p where p.id = p_user),
      false
    );
$$;


ALTER FUNCTION public.is_admin(p_user uuid) OWNER TO postgres;

--
-- TOC entry 1116 (class 1255 OID 43810)
-- Name: is_pickup_pin_required_v1(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_pickup_pin_required_v1(p_rider_id uuid, p_driver_id uuid) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public'
    AS $$
  WITH s AS (
    SELECT
      COALESCE((SELECT require_pickup_pin FROM public.drivers WHERE id = p_driver_id), false) AS driver_requires,
      COALESCE((SELECT pin_verification_mode FROM public.user_safety_settings WHERE user_id = p_rider_id), 'off'::public.pin_verification_mode) AS rider_mode
  ), t AS (
    SELECT EXTRACT(HOUR FROM timezone('Asia/Baghdad', now()))::int AS baghdad_hour
  )
  SELECT
    (SELECT driver_requires FROM s)
    OR
    CASE (SELECT rider_mode FROM s)
      WHEN 'every_ride'::public.pin_verification_mode THEN true
      WHEN 'night_only'::public.pin_verification_mode THEN ((SELECT baghdad_hour FROM t) >= 21 OR (SELECT baghdad_hour FROM t) < 6)
      ELSE false
    END;
$$;


ALTER FUNCTION public.is_pickup_pin_required_v1(p_rider_id uuid, p_driver_id uuid) OWNER TO postgres;

--
-- TOC entry 1096 (class 1255 OID 66182)
-- Name: maps_pick_provider_v1(text, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_pick_provider_v1(p_capability text, p_exclude text[] DEFAULT '{}'::text[]) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_month_start date := date_trunc('month', (now() AT TIME ZONE 'UTC'))::date;
  v_provider text;
BEGIN
  IF p_capability NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'unknown_capability';
  END IF;

  SELECT mp.provider_code
  INTO v_provider
  FROM public.maps_providers mp
  WHERE mp.enabled = true
    AND mp.provider_code <> ALL(COALESCE(p_exclude, '{}'::text[]))
    AND (
      mp.monthly_hard_cap_units IS NULL
      OR (
        COALESCE(
          (SELECT SUM(mu.units)
           FROM public.maps_usage_daily mu
           WHERE mu.provider_code = mp.provider_code
             AND mu.capability = p_capability
             AND mu.day >= v_month_start),
          0
        ) < mp.monthly_hard_cap_units
      )
    )
  ORDER BY mp.priority DESC
  LIMIT 1;

  RETURN v_provider;
END;
$$;


ALTER FUNCTION public.maps_pick_provider_v1(p_capability text, p_exclude text[]) OWNER TO postgres;

