           FROM public.maps_usage_daily mu
           WHERE mu.provider_code = mp.provider_code
             AND mu.capability = p_capability
             AND mu.day >= v_month_start),
          0
        ) < mp.monthly_hard_cap_units
      )
    )
  ORDER BY mp.priority DESC
  LIMIT 1;

  RETURN v_provider;
END;
$$;


ALTER FUNCTION public.maps_pick_provider_v2(p_capability text, p_exclude text[]) OWNER TO postgres;

--
-- TOC entry 1617 (class 1255 OID 66261)
-- Name: maps_pick_provider_v3(text, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_pick_provider_v3(p_capability text, p_exclude text[] DEFAULT '{}'::text[]) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_month_start date := date_trunc('month', (now() AT TIME ZONE 'UTC'))::date;
  v_provider text;
BEGIN
  IF p_capability NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'unknown_capability';
  END IF;

  SELECT mp.provider_code
  INTO v_provider
  FROM public.maps_providers mp
  JOIN public.maps_provider_capabilities mc
    ON mc.provider_code = mp.provider_code
   AND mc.capability = p_capability
   AND mc.enabled = true
  LEFT JOIN public.maps_provider_health mh
    ON mh.provider_code = mp.provider_code
   AND mh.capability = p_capability
  WHERE mp.enabled = true
    AND mp.provider_code <> ALL(COALESCE(p_exclude, '{}'::text[]))
    AND (mh.disabled_until IS NULL OR mh.disabled_until <= now())
    AND (
      mp.monthly_hard_cap_units IS NULL
      OR (
        COALESCE(
          (SELECT SUM(mu.units)
           FROM public.maps_usage_daily mu
           WHERE mu.provider_code = mp.provider_code
             AND mu.capability = p_capability
             AND mu.day >= v_month_start),
          0
        ) < mp.monthly_hard_cap_units
      )
    )
  ORDER BY mp.priority DESC
  LIMIT 1;

  RETURN v_provider;
END;
$$;


ALTER FUNCTION public.maps_pick_provider_v3(p_capability text, p_exclude text[]) OWNER TO postgres;

--
-- TOC entry 943 (class 1255 OID 66270)
-- Name: maps_pick_provider_v4(text, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_pick_provider_v4(p_capability text, p_exclude text[] DEFAULT '{}'::text[]) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_month_start date := date_trunc('month', (now() AT TIME ZONE 'UTC'))::date;
  v_provider text;
BEGIN
  IF p_capability NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'unknown_capability';
  END IF;

  SELECT mp.provider_code
  INTO v_provider
  FROM public.maps_providers mp
  JOIN public.maps_provider_capabilities mc
    ON mc.provider_code = mp.provider_code
   AND mc.capability = p_capability
   AND mc.enabled = true
  LEFT JOIN public.maps_provider_health mh
    ON mh.provider_code = mp.provider_code
   AND mh.capability = p_capability
  LEFT JOIN LATERAL (
    SELECT COALESCE(SUM(mu.units), 0) AS mtd_units
    FROM public.maps_usage_daily mu
    WHERE mu.provider_code = mp.provider_code
      AND mu.capability = p_capability
      AND mu.day >= v_month_start
  ) u ON true
  WHERE mp.enabled = true
    AND mp.provider_code <> ALL(COALESCE(p_exclude, '{}'::text[]))
    AND (mh.disabled_until IS NULL OR mh.disabled_until <= now())
    -- Soft cap: cut over before hard failures.
    AND (mp.monthly_soft_cap_units IS NULL OR u.mtd_units < mp.monthly_soft_cap_units)
    -- Hard cap: never exceed.
    AND (mp.monthly_hard_cap_units IS NULL OR u.mtd_units < mp.monthly_hard_cap_units)
  ORDER BY mp.priority DESC
  LIMIT 1;

  RETURN v_provider;
END;
$$;


ALTER FUNCTION public.maps_pick_provider_v4(p_capability text, p_exclude text[]) OWNER TO postgres;

--
-- TOC entry 646 (class 1255 OID 66259)
-- Name: maps_provider_health_on_failure_v1(text, text, integer, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_provider_health_on_failure_v1(p_provider_code text, p_capability text, p_http_status integer DEFAULT NULL::integer, p_error_code text DEFAULT NULL::text, p_base_cooldown_seconds integer DEFAULT 60) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_provider text := lower(btrim(p_provider_code));
  v_cap text := lower(btrim(p_capability));
  v_now timestamptz := now();
  v_base int := greatest(0, least(coalesce(p_base_cooldown_seconds, 60), 86400));
  v_new_failures int;
  v_effective int;
BEGIN
  IF v_provider NOT IN ('google','mapbox','here') THEN
    RAISE EXCEPTION 'invalid_provider_code';
  END IF;
  IF v_cap NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'invalid_capability';
  END IF;

  INSERT INTO public.maps_provider_health(provider_code, capability)
  VALUES (v_provider, v_cap)
  ON CONFLICT (provider_code, capability)
  DO NOTHING;

  -- Increment failures.
  UPDATE public.maps_provider_health
  SET
    consecutive_failures = consecutive_failures + 1,
    last_http_status = p_http_status,
    last_error_code = left(coalesce(p_error_code, ''), 120),
    last_failure_at = v_now,
    updated_at = v_now
  WHERE provider_code = v_provider AND capability = v_cap
  RETURNING consecutive_failures INTO v_new_failures;

  -- Exponential backoff capped at 24h.
  v_effective := LEAST(86400, v_base * power(2, GREATEST(0, v_new_failures - 1))::int);

  UPDATE public.maps_provider_health
  SET disabled_until = GREATEST(coalesce(disabled_until, v_now), v_now + make_interval(secs => v_effective)),
      updated_at = v_now
  WHERE provider_code = v_provider AND capability = v_cap;
END;
$$;


ALTER FUNCTION public.maps_provider_health_on_failure_v1(p_provider_code text, p_capability text, p_http_status integer, p_error_code text, p_base_cooldown_seconds integer) OWNER TO postgres;

--
-- TOC entry 1667 (class 1255 OID 66260)
-- Name: maps_provider_health_on_success_v1(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_provider_health_on_success_v1(p_provider_code text, p_capability text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_provider text := lower(btrim(p_provider_code));
  v_cap text := lower(btrim(p_capability));
BEGIN
  IF v_provider NOT IN ('google','mapbox','here') THEN
    RAISE EXCEPTION 'invalid_provider_code';
  END IF;
  IF v_cap NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'invalid_capability';
  END IF;

  INSERT INTO public.maps_provider_health(provider_code, capability)
  VALUES (v_provider, v_cap)
  ON CONFLICT (provider_code, capability)
  DO UPDATE SET
    consecutive_failures = 0,
    disabled_until = NULL,
    updated_at = now();
END;
$$;


