--
-- TOC entry 729 (class 1255 OID 66181)
-- Name: maps_usage_increment_v1(text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.maps_usage_increment_v1(p_provider_code text, p_capability text, p_units integer DEFAULT 1) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_units integer := COALESCE(p_units, 1);
  v_day date := (now() AT TIME ZONE 'UTC')::date;
BEGIN
  IF v_units <= 0 THEN
    RAISE EXCEPTION 'invalid_units';
  END IF;

  -- Validate provider & capability.
  IF NOT EXISTS (SELECT 1 FROM public.maps_providers WHERE provider_code = p_provider_code) THEN
    RAISE EXCEPTION 'unknown_provider';
  END IF;
  IF p_capability NOT IN ('render','directions','geocode','distance_matrix') THEN
    RAISE EXCEPTION 'unknown_capability';
  END IF;

  INSERT INTO public.maps_usage_daily(day, provider_code, capability, units)
  VALUES (v_day, p_provider_code, p_capability, v_units)
  ON CONFLICT (day, provider_code, capability)
  DO UPDATE SET units = public.maps_usage_daily.units + EXCLUDED.units,
                updated_at = now();
END;
$$;


ALTER FUNCTION public.maps_usage_increment_v1(p_provider_code text, p_capability text, p_units integer) OWNER TO postgres;

--
-- TOC entry 1643 (class 1255 OID 44841)
-- Name: merchant_best_promo(uuid, uuid, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_best_promo(p_merchant_id uuid, p_product_id uuid, p_price_iqd bigint) RETURNS TABLE(promo_id uuid, unit_price_iqd bigint, savings_iqd bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  r record;
  best_savings bigint := 0;
  best_unit bigint := p_price_iqd;
  best_id uuid := null;
  now_ts timestamptz := now();
  savings bigint;
  pct numeric;
  fixed numeric;
  v_category text;
begin
  select category into v_category
  from public.merchant_products
  where id = p_product_id and merchant_id = p_merchant_id;

  for r in
    select id, discount_type, value
    from public.merchant_promotions
    where merchant_id = p_merchant_id
      and is_active = true
      and (starts_at is null or starts_at <= now_ts)
      and (ends_at is null or ends_at >= now_ts)
      and (
        (product_id is null and category is null)
        or (product_id = p_product_id)
        or (category is not null and v_category is not null and category = v_category)
      )
  loop
    if r.discount_type = 'percent' then
      pct := r.value;
      savings := floor((p_price_iqd::numeric * pct) / 100)::bigint;
    else
      fixed := r.value;
      savings := floor(fixed)::bigint;
    end if;

    if savings > best_savings then
      best_savings := savings;
      best_id := r.id;
      best_unit := greatest(p_price_iqd - savings, 0);
    end if;
  end loop;

  promo_id := best_id;
  savings_iqd := greatest(best_savings, 0);
  unit_price_iqd := best_unit;
  return next;
end;
$$;


ALTER FUNCTION public.merchant_best_promo(p_merchant_id uuid, p_product_id uuid, p_price_iqd bigint) OWNER TO postgres;

--
-- TOC entry 1496 (class 1255 OID 44716)
-- Name: merchant_chat_get_or_create_thread(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_chat_get_or_create_thread(p_merchant_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_thread_id uuid;
  v_uid uuid;
  v_ok boolean;
begin
  v_uid := (select auth.uid());
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  -- Merchant must be approved for customers. Owners/admins can still access.
  select exists(
    select 1
    from public.merchants m
    where m.id = p_merchant_id
      and (
        m.status = 'approved'
        or m.owner_profile_id = v_uid
        or (select is_admin())
      )
  ) into v_ok;

  if not v_ok then
    raise exception 'Merchant not available';
  end if;

  select id into v_thread_id
  from public.merchant_chat_threads
  where merchant_id = p_merchant_id
    and customer_id = v_uid;

  if v_thread_id is not null then
    return v_thread_id;
  end if;

  insert into public.merchant_chat_threads (merchant_id, customer_id)
  values (p_merchant_id, v_uid)
  returning id into v_thread_id;

  return v_thread_id;
end;
$$;


ALTER FUNCTION public.merchant_chat_get_or_create_thread(p_merchant_id uuid) OWNER TO postgres;

--
-- TOC entry 948 (class 1255 OID 44742)
-- Name: merchant_chat_list_messages(uuid, timestamp with time zone, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_chat_list_messages(p_thread_id uuid, p_before_created_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_before_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 50) RETURNS TABLE(id uuid, thread_id uuid, sender_id uuid, body text, message_type text, attachments jsonb, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  select
    m.id,
    m.thread_id,
    m.sender_id,
    m.body,
    m.message_type,
    m.attachments,
    m.created_at
  from public.merchant_chat_messages m
  where m.thread_id = p_thread_id
    and (
      p_before_created_at is null
      or (
        p_before_id is null
        and m.created_at < p_before_created_at
      )
      or (
        p_before_id is not null
        and (m.created_at, m.id) < (p_before_created_at, p_before_id)
      )
    )
  order by m.created_at desc, m.id desc
  limit least(greatest(p_limit, 1), 200);
$$;


ALTER FUNCTION public.merchant_chat_list_messages(p_thread_id uuid, p_before_created_at timestamp with time zone, p_before_id uuid, p_limit integer) OWNER TO postgres;

--
-- TOC entry 730 (class 1255 OID 44741)
-- Name: merchant_chat_mark_read(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_chat_mark_read(p_thread_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_uid uuid;
  v_customer uuid;
  v_owner uuid;
begin
  v_uid := (select auth.uid());
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select t.customer_id, m.owner_profile_id
    into v_customer, v_owner
  from public.merchant_chat_threads t
  join public.merchants m on m.id = t.merchant_id
  where t.id = p_thread_id;

  if not found then
    raise exception 'Thread not found';
  end if;

  if v_uid = v_customer then
    update public.merchant_chat_threads
      set customer_last_read_at = now()
    where id = p_thread_id;
    return;
  end if;

  if v_uid = v_owner then
    update public.merchant_chat_threads
      set merchant_last_read_at = now()
    where id = p_thread_id;
    return;
  end if;

  if (select is_admin()) then
    -- Admin may mark both sides as read for operational tooling
    update public.merchant_chat_threads
      set customer_last_read_at = coalesce(customer_last_read_at, now()),
          merchant_last_read_at = coalesce(merchant_last_read_at, now())
    where id = p_thread_id;
    return;
  end if;

  raise exception 'Not permitted';
end;
$$;


ALTER FUNCTION public.merchant_chat_mark_read(p_thread_id uuid) OWNER TO postgres;

--
-- TOC entry 1267 (class 1255 OID 44960)
-- Name: merchant_chat_notify_new_message(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_chat_notify_new_message() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_thread record;
  v_receiver uuid;
  v_owner uuid;
  v_body text;
begin
  -- لا نرسل إشعار لرسائل المساعد (حتى ما يزعج الطرفين بإشعارات غير لازمة)
  if new.sender_id = '00000000-0000-0000-0000-00000000a1a1'::uuid or coalesce(new.message_type, '') = 'ai' then
    return new;
  end if;

  v_body := coalesce(nullif(new.body, ''), '');

  select t.id, t.merchant_id, t.customer_id
    into v_thread
  from public.merchant_chat_threads t
  where t.id = new.thread_id;

  if not found then
    return new;
  end if;

  select m.owner_profile_id into v_owner
  from public.merchants m
  where m.id = v_thread.merchant_id;

  -- تحديد المستلم حسب المرسل
  if new.sender_id = v_thread.customer_id then
    v_receiver := v_owner;
  elsif v_owner is not null and new.sender_id = v_owner then
    v_receiver := v_thread.customer_id;
  else
    return new;
  end if;

  if v_receiver is null then
    return new;
  end if;

  insert into public.user_notifications(user_id, kind, title, body, data)
  values (
    v_receiver,
    'merchant_chat_message',
    'مسج جديد',
    case when v_body = '' then null else left(v_body, 140) end,
    jsonb_build_object(
      'thread_id', new.thread_id,
      'merchant_id', v_thread.merchant_id,
      'push', true,
      'inapp', true
    )
  );

  return new;
end;
$$;


ALTER FUNCTION public.merchant_chat_notify_new_message() OWNER TO postgres;

--
-- TOC entry 1787 (class 1255 OID 44714)
