--
-- TOC entry 1435 (class 1255 OID 63371)
-- Name: merchant_cod_handling_fee_compute_iqd(uuid, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_cod_handling_fee_compute_iqd(p_merchant_id uuid, p_goods_amount_iqd bigint) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  cfg public.merchant_commission_configs;
  v_goods bigint := greatest(0, coalesce(p_goods_amount_iqd, 0));
  v_rate integer := 0;
  v_flat bigint := 0;
  v_percent bigint := 0;
BEGIN
  -- Prefer merchant-specific config; fallback to default.
  SELECT * INTO cfg
  FROM public.merchant_commission_configs c
  WHERE c.is_active = true AND c.merchant_id = p_merchant_id
  ORDER BY c.created_at DESC
  LIMIT 1;

  IF NOT FOUND THEN
    SELECT * INTO cfg
    FROM public.merchant_commission_configs c
    WHERE c.is_active = true AND c.merchant_id IS NULL
    ORDER BY c.created_at DESC
    LIMIT 1;
  END IF;

  IF FOUND THEN
    v_rate := coalesce(cfg.cod_handling_rate_bps, 0);
    v_flat := coalesce(cfg.cod_handling_flat_fee_iqd, 0);
  END IF;

  v_percent := (v_goods * v_rate) / 10000;
  RETURN greatest(0, v_percent + v_flat);
END;
$$;


ALTER FUNCTION public.merchant_cod_handling_fee_compute_iqd(p_merchant_id uuid, p_goods_amount_iqd bigint) OWNER TO postgres;

--
-- TOC entry 1330 (class 1255 OID 63116)
-- Name: merchant_commission_compute_iqd(uuid, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_commission_compute_iqd(p_merchant_id uuid, p_goods_amount_iqd bigint) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  cfg public.merchant_commission_configs;
  v_goods bigint := greatest(0, coalesce(p_goods_amount_iqd, 0));
  v_rate integer := 0;
  v_flat bigint := 0;
  v_percent bigint := 0;
BEGIN
  -- Prefer merchant-specific config; fallback to default (merchant_id NULL).
  SELECT * INTO cfg
  FROM public.merchant_commission_configs c
  WHERE c.is_active = true AND c.merchant_id = p_merchant_id
  ORDER BY c.created_at DESC
  LIMIT 1;

  IF NOT FOUND THEN
    SELECT * INTO cfg
    FROM public.merchant_commission_configs c
    WHERE c.is_active = true AND c.merchant_id IS NULL
    ORDER BY c.created_at DESC
    LIMIT 1;
  END IF;

  IF FOUND THEN
    v_rate := coalesce(cfg.rate_bps, 0);
    v_flat := coalesce(cfg.flat_fee_iqd, 0);
  END IF;

  v_percent := (v_goods * v_rate) / 10000;
  RETURN greatest(0, v_percent + v_flat);
END;
$$;


ALTER FUNCTION public.merchant_commission_compute_iqd(p_merchant_id uuid, p_goods_amount_iqd bigint) OWNER TO postgres;

--
-- TOC entry 1762 (class 1255 OID 63117)
-- Name: merchant_order_cod_settlement_after(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_cod_settlement_after() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_order public.merchant_orders;
  v_goods bigint := 0;
  v_commission bigint := 0;
  v_handling bigint := 0;
  v_delivery_id uuid := NEW.id;
  v_idem_base text := 'cod_settle:' || v_delivery_id::text || ':';
BEGIN
  -- Only on first transition to delivered.
  IF NOT (TG_OP = 'UPDATE' AND OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'delivered') THEN
    RETURN NEW;
  END IF;

  -- Only if this delivery is COD.
  IF coalesce(NEW.payment_method_snapshot, 'cod') <> 'cod' THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_order
  FROM public.merchant_orders o
  WHERE o.id = NEW.order_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN NEW;
  END IF;

  -- goods = total - delivery_fee (keep delivery fee out of COD goods due)
  v_goods := greatest(0, coalesce(v_order.total_iqd, 0) - coalesce(v_order.delivery_fee_iqd, 0));

  v_commission := public.merchant_commission_compute_iqd(v_order.merchant_id, v_goods);
  v_handling := public.merchant_cod_handling_fee_compute_iqd(v_order.merchant_id, v_goods);

  -- Driver owes platform the COD goods cash.
  PERFORM public.settlement_post_entry(
    'driver'::public.settlement_party_type,
    NEW.driver_profile_id,
    -v_goods,
    'merchant_cod_goods_due',
    'merchant_order_delivery',
    v_delivery_id,
    v_idem_base || 'driver_goods'
  );

  -- Merchant gross goods.
  PERFORM public.settlement_post_entry(
    'merchant'::public.settlement_party_type,
    v_order.merchant_id,
    v_goods,
    'merchant_cod_gross',
    'merchant_order_delivery',
    v_delivery_id,
    v_idem_base || 'merchant_gross'
  );

  -- Merchant commission.
  IF v_commission > 0 THEN
    PERFORM public.settlement_post_entry(
      'merchant'::public.settlement_party_type,
      v_order.merchant_id,
      -v_commission,
      'merchant_cod_commission',
      'merchant_order_delivery',
      v_delivery_id,
      v_idem_base || 'merchant_commission'
    );
  END IF;

  -- Merchant COD handling fee (separate entry for statement clarity).
  IF v_handling > 0 THEN
    PERFORM public.settlement_post_entry(
      'merchant'::public.settlement_party_type,
      v_order.merchant_id,
      -v_handling,
      'merchant_cod_handling_fee',
      'merchant_order_delivery',
      v_delivery_id,
      v_idem_base || 'merchant_handling'
    );
  END IF;

  -- Mark order as collected COD.
  UPDATE public.merchant_orders
  SET payment_status = 'collected_cod'::public.merchant_order_payment_status,
      paid_at = coalesce(paid_at, now())
  WHERE id = v_order.id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.merchant_order_cod_settlement_after() OWNER TO postgres;

--
-- TOC entry 1676 (class 1255 OID 44842)
-- Name: merchant_order_create(uuid, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_create(p_merchant_id uuid, p_address_id uuid, p_customer_note text, p_items jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  uid uuid;
  order_id uuid;
  it jsonb;
  product_id uuid;
  qty integer;
  prod record;
  promo record;
  unit_price bigint;
  line_total bigint;
  subtotal bigint := 0;
  discount bigint := 0;
  delivery_fee bigint := 0;
  total bigint := 0;
  addr record;
  addr_snapshot jsonb := '{}'::jsonb;

  items_norm jsonb := '[]'::jsonb;
begin
  uid := auth.uid();
  if uid is null then
    raise exception 'Not authenticated';
  end if;

  if not exists (
    select 1 from public.merchants m
    where m.id = p_merchant_id
      and m.status = 'approved'
  ) then
    raise exception 'Merchant not available';
  end if;

  if p_items is null or jsonb_typeof(p_items) <> 'array' or jsonb_array_length(p_items) = 0 then
    raise exception 'Empty order';
  end if;

  if p_address_id is not null then
    select * into addr
    from public.customer_addresses a
    where a.id = p_address_id
      and a.user_id = uid;

    if not found then
      raise exception 'Invalid address';
    end if;

    addr_snapshot := jsonb_build_object(
      'id', addr.id,
      'label', addr.label,
      'recipient_name', addr.recipient_name,
      'phone', addr.phone,
      'city', addr.city,
      'area', addr.area,
      'address_line1', addr.address_line1,
      'address_line2', addr.address_line2,
      'notes', addr.notes
    );
  end if;

  -- Normalize items + compute totals before inserting order.
  for it in select * from jsonb_array_elements(p_items)
  loop
    product_id := (it->>'product_id')::uuid;
    qty := greatest((it->>'qty')::int, 0);

    if qty <= 0 or qty > 99 then
      raise exception 'Invalid qty';
    end if;

    select id, name, price_iqd, is_active into prod
    from public.merchant_products
    where id = product_id
      and merchant_id = p_merchant_id;

    if not found or prod.is_active is not true then
      raise exception 'Invalid product';
    end if;

    select * into promo
    from public.merchant_best_promo(p_merchant_id, product_id, prod.price_iqd);

    unit_price := promo.unit_price_iqd;
    line_total := unit_price * qty;

    subtotal := subtotal + (prod.price_iqd * qty);
    discount := discount + (greatest(prod.price_iqd - unit_price, 0) * qty);

    items_norm := items_norm || jsonb_build_object(
      'product_id', product_id,
      'name', prod.name,
      'unit_price_iqd', unit_price,
      'qty', qty,
      'line_total_iqd', line_total,
      'promo_id', promo.promo_id,
      'original_price_iqd', prod.price_iqd,
      'savings_iqd', promo.savings_iqd
    );
  end loop;

  total := greatest(subtotal - discount + delivery_fee, 0);

  -- Insert order ONCE with final totals (no UPDATE)
  insert into public.merchant_orders(
    merchant_id,
    customer_id,
    status,
    subtotal_iqd,
    discount_iqd,
    delivery_fee_iqd,
    total_iqd,
    address_id,
    address_snapshot,
    customer_note
  ) values (
    p_merchant_id,
    uid,
    'placed'::public.merchant_order_status,
    subtotal,
    discount,
    delivery_fee,
    total,
    p_address_id,
    addr_snapshot,
    nullif(p_customer_note, '')
  ) returning id into order_id;

  -- Insert items
  for it in select * from jsonb_array_elements(items_norm)
  loop
    insert into public.merchant_order_items(
      order_id,
      product_id,
      name_snapshot,
      unit_price_iqd,
      qty,
      line_total_iqd,
      meta
    ) values (
      order_id,
      (it->>'product_id')::uuid,
      it->>'name',
      (it->>'unit_price_iqd')::bigint,
      (it->>'qty')::int,
      (it->>'line_total_iqd')::bigint,
      jsonb_build_object(
        'promo_id', nullif(it->>'promo_id','')::uuid,
        'original_price_iqd', (it->>'original_price_iqd')::bigint,
        'savings_iqd', (it->>'savings_iqd')::bigint
      )
    );
  end loop;

  return order_id;
end;
$$;


ALTER FUNCTION public.merchant_order_create(p_merchant_id uuid, p_address_id uuid, p_customer_note text, p_items jsonb) OWNER TO postgres;

--
-- TOC entry 1747 (class 1255 OID 45078)
-- Name: merchant_order_delivery_audit_after(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_delivery_audit_after() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_actor uuid := (select auth.uid());
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_is_driver boolean := exists (select 1 from public.drivers d where d.id = v_actor);
  v_merch public.merchants;
  v_is_merchant_owner boolean := false;
  v_actor_role public.delivery_actor_role;
  v_from public.merchant_order_delivery_status;
  v_to public.merchant_order_delivery_status;
begin
  v_from := old.status;
  v_to := new.status;

  select *
    into v_merch
  from public.merchants m
  where m.id = coalesce(new.merchant_id, old.merchant_id);

  if found then
    v_is_merchant_owner := (v_merch.owner_profile_id = v_actor);
  end if;

  if tg_op = 'INSERT' then
    insert into public.merchant_order_delivery_events(
      delivery_id, actor_id, actor_role, from_status, to_status, note
    ) values (
      new.id, v_actor, null, null, new.status, null
    );
    return new;
  end if;

  if tg_op = 'UPDATE' and v_to is distinct from v_from then
    if v_is_admin then
      v_actor_role := 'admin'::public.delivery_actor_role;
    elsif v_is_driver then
      v_actor_role := 'driver'::public.delivery_actor_role;
    elsif v_is_merchant_owner then
      v_actor_role := 'merchant'::public.delivery_actor_role;
    else
      v_actor_role := null;
    end if;

    insert into public.merchant_order_delivery_events(
      delivery_id, actor_id, actor_role, from_status, to_status, note
    ) values (
      new.id, v_actor, v_actor_role, v_from, v_to, null
    );

    -- Notifications (unchanged behavior; moved to AFTER).
    if v_to = 'assigned'::public.merchant_order_delivery_status then
      insert into public.user_notifications(user_id, kind, title, body, data)
      values (
        new.customer_id,
        'order_delivery',
        'Delivery assigned',
        'A driver has been assigned to your order delivery.',
        jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
      );

      if v_merch.owner_profile_id is not null then
        insert into public.user_notifications(user_id, kind, title, body, data)
        values (
          v_merch.owner_profile_id,
          'order_delivery',
          'Delivery assigned',
          'A driver claimed the delivery for an order.',
          jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
        );
      end if;

      if new.driver_id is not null then
        insert into public.user_notifications(user_id, kind, title, body, data)
        values (
          new.driver_id,
          'order_delivery',
          'New delivery job',
          'You have been assigned a delivery job.',
          jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
        );
      end if;

    elsif v_to = 'delivered'::public.merchant_order_delivery_status then
      insert into public.user_notifications(user_id, kind, title, body, data)
      values (
        new.customer_id,
        'order_delivery',
        'Order delivered',
        'Your order has been marked as delivered.',
        jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
      );

      if v_merch.owner_profile_id is not null then
        insert into public.user_notifications(user_id, kind, title, body, data)
        values (
          v_merch.owner_profile_id,
          'order_delivery',
          'Order delivered',
          'A delivery has been marked as delivered.',
          jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
        );
      end if;

    elsif v_to = 'cancelled'::public.merchant_order_delivery_status then
      insert into public.user_notifications(user_id, kind, title, body, data)
      values (
        new.customer_id,
        'order_delivery',
        'Delivery cancelled',
        'The delivery for your order was cancelled.',
        jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
      );

      if v_merch.owner_profile_id is not null then
        insert into public.user_notifications(user_id, kind, title, body, data)
        values (
          v_merch.owner_profile_id,
          'order_delivery',
          'Delivery cancelled',
          'The delivery for an order was cancelled.',
          jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
        );
      end if;

      if new.driver_id is not null then
        insert into public.user_notifications(user_id, kind, title, body, data)
        values (
          new.driver_id,
          'order_delivery',
          'Delivery cancelled',
          'A delivery you were assigned to was cancelled.',
          jsonb_build_object('order_id', new.order_id, 'delivery_id', new.id)
        );
      end if;
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.merchant_order_delivery_audit_after() OWNER TO postgres;

--
-- TOC entry 1530 (class 1255 OID 44947)
-- Name: merchant_order_delivery_guard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_delivery_guard() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_actor uuid := (select auth.uid());
  v_is_admin boolean := coalesce((select public.is_admin()), false);
  v_is_driver boolean := exists (select 1 from public.drivers d where d.id = v_actor);
  v_merch public.merchants;
  v_is_merchant_owner boolean := false;
  v_from public.merchant_order_delivery_status;
  v_to public.merchant_order_delivery_status;
  v_method public.merchant_order_payment_method;
  v_expected bigint;
  v_collected bigint;
  v_change bigint;
begin
  -- Resolve merchant + ownership (best-effort; merchant_id should be present)
  select *
    into v_merch
  from public.merchants m
  where m.id = coalesce(new.merchant_id, old.merchant_id);

  if found then
    v_is_merchant_owner := (v_merch.owner_profile_id = v_actor);
  end if;

  v_from := old.status;
  v_to := new.status;

  if tg_op = 'INSERT' then
    -- Only merchant owner (or admin) can create delivery rows
    if not (v_is_admin or v_is_merchant_owner) then
      raise exception 'not_authorized';
    end if;
  end if;

  if tg_op = 'UPDATE' then
    -- Only validate transitions when status changes.
    if v_to is distinct from v_from then
      if v_from = 'requested'::public.merchant_order_delivery_status and v_to = 'assigned'::public.merchant_order_delivery_status then
        -- drivers can claim; admins can assign
        if not (v_is_admin or v_is_driver) then
          raise exception 'not_authorized';
        end if;
        if not v_is_admin and new.driver_id <> v_actor then
          raise exception 'invalid_driver';
        end if;

      elsif v_from = 'assigned'::public.merchant_order_delivery_status and v_to = 'picked_up'::public.merchant_order_delivery_status then
        if not (v_is_admin or (v_is_driver and old.driver_id = v_actor)) then
          raise exception 'not_authorized';
        end if;

      elsif v_from = 'picked_up'::public.merchant_order_delivery_status and v_to = 'delivered'::public.merchant_order_delivery_status then
        if not (v_is_admin or (v_is_driver and old.driver_id = v_actor)) then
          raise exception 'not_authorized';
        end if;

        -- COD enforcement
        v_method := coalesce(new.payment_method_snapshot, old.payment_method_snapshot);
        if v_method = 'cod'::public.merchant_order_payment_method then
          v_expected := coalesce(new.cod_expected_amount_iqd, old.cod_expected_amount_iqd, 0);
          if v_expected <= 0 then
            raise exception 'cod_expected_missing';
          end if;

          if new.cod_collected_amount_iqd is null then
            raise exception 'cod_collection_required';
          end if;

          v_collected := greatest(0, new.cod_collected_amount_iqd);
          v_change := greatest(0, coalesce(new.cod_change_given_iqd, 0));
          if v_collected < v_change then
            raise exception 'cod_invalid_amounts';
          end if;

          if (v_collected - v_change) < v_expected then
            raise exception 'cod_underpaid';
          end if;

          new.cod_collected_at := coalesce(new.cod_collected_at, now());
        end if;

      elsif v_to = 'cancelled'::public.merchant_order_delivery_status then
        -- merchant owner or admin can cancel
        if not (v_is_admin or v_is_merchant_owner) then
          raise exception 'not_authorized';
        end if;

      else
        raise exception 'invalid_status_transition';
      end if;
    end if;
  end if;

  -- Stamp transition timestamps
  if tg_op = 'UPDATE' and v_to is distinct from v_from then
    if v_to = 'assigned'::public.merchant_order_delivery_status then
      new.assigned_at := coalesce(new.assigned_at, now());
    elsif v_to = 'picked_up'::public.merchant_order_delivery_status then
      new.picked_up_at := coalesce(new.picked_up_at, now());
    elsif v_to = 'delivered'::public.merchant_order_delivery_status then
      new.delivered_at := coalesce(new.delivered_at, now());
    elsif v_to = 'cancelled'::public.merchant_order_delivery_status then
      new.cancelled_at := coalesce(new.cancelled_at, now());
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.merchant_order_delivery_guard() OWNER TO postgres;

--
-- TOC entry 1053 (class 1255 OID 44959)
-- Name: merchant_order_get_or_create_chat_thread(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_get_or_create_chat_thread(p_order_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_catalog'
    AS $$
declare
  uid uuid;
  v_order record;
  v_thread_id uuid;
begin
  uid := auth.uid();
  if uid is null then
    raise exception 'Not authenticated';
  end if;

  select o.id, o.merchant_id, o.customer_id, o.chat_thread_id
    into v_order
  from public.merchant_orders o
  where o.id = p_order_id;

  if not found then
    raise exception 'Order not found';
  end if;

  if not (
    v_order.customer_id = uid
    or exists (select 1 from public.merchants m where m.id = v_order.merchant_id and m.owner_profile_id = uid)
    or (select is_admin())
  ) then
    raise exception 'Not allowed';
  end if;

  if v_order.chat_thread_id is not null then
    return v_order.chat_thread_id;
  end if;

  -- FIX: Insert with ON CONFLICT to handle race conditions
  INSERT INTO public.merchant_chat_threads(merchant_id, customer_id)
  VALUES (v_order.merchant_id, v_order.customer_id)
  ON CONFLICT (merchant_id, customer_id) DO NOTHING;

  -- Select the ID (whether it was just inserted or already existed)
  SELECT id INTO v_thread_id
  FROM public.merchant_chat_threads
  WHERE merchant_id = v_order.merchant_id
    AND customer_id = v_order.customer_id;

  -- Link logic
  UPDATE public.merchant_orders
    SET chat_thread_id = v_thread_id
  WHERE id = v_order.id
    AND chat_thread_id IS NULL;

  return v_thread_id;
end;
$$;


ALTER FUNCTION public.merchant_order_get_or_create_chat_thread(p_order_id uuid) OWNER TO postgres;

--
-- TOC entry 1419 (class 1255 OID 44949)
-- Name: merchant_order_request_delivery(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_request_delivery(p_order_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
declare
  v_order public.merchant_orders;
  v_merch public.merchants;
  v_delivery_id uuid;
begin
  select * into v_order
  from public.merchant_orders o
  where o.id = p_order_id
  for update;

  if not found then
    raise exception 'order_not_found';
  end if;

  -- AuthZ: merchant owner or admin
  select * into v_merch from public.merchants m where m.id = v_order.merchant_id;

  if not ( (select is_admin()) or v_merch.owner_profile_id = (select auth.uid()) ) then
    raise exception 'not_authorized';
  end if;

  -- Idempotent: if exists return id
  select d.id into v_delivery_id
  from public.merchant_order_deliveries d
  where d.order_id = v_order.id;

  if v_delivery_id is not null then
    return v_delivery_id;
  end if;

  insert into public.merchant_order_deliveries(
    order_id, merchant_id, customer_id, status,
    pickup_snapshot, dropoff_snapshot,
    fee_iqd,
    payment_method_snapshot,
    cod_expected_amount_iqd
  )
  values (
    v_order.id,
    v_order.merchant_id,
    v_order.customer_id,
    'requested'::public.merchant_order_delivery_status,
    jsonb_build_object(
      'business_name', v_merch.business_name,
      'contact_phone', v_merch.contact_phone,
      'address_text', v_merch.address_text
    ),
    coalesce(v_order.address_snapshot, '{}'::jsonb),
    coalesce(v_order.delivery_fee_iqd, 0),
    coalesce(v_order.payment_method, 'cod'::public.merchant_order_payment_method),
    coalesce(v_order.total_iqd, 0)
  )
  returning id into v_delivery_id;

  return v_delivery_id;
end;
$$;


ALTER FUNCTION public.merchant_order_request_delivery(p_order_id uuid) OWNER TO postgres;

--
-- TOC entry 1368 (class 1255 OID 62234)
-- Name: merchant_order_set_status(uuid, public.merchant_order_status, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_set_status(p_order_id uuid, p_status public.merchant_order_status, p_merchant_note text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  uid uuid;
  o record;
  is_owner boolean := false;
  is_customer boolean := false;
begin
  uid := auth.uid();
  if uid is null then
    raise exception 'Not authenticated';
  end if;

  select * into o from public.merchant_orders where id = p_order_id;
  if not found then
    raise exception 'Order not found';
  end if;

  is_customer := (o.customer_id = uid);
  is_owner := exists (
    select 1 from public.merchants m
    where m.id = o.merchant_id
      and m.owner_profile_id = uid
  );

  if (select public.is_admin()) then
    is_owner := true;
  end if;

  if is_owner then
    update public.merchant_orders
      set status = p_status,
          merchant_note = nullif(p_merchant_note, '')
    where id = p_order_id;
    return;
  end if;

  if is_customer then
    -- customer can only cancel while still placed
    if p_status <> 'cancelled'::public.merchant_order_status or o.status <> 'placed'::public.merchant_order_status then
      raise exception 'Not allowed';
    end if;
    update public.merchant_orders
      set status = 'cancelled'::public.merchant_order_status
    where id = p_order_id;
    return;
  end if;

  raise exception 'Not allowed';
end;
$$;


ALTER FUNCTION public.merchant_order_set_status(p_order_id uuid, p_status public.merchant_order_status, p_merchant_note text) OWNER TO postgres;

