--
-- TOC entry 1593 (class 1255 OID 44881)
-- Name: merchant_order_status_events_on_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_order_status_events_on_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  uid uuid;
  is_owner boolean := false;
begin
  if new.status is not distinct from old.status then
    return new;
  end if;

  uid := auth.uid();
  if uid is not null then
    is_owner := exists (
      select 1
      from public.merchants m
      where m.id = new.merchant_id
        and m.owner_profile_id = uid
    ) or (select public.is_admin());
  end if;

  insert into public.merchant_order_status_events(order_id, actor_id, from_status, to_status, note)
  values (
    new.id,
    uid,
    old.status,
    new.status,
    case when is_owner then nullif(new.merchant_note, '') else null end
  );

  return new;
end;
$$;


ALTER FUNCTION public.merchant_order_status_events_on_status_change() OWNER TO postgres;

--
-- TOC entry 1034 (class 1255 OID 44844)
-- Name: merchant_orders_guard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_orders_guard() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  uid uuid;
  is_owner boolean;
  is_customer boolean;
  is_admin boolean;
begin
  uid := auth.uid();
  is_admin := (select public.is_admin());
  is_customer := (uid is not null and uid = old.customer_id);
  is_owner := (uid is not null and exists (
    select 1 from public.merchants m where m.id = old.merchant_id and m.owner_profile_id = uid
  ));
  if is_admin then
    is_owner := true;
  end if;

  -- Protect totals from client tampering (only allow changes via privileged RPC / admin)
  if (new.subtotal_iqd is distinct from old.subtotal_iqd
      or new.discount_iqd is distinct from old.discount_iqd
      or new.delivery_fee_iqd is distinct from old.delivery_fee_iqd
      or new.total_iqd is distinct from old.total_iqd)
     and not is_admin then
    raise exception 'Totals are immutable';
  end if;

  -- Status transitions:
  if new.status is distinct from old.status then
    new.status_changed_at := now();

    -- Customer can only cancel from placed
    if is_customer and not is_owner then
      if not (old.status = 'placed'::public.merchant_order_status and new.status = 'cancelled'::public.merchant_order_status) then
        raise exception 'Not allowed';
      end if;
      return new;
    end if;

    -- Merchant owner state machine (admin can override)
    if is_owner and not is_admin then
      -- Final states cannot change
      if old.status in ('fulfilled'::public.merchant_order_status,'cancelled'::public.merchant_order_status) then
        raise exception 'Order is final';
      end if;

      if old.status = 'placed'::public.merchant_order_status and new.status not in ('accepted'::public.merchant_order_status,'cancelled'::public.merchant_order_status) then
        raise exception 'Invalid status transition';
      elsif old.status = 'accepted'::public.merchant_order_status and new.status not in ('preparing'::public.merchant_order_status,'cancelled'::public.merchant_order_status) then
        raise exception 'Invalid status transition';
      elsif old.status = 'preparing'::public.merchant_order_status and new.status not in ('out_for_delivery'::public.merchant_order_status,'cancelled'::public.merchant_order_status) then
        raise exception 'Invalid status transition';
      elsif old.status = 'out_for_delivery'::public.merchant_order_status and new.status not in ('fulfilled'::public.merchant_order_status,'cancelled'::public.merchant_order_status) then
        raise exception 'Invalid status transition';
      end if;
    end if;
  end if;

  -- merchant_note can only be set by owner/admin
  if new.merchant_note is distinct from old.merchant_note and not is_owner then
    raise exception 'Not allowed';
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.merchant_orders_guard() OWNER TO postgres;

--
-- TOC entry 1589 (class 1255 OID 63119)
-- Name: merchant_settlement_get_my_account_v1(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_settlement_get_my_account_v1() RETURNS TABLE(balance_iqd bigint, currency text, updated_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid;
  v_merchant_id uuid;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  select m.id into v_merchant_id
  from public.merchants m
  where m.owner_profile_id = v_uid
  order by m.created_at desc
  limit 1;

  if v_merchant_id is null then
    raise exception 'not_a_merchant';
  end if;

  return query
  select coalesce(sa.balance_iqd, 0)::bigint as balance_iqd,
         'IQD'::text as currency,
         coalesce(sa.updated_at, now()) as updated_at
  from public.settlement_accounts sa
  where sa.party_type = 'merchant'::public.settlement_party_type
    and sa.party_id = v_merchant_id
    and sa.currency = 'IQD'
  limit 1;

  if not found then
    return query select 0::bigint, 'IQD'::text, now();
  end if;
end;
$$;


ALTER FUNCTION public.merchant_settlement_get_my_account_v1() OWNER TO postgres;

--
-- TOC entry 653 (class 1255 OID 63120)
-- Name: merchant_settlement_list_entries_v1(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_settlement_list_entries_v1(p_limit integer DEFAULT 100, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, created_at timestamp with time zone, delta_iqd bigint, reason text, ref_type text, ref_id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_uid uuid;
  v_merchant_id uuid;
  v_acct_id uuid;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  select m.id into v_merchant_id
  from public.merchants m
  where m.owner_profile_id = v_uid
  order by m.created_at desc
  limit 1;

  if v_merchant_id is null then
    raise exception 'not_a_merchant';
  end if;

  select sa.id into v_acct_id
  from public.settlement_accounts sa
  where sa.party_type = 'merchant'::public.settlement_party_type
    and sa.party_id = v_merchant_id
    and sa.currency = 'IQD'
  limit 1;

  if v_acct_id is null then
    return;
  end if;

  return query
  select e.id, e.created_at, e.delta_iqd, e.reason, e.ref_type, e.ref_id
  from public.settlement_entries e
  where e.account_id = v_acct_id
  order by e.created_at desc
  limit greatest(1, least(p_limit, 500))
  offset greatest(0, p_offset);
end;
$$;


ALTER FUNCTION public.merchant_settlement_list_entries_v1(p_limit integer, p_offset integer) OWNER TO postgres;

