--

CREATE FUNCTION public.merchant_settlement_list_payment_requests_v1(p_limit integer DEFAULT 50, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, status text, amount_iqd integer, method text, reference text, requested_at timestamp with time zone, processed_at timestamp with time zone, admin_note text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_merchant_id uuid;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT m.id INTO v_merchant_id
  FROM public.merchants m
  WHERE m.owner_profile_id = v_uid
  ORDER BY m.created_at DESC
  LIMIT 1;

  IF v_merchant_id IS NULL THEN
    RAISE EXCEPTION 'not_a_merchant';
  END IF;

  RETURN QUERY
    SELECT r.id, r.status::text, r.amount_iqd, r.method, r.reference, r.requested_at, r.processed_at, r.admin_note
    FROM public.settlement_payment_requests r
    WHERE r.party_type = 'merchant'::public.settlement_party_type
      AND r.party_id = v_merchant_id
    ORDER BY r.requested_at DESC
    LIMIT greatest(1, least(coalesce(p_limit, 50), 200))
    OFFSET greatest(coalesce(p_offset, 0), 0);
END;
$$;


