--
-- TOC entry 1291 (class 1255 OID 63183)
-- Name: merchant_settlement_request_payment_v1(integer, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_settlement_request_payment_v1(p_amount_iqd integer, p_method text, p_reference text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text) RETURNS TABLE(id uuid, status text, amount_iqd integer, method text, reference text, requested_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_merchant_id uuid;
  v_row public.settlement_payment_requests;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT m.id INTO v_merchant_id
  FROM public.merchants m
  WHERE m.owner_profile_id = v_uid
  ORDER BY m.created_at DESC
  LIMIT 1;

  IF v_merchant_id IS NULL THEN
    RAISE EXCEPTION 'not_a_merchant';
  END IF;

  IF p_amount_iqd IS NULL OR p_amount_iqd <= 0 THEN
    RAISE EXCEPTION 'invalid_amount';
  END IF;

  IF COALESCE(NULLIF(trim(p_method), ''), '') = '' THEN
    RAISE EXCEPTION 'invalid_method';
  END IF;

  IF p_idempotency_key IS NOT NULL THEN
    SELECT * INTO v_row
    FROM public.settlement_payment_requests r
    WHERE r.idempotency_key = p_idempotency_key
    LIMIT 1;
    IF FOUND THEN
      RETURN QUERY SELECT v_row.id, v_row.status::text, v_row.amount_iqd, v_row.method, v_row.reference, v_row.requested_at;
      RETURN;
    END IF;
  END IF;

  INSERT INTO public.settlement_payment_requests (
    party_type, party_id, amount_iqd, method, reference, status, requested_by, idempotency_key
  ) VALUES (
    'merchant'::public.settlement_party_type,
    v_merchant_id,
    p_amount_iqd,
    trim(p_method),
    NULLIF(trim(COALESCE(p_reference, '')), ''),
    'requested'::public.settlement_request_status,
    v_uid,
    p_idempotency_key
  )
  RETURNING * INTO v_row;

  RETURN QUERY SELECT v_row.id, v_row.status::text, v_row.amount_iqd, v_row.method, v_row.reference, v_row.requested_at;
END;
$$;


ALTER FUNCTION public.merchant_settlement_request_payment_v1(p_amount_iqd integer, p_method text, p_reference text, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 1122 (class 1255 OID 63185)
-- Name: merchant_settlement_request_payout_v1(integer, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchant_settlement_request_payout_v1(p_amount_iqd integer, p_method text, p_reference text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text) RETURNS TABLE(id uuid, status text, amount_iqd integer, method text, reference text, requested_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_merchant_id uuid;
  v_row public.settlement_payout_requests;
  v_bal bigint;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT m.id INTO v_merchant_id
  FROM public.merchants m
  WHERE m.owner_profile_id = v_uid
  ORDER BY m.created_at DESC
  LIMIT 1;

  IF v_merchant_id IS NULL THEN
    RAISE EXCEPTION 'not_a_merchant';
  END IF;

  IF p_amount_iqd IS NULL OR p_amount_iqd <= 0 THEN
    RAISE EXCEPTION 'invalid_amount';
  END IF;

  IF COALESCE(NULLIF(trim(p_method), ''), '') = '' THEN
    RAISE EXCEPTION 'invalid_method';
  END IF;

  SELECT COALESCE(sa.balance_iqd, 0) INTO v_bal
  FROM public.settlement_accounts sa
  WHERE sa.party_type = 'merchant'::public.settlement_party_type
    AND sa.party_id = v_merchant_id
    AND sa.currency = 'IQD'
  LIMIT 1;

  IF v_bal < p_amount_iqd THEN
    RAISE EXCEPTION 'insufficient_balance';
  END IF;

  IF p_idempotency_key IS NOT NULL THEN
    SELECT * INTO v_row
    FROM public.settlement_payout_requests r
    WHERE r.idempotency_key = p_idempotency_key
    LIMIT 1;
    IF FOUND THEN
      RETURN QUERY SELECT v_row.id, v_row.status::text, v_row.amount_iqd, v_row.method, v_row.reference, v_row.requested_at;
      RETURN;
    END IF;
  END IF;

  INSERT INTO public.settlement_payout_requests (
    party_type, party_id, amount_iqd, method, reference, status, requested_by, idempotency_key
  ) VALUES (
    'merchant'::public.settlement_party_type,
    v_merchant_id,
    p_amount_iqd,
    trim(p_method),
    NULLIF(trim(COALESCE(p_reference, '')), ''),
    'requested'::public.settlement_request_status,
    v_uid,
    p_idempotency_key
  )
  RETURNING * INTO v_row;

  RETURN QUERY SELECT v_row.id, v_row.status::text, v_row.amount_iqd, v_row.method, v_row.reference, v_row.requested_at;
END;
$$;


ALTER FUNCTION public.merchant_settlement_request_payout_v1(p_amount_iqd integer, p_method text, p_reference text, p_idempotency_key text) OWNER TO postgres;

