-- TOC entry 1411 (class 1255 OID 44736)
-- Name: merchants_audit_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchants_audit_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_note text;
begin
  if (tg_op = 'UPDATE') then
    if new.status is distinct from old.status then
      v_note := nullif(current_setting('app.merchant_status_note', true), '');
      insert into public.merchant_status_audit_log (merchant_id, from_status, to_status, note, actor_id)
      values (new.id, old.status, new.status, v_note, (select auth.uid()));
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.merchants_audit_status_change() OWNER TO postgres;

--
-- TOC entry 1708 (class 1255 OID 44601)
-- Name: merchants_guard_status(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.merchants_guard_status() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  -- On insert, enforce pending unless admin
  if (tg_op = 'INSERT') then
    if not (select is_admin()) then
      new.status := 'pending';
    end if;
    return new;
  end if;

  if (tg_op = 'UPDATE') then
    if new.status is distinct from old.status and not (select is_admin()) then
      raise exception 'Only admins can change merchant status';
    end if;
    return new;
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.merchants_guard_status() OWNER TO postgres;

--
-- TOC entry 1597 (class 1255 OID 45140)
-- Name: nearby_available_drivers_v1(double precision, double precision, double precision, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.nearby_available_drivers_v1(p_pickup_lat double precision, p_pickup_lng double precision, p_radius_m double precision, p_stale_after_s integer DEFAULT 120, p_limit integer DEFAULT 100) RETURNS TABLE(driver_id uuid, lat double precision, lng double precision, dist_m double precision, updated_at timestamp with time zone, vehicle_type text)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
  select
    dl.driver_id,
    dl.lat,
    dl.lng,
    extensions.st_distance(
      dl.loc,
      extensions.st_setsrid(extensions.st_makepoint(p_pickup_lng, p_pickup_lat), 4326)::extensions.geography
    ) as dist_m,
    dl.updated_at,
    coalesce(d.vehicle_type, 'car_taxi') as vehicle_type
  from public.driver_locations dl
  join public.drivers d on d.id = dl.driver_id
  where
    public.is_admin(auth.uid()) -- enforce admin
    and d.status = 'available'::public.driver_status
    and dl.updated_at >= now() - make_interval(secs => greatest(0, p_stale_after_s))
    and extensions.st_dwithin(
      dl.loc,
      extensions.st_setsrid(extensions.st_makepoint(p_pickup_lng, p_pickup_lat), 4326)::extensions.geography,
      p_radius_m
    )
  order by dl.loc <-> extensions.st_setsrid(extensions.st_makepoint(p_pickup_lng, p_pickup_lat), 4326)::extensions.geography
  limit p_limit;
$$;


ALTER FUNCTION public.nearby_available_drivers_v1(p_pickup_lat double precision, p_pickup_lng double precision, p_radius_m double precision, p_stale_after_s integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 1014 (class 1255 OID 64946)
-- Name: nearby_available_drivers_v2(double precision, double precision, double precision, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.nearby_available_drivers_v2(p_pickup_lat double precision, p_pickup_lng double precision, p_radius_m double precision DEFAULT 5000, p_stale_after_s integer DEFAULT 120, p_limit integer DEFAULT 25, p_required_capacity integer DEFAULT 4) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_radius double precision := least(greatest(coalesce(p_radius_m, 5000), 100), 50000);
  v_stale integer := least(greatest(coalesce(p_stale_after_s, 120), 10), 3600);
  v_limit integer := least(greatest(coalesce(p_limit, 25), 1), 200);
  v_cap integer := least(greatest(coalesce(p_required_capacity, 4), 1), 8);
  v_point extensions.geography := extensions.st_setsrid(extensions.st_makepoint(p_pickup_lng, p_pickup_lat), 4326)::extensions.geography;
  v_since timestamptz := now() - make_interval(secs => v_stale);
  rl record;
  v_drivers jsonb;
  v_busy_count integer;
begin
  if v_uid is null then
    return jsonb_build_object('allowed', false, 'error', 'not_authenticated');
  end if;

  -- 60 requests per 60 seconds, per-user.
  select * into rl from public.rate_limit_consume('drivers_nearby:' || v_uid::text, 60, 60);

  if not coalesce(rl.allowed, true) then
    return jsonb_build_object(
      'allowed', false,
      'remaining', coalesce(rl.remaining, 0),
      'reset_at', rl.reset_at
    );
  end if;

  with
    busy as (
      select distinct r.driver_id
      from public.rides r
      where r.driver_id is not null
        and r.status in (
          'assigned'::public.ride_status,
          'arrived'::public.ride_status,
          'in_progress'::public.ride_status
        )
    ),
    candidates as (
      select
        dl.driver_id,
        dl.lat,
        dl.lng,
        dl.updated_at,
        extensions.st_distance(dl.loc, v_point) as dist_m
      from public.driver_locations dl
      join public.drivers d on d.id = dl.driver_id
      where d.status = 'available'::public.driver_status
        and dl.updated_at >= v_since
        and not exists (select 1 from busy b where b.driver_id = dl.driver_id)
        and exists (
          select 1
          from public.driver_vehicles dv
          where dv.driver_id = dl.driver_id
            and coalesce(dv.is_active, true) = true
            and coalesce(dv.capacity, 4) >= v_cap
        )
        and extensions.st_dwithin(dl.loc, v_point, v_radius)
      order by dl.loc <-> v_point
      limit v_limit
    )
  select
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', c.driver_id,
          'lat', c.lat,
          'lng', c.lng,
          'dist_m', c.dist_m,
          'updated_at', c.updated_at
        )
        order by c.dist_m
      ),
      '[]'::jsonb
    )
  into v_drivers
  from candidates c;

  select count(*) into v_busy_count
  from (
    select distinct r.driver_id
    from public.rides r
    where r.driver_id is not null
      and r.status in (
        'assigned'::public.ride_status,
        'arrived'::public.ride_status,
        'in_progress'::public.ride_status
      )
  ) t;

  return jsonb_build_object(
    'allowed', true,
    'remaining', coalesce(rl.remaining, 0),
    'reset_at', rl.reset_at,
    'stats', jsonb_build_object(
      'busy_drivers', v_busy_count,
      'scanned_locations', null,
      'matched', jsonb_array_length(v_drivers)
    ),
    'drivers', v_drivers
  );
end;
$$;


ALTER FUNCTION public.nearby_available_drivers_v2(p_pickup_lat double precision, p_pickup_lng double precision, p_radius_m double precision, p_stale_after_s integer, p_limit integer, p_required_capacity integer) OWNER TO postgres;

--
-- TOC entry 1665 (class 1255 OID 55165)
-- Name: normalize_iraq_phone_e164(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.normalize_iraq_phone_e164(p_phone text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog'
    AS $_$
declare
  p text;
begin
  if p_phone is null then
    return null;
  end if;

  p := regexp_replace(trim(p_phone), '[\s\-().]', '', 'g');

  if p like '+%' then
    p := substr(p, 2);
  end if;

  if p like '00%' then
    p := substr(p, 3);
  end if;

  if p like '964%' then
    -- ok
  elsif p like '0%' then
    p := '964' || substr(p, 2);
  elsif p like '7%' then
    p := '964' || p;
  else
    raise exception 'Phone must be an Iraqi mobile number';
  end if;

  if p !~ '^9647[0-9]{9}$' then
    raise exception 'Invalid Iraqi mobile number format';
  end if;

  return '+' || p;
end;
$_$;


ALTER FUNCTION public.normalize_iraq_phone_e164(p_phone text) OWNER TO postgres;

--
-- TOC entry 1061 (class 1255 OID 45071)
-- Name: notification_outbox_claim(integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notification_outbox_claim(p_limit integer DEFAULT 50, p_lock_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id bigint, notification_id uuid, user_id uuid, device_token_id bigint, payload jsonb, attempts integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
begin
  return query
  with picked as (
    select o.id
    from public.notification_outbox o
    where o.status = 'pending'
      and o.next_attempt_at <= now()
    order by o.id
    limit greatest(1, least(coalesce(p_limit, 50), 200))
    for update skip locked
  )
  update public.notification_outbox o
    set status = 'processing',
        attempts = o.attempts + 1,
        last_attempt_at = now(),
        lock_id = p_lock_id,
        locked_at = now()
  where o.id in (select id from picked)
  returning o.id, o.notification_id, o.user_id, o.device_token_id, o.payload, o.attempts;
end;
$$;


ALTER FUNCTION public.notification_outbox_claim(p_limit integer, p_lock_id uuid) OWNER TO postgres;

--
-- TOC entry 802 (class 1255 OID 62235)
-- Name: notification_outbox_mark(bigint, public.outbox_status, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notification_outbox_mark(p_outbox_id bigint, p_status public.outbox_status, p_error text DEFAULT NULL::text, p_retry_seconds integer DEFAULT NULL::integer) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
  v_status public.outbox_status := coalesce(p_status, 'failed'::public.outbox_status);
  v_retry int := coalesce(p_retry_seconds, 0);
begin
  if v_status not in ('sent'::public.outbox_status, 'failed'::public.outbox_status, 'skipped'::public.outbox_status) then
    raise exception 'invalid_status';
  end if;

  if v_status = 'sent'::public.outbox_status then
    update public.notification_outbox
      set status = 'sent',
          sent_at = now(),
          last_error = null,
          lock_id = null,
          locked_at = null
    where id = p_outbox_id;

  elsif v_status = 'skipped'::public.outbox_status then
    update public.notification_outbox
      set status = 'skipped',
          last_error = null,
          lock_id = null,
          locked_at = null
    where id = p_outbox_id;

  else
    -- failed
    if v_retry > 0 then
      -- schedule retry by returning to pending
      update public.notification_outbox
        set status = 'pending',
            next_attempt_at = now() + make_interval(secs => v_retry),
            last_error = left(coalesce(p_error,''), 1000),
            lock_id = null,
            locked_at = null
      where id = p_outbox_id;
    else
      -- permanent fail
      update public.notification_outbox
        set status = 'failed',
            last_error = left(coalesce(p_error,''), 1000),
            lock_id = null,
            locked_at = null
      where id = p_outbox_id;
    end if;
  end if;
end;
$$;


ALTER FUNCTION public.notification_outbox_mark(p_outbox_id bigint, p_status public.outbox_status, p_error text, p_retry_seconds integer) OWNER TO postgres;

--
-- TOC entry 651 (class 1255 OID 44847)
-- Name: notify_merchant_order_created(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notify_merchant_order_created() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  owner_id uuid;
  merchant_name text;
begin
  select m.owner_profile_id, m.business_name into owner_id, merchant_name
  from public.merchants m
  where m.id = new.merchant_id;

  -- merchant owner
  if owner_id is not null then
    insert into public.user_notifications(user_id, kind, title, body, data)
    values (
      owner_id,
      'merchant_order_created',
      'New order received',
      'Order from customer' || case when merchant_name is not null then ' • ' || merchant_name else '' end,
      jsonb_build_object('order_id', new.id, 'merchant_id', new.merchant_id)
    );
  end if;

  -- customer
  insert into public.user_notifications(user_id, kind, title, body, data)
  values (
    new.customer_id,
    'merchant_order_created',
    'Order placed',
    case when merchant_name is not null then 'Your order was placed • ' || merchant_name else 'Your order was placed' end,
    jsonb_build_object('order_id', new.id, 'merchant_id', new.merchant_id)
  );

  return new;
end;
$$;


ALTER FUNCTION public.notify_merchant_order_created() OWNER TO postgres;

--
-- TOC entry 1533 (class 1255 OID 44849)
-- Name: notify_merchant_order_status_changed(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notify_merchant_order_status_changed() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  owner_id uuid;
  merchant_name text;
begin
  if new.status is not distinct from old.status then
    return new;
  end if;

  select m.owner_profile_id, m.business_name into owner_id, merchant_name
  from public.merchants m
  where m.id = new.merchant_id;

  -- customer
  insert into public.user_notifications(user_id, kind, title, body, data)
  values (
    new.customer_id,
    'merchant_order_status',
    'Order status updated',
    'Status: ' || new.status || case when merchant_name is not null then ' • ' || merchant_name else '' end,
    jsonb_build_object('order_id', new.id, 'merchant_id', new.merchant_id, 'status', new.status)
  );

  -- merchant owner
  if owner_id is not null then
    insert into public.user_notifications(user_id, kind, title, body, data)
    values (
      owner_id,
      'merchant_order_status',
      'Order status updated',
      'Status: ' || new.status || case when merchant_name is not null then ' • ' || merchant_name else '' end,
      jsonb_build_object('order_id', new.id, 'merchant_id', new.merchant_id, 'status', new.status)
    );
  end if;

  return new;
end;
$$;


ALTER FUNCTION public.notify_merchant_order_status_changed() OWNER TO postgres;

