-- TOC entry 962 (class 1255 OID 64687)
-- Name: passkey_register(uuid, bytea, bytea, text, text, boolean, text, text, text[], text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.passkey_register(p_user_id uuid, p_credential_id bytea, p_public_key bytea, p_passkey_type text, p_friendly_name text DEFAULT NULL::text, p_backup_eligible boolean DEFAULT false, p_device_type text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text, p_transports text[] DEFAULT NULL::text[], p_webauthn_device_type text DEFAULT NULL::text, p_backup_state boolean DEFAULT NULL::boolean) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_id uuid;
begin
  insert into public.user_passkeys (
    user_id,
    credential_id,
    public_key,
    passkey_type,
    friendly_name,
    backup_eligible,
    backup_state,
    device_type,
    user_agent,
    transports,
    webauthn_device_type
  ) values (
    p_user_id,
    p_credential_id,
    p_public_key,
    p_passkey_type::public.passkey_type,
    left(p_friendly_name, 120),
    coalesce(p_backup_eligible, false),
    coalesce(p_backup_state, false),
    left(p_device_type, 50),
    left(p_user_agent, 500),
    p_transports,
    p_webauthn_device_type
  )
  returning id into v_id;

  -- Audit log: Fixed table name and column names to match Migration 13
  insert into public.passkey_auth_log(user_id, passkey_id, event_type, success, ip_address, user_agent)
  values (p_user_id, v_id, 'registration', true, inet_client_addr(), left(p_user_agent, 500));

  return v_id;
end;
$$;


