-- TOC entry 1424 (class 1255 OID 64677)
-- Name: passkey_revoke(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.passkey_revoke(p_passkey_id uuid, p_reason text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_user_id uuid;
begin
  update public.user_passkeys
  set status = 'revoked',
      revoked_at = now(),
      revoked_reason = p_reason,
      updated_at = now()
  where id = p_passkey_id
    and user_id = auth.uid()
    and status = 'active'
  returning user_id into v_user_id;

  if not found then
    return false;
  end if;

  -- Log revocation
  insert into public.passkey_auth_log (user_id, passkey_id, event_type, success)
  values (v_user_id, p_passkey_id, 'revocation', true);

  return true;
end;
$$;


ALTER FUNCTION public.passkey_revoke(p_passkey_id uuid, p_reason text) OWNER TO postgres;

--
-- TOC entry 965 (class 1255 OID 64675)
-- Name: passkey_update_sign_count(bytea, bigint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.passkey_update_sign_count(p_credential_id bytea, p_new_sign_count bigint) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_current_count bigint;
begin
  select sign_count into v_current_count
  from public.user_passkeys
  where credential_id = p_credential_id
    and status = 'active';

  if not found then
    return false;
  end if;

  -- Clone detection: new count should be greater than current
  if p_new_sign_count <= v_current_count and v_current_count > 0 then
    -- Possible clone detected - don't update, return false
    return false;
  end if;

  update public.user_passkeys
  set sign_count = p_new_sign_count,
      last_used_at = now(),
      use_count = use_count + 1,
      updated_at = now()
  where credential_id = p_credential_id;

  return true;
end;
$$;


ALTER FUNCTION public.passkey_update_sign_count(p_credential_id bytea, p_new_sign_count bigint) OWNER TO postgres;

