--
-- TOC entry 1347 (class 1255 OID 44546)
-- Name: payout_claim_jobs(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payout_claim_jobs(p_limit integer DEFAULT 10, p_lock_seconds integer DEFAULT 300) RETURNS SETOF public.payout_provider_jobs
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
begin
  if current_user <> 'service_role' then
    raise exception 'not_allowed';
  end if;

  return query
  with c as (
    select id
    from public.payout_provider_jobs
    where status in ('queued','failed')
      and next_attempt_at <= now()
      and attempt_count < max_attempts
      and canceled_at is null
      and (locked_at is null or locked_at < now() - (p_lock_seconds || ' seconds')::interval)
    order by next_attempt_at asc, created_at asc
    limit greatest(p_limit, 1)
    for update skip locked
  )
  update public.payout_provider_jobs j
  set locked_at = now(),
      lock_token = gen_random_uuid(),
      updated_at = now()
  from c
  where j.id = c.id
  returning j.*;
end;
$$;


ALTER FUNCTION public.payout_claim_jobs(p_limit integer, p_lock_seconds integer) OWNER TO postgres;

