--
-- TOC entry 1662 (class 1255 OID 63000)
-- Name: platform_fee_compute_iqd(text, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.platform_fee_compute_iqd(p_product_code text, p_service_area_id uuid, p_fare_iqd integer) RETURNS integer
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  cfg record;
  v_rate_bps integer;
  v_flat integer;
  v_fee bigint;
  v_fare bigint;
BEGIN
  v_fare := GREATEST(0, COALESCE(p_fare_iqd, 0))::bigint;

  SELECT * INTO cfg
  FROM public.platform_fee_configs
  WHERE active = true
    AND product_code = COALESCE(NULLIF(p_product_code, ''), 'standard')
    AND (service_area_id = p_service_area_id OR service_area_id IS NULL)
  ORDER BY (service_area_id IS NOT NULL) DESC, updated_at DESC
  LIMIT 1;

  v_rate_bps := COALESCE(cfg.rate_bps, 0);
  v_flat := COALESCE(cfg.flat_fee_iqd, 0);

  v_fee := (v_fare * v_rate_bps) / 10000 + v_flat;
  v_fee := GREATEST(0, v_fee);

  RETURN LEAST(v_fee, 2147483647)::integer;
END;
$$;


ALTER FUNCTION public.platform_fee_compute_iqd(p_product_code text, p_service_area_id uuid, p_fare_iqd integer) OWNER TO postgres;

