--
-- TOC entry 905 (class 1255 OID 41818)
-- Name: referral_status(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.referral_status() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
declare
  v_uid uuid;
  v_code text;
  v_pending int;
  v_rewarded int;
  v_earned bigint;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  select code into v_code
  from public.referral_codes
  where user_id = v_uid;

  select count(*) into v_pending
  from public.referral_invites
  where referrer_id = v_uid and status in ('pending','qualified');

  select count(*) into v_rewarded
  from public.referral_invites
  where referrer_id = v_uid and status = 'rewarded';

  select coalesce(sum(delta_iqd),0) into v_earned
  from public.wallet_entries
  where user_id = v_uid and source_type = 'referral';

  return jsonb_build_object(
    'code', v_code,
    'pending', v_pending,
    'rewarded', v_rewarded,
    'earned_iqd', v_earned
  );
end;
$$;


ALTER FUNCTION public.referral_status() OWNER TO postgres;

--
-- TOC entry 721 (class 1255 OID 62236)
-- Name: refresh_driver_rank_snapshots(public.driver_rank_period, date, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.refresh_driver_rank_snapshots(p_period public.driver_rank_period, p_period_start date, p_limit integer DEFAULT 200) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
declare
  v_period public.driver_rank_period := coalesce(p_period, 'weekly'::public.driver_rank_period);
  v_start date := p_period_start;
  v_end date;
  v_limit integer := greatest(1, least(coalesce(p_limit, 200), 1000));
begin
  if v_start is null then
    raise exception 'period_start_required';
  end if;

  if v_period = 'weekly'::public.driver_rank_period then
    v_end := (v_start + interval '7 days')::date;
  else
    v_end := (date_trunc('month', v_start::timestamptz) + interval '1 month')::date;
  end if;

  delete from public.driver_rank_snapshots
  where period = v_period and period_start = v_start;

  insert into public.driver_rank_snapshots(period, period_start, period_end, driver_id, rank, score_iqd, rides_completed)
  select
    v_period,
    v_start,
    v_end,
    s.driver_id,
    row_number() over (order by s.earnings_iqd desc, s.rides_completed desc, s.driver_id) as rank,
    s.earnings_iqd,
    s.rides_completed
  from (
    select
      r.driver_id,
      sum(r.fare_total_iqd)::bigint as earnings_iqd,
      count(*)::int as rides_completed
    from public.rides r
    where r.status = 'completed'
      and r.completed_at >= v_start
      and r.completed_at < v_end
    group by r.driver_id
    having count(*) > 0
    order by earnings_iqd desc
    limit v_limit
  ) s;

end;
$$;


ALTER FUNCTION public.refresh_driver_rank_snapshots(p_period public.driver_rank_period, p_period_start date, p_limit integer) OWNER TO postgres;

--
-- TOC entry 1076 (class 1255 OID 43608)
-- Name: resolve_service_area(double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.resolve_service_area(p_lat double precision, p_lng double precision) RETURNS TABLE(id uuid, name text, governorate text, pricing_config_id uuid)
    LANGUAGE sql STABLE
    SET search_path TO 'public', 'extensions'
    AS $$
  SELECT sa.id, sa.name, sa.governorate, sa.pricing_config_id
  FROM public.service_areas sa
  WHERE sa.is_active
    AND extensions.ST_Contains(sa.geom, extensions.ST_SetSRID(extensions.ST_Point(p_lng, p_lat), 4326))
  ORDER BY sa.priority DESC, sa.created_at DESC
  LIMIT 1;
$$;


