--
-- TOC entry 1545 (class 1255 OID 41774)
-- Name: ride_chat_get_or_create_thread(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_chat_get_or_create_thread(p_ride_id uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
declare
  v_uid uuid;
  r record;
  v_thread uuid;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  select id, rider_id, driver_id into r
  from public.rides
  where id = p_ride_id
    and (rider_id = v_uid or driver_id = v_uid);

  if not found then
    raise exception 'not_a_participant';
  end if;

  insert into public.ride_chat_threads (ride_id, rider_id, driver_id)
  values (p_ride_id, r.rider_id, r.driver_id)
  on conflict (ride_id) do update
    set updated_at = now()
  returning id into v_thread;

  return v_thread;
end;
$$;


ALTER FUNCTION public.ride_chat_get_or_create_thread(p_ride_id uuid) OWNER TO postgres;

--
-- TOC entry 1505 (class 1255 OID 65025)
-- Name: ride_chat_list_user_v1(uuid, integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_chat_list_user_v1(p_ride_id uuid, p_limit integer DEFAULT 50, p_before timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  v_uid uuid;
  v_thread_id uuid;
  v_limit integer;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  v_limit := GREATEST(1, LEAST(COALESCE(p_limit, 50), 100));

  v_thread_id := public.ride_chat_get_or_create_thread(p_ride_id);

  RETURN (
    WITH msgs AS (
      SELECT
        id,
        thread_id,
        ride_id,
        sender_id,
        kind,
        body,
        attachment_bucket,
        attachment_key,
        metadata,
        created_at
      FROM public.ride_chat_messages
      WHERE thread_id = v_thread_id
        AND (p_before IS NULL OR created_at < p_before)
      ORDER BY created_at DESC
      LIMIT v_limit
    )
    SELECT jsonb_build_object(
      'ok', true,
      'thread_id', v_thread_id,
      'messages', COALESCE(
        (
          SELECT jsonb_agg(to_jsonb(m) ORDER BY m.created_at ASC)
          FROM msgs m
        ),
        '[]'::jsonb
      ),
      'next_cursor', (
        SELECT min(created_at) FROM msgs
      )
    )
  );
END;
$$;


ALTER FUNCTION public.ride_chat_list_user_v1(p_ride_id uuid, p_limit integer, p_before timestamp with time zone) OWNER TO postgres;

--
-- TOC entry 1295 (class 1255 OID 64987)
-- Name: ride_chat_mark_read(uuid, timestamp with time zone, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_chat_mark_read(p_ride_id uuid, p_last_read_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_last_read_message_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
DECLARE
  v_uid uuid;
  v_thread uuid;
  v_at timestamptz;
  v_row record;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'not_authenticated';
  END IF;

  v_thread := public.ride_chat_get_or_create_thread(p_ride_id);
  v_at := COALESCE(p_last_read_at, now());

  IF p_last_read_message_id IS NOT NULL THEN
    PERFORM 1
    FROM public.ride_chat_messages m
    WHERE m.id = p_last_read_message_id
      AND m.ride_id = p_ride_id
      AND (m.thread_id = v_thread OR m.thread_id IS NULL);
    IF NOT FOUND THEN
      RAISE EXCEPTION 'invalid_last_read_message';
    END IF;
  END IF;

  INSERT INTO public.ride_chat_read_receipts (
    ride_id,
    thread_id,
    user_id,
    last_read_at,
    last_read_message_id,
    updated_at
  ) VALUES (
    p_ride_id,
    v_thread,
    v_uid,
    v_at,
    p_last_read_message_id,
    now()
  )
  ON CONFLICT (thread_id, user_id) DO UPDATE
  SET last_read_at = GREATEST(
        COALESCE(public.ride_chat_read_receipts.last_read_at, to_timestamp(0)),
        EXCLUDED.last_read_at
      ),
      last_read_message_id = COALESCE(EXCLUDED.last_read_message_id, public.ride_chat_read_receipts.last_read_message_id),
      updated_at = now()
  RETURNING
    id,
    ride_id,
    thread_id,
    user_id,
    last_read_at,
    last_read_message_id,
    updated_at
  INTO v_row;

  RETURN jsonb_build_object(
    'ok', true,
    'receipt', jsonb_build_object(
      'id', v_row.id,
      'ride_id', v_row.ride_id,
      'thread_id', v_row.thread_id,
      'user_id', v_row.user_id,
      'last_read_at', v_row.last_read_at,
      'last_read_message_id', v_row.last_read_message_id,
      'updated_at', v_row.updated_at
    )
  );
END;
$$;


ALTER FUNCTION public.ride_chat_mark_read(p_ride_id uuid, p_last_read_at timestamp with time zone, p_last_read_message_id uuid) OWNER TO postgres;

--
-- TOC entry 1327 (class 1255 OID 41775)
-- Name: ride_chat_notify_on_message(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_chat_notify_on_message() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
declare
  t record;
  v_to uuid;
begin
  select ride_id, rider_id, driver_id into t
  from public.ride_chat_threads
  where id = new.thread_id;

  if not found then
    return new;
  end if;

  if new.sender_id = t.rider_id then
    v_to := t.driver_id;
  else
    v_to := t.rider_id;
  end if;

  perform public.notify_user(
    v_to,
    'chat_message',
    'New message',
    case when new.kind = 'text' then left(coalesce(new.body,''), 140) else 'Attachment' end,
    jsonb_build_object('ride_id', t.ride_id, 'thread_id', new.thread_id, 'message_id', new.id)
  );

  return new;
end;
$$;


ALTER FUNCTION public.ride_chat_notify_on_message() OWNER TO postgres;

--
-- TOC entry 1179 (class 1255 OID 64986)
-- Name: ride_chat_send_message(uuid, public.chat_message_type, text, text, text, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_chat_send_message(p_ride_id uuid, p_kind public.chat_message_type DEFAULT 'text'::public.chat_message_type, p_text text DEFAULT NULL::text, p_attachment_bucket text DEFAULT NULL::text, p_attachment_key text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb, p_message_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_temp'
    AS $$
DECLARE
  v_uid uuid;
  v_thread uuid;
  v_body text;
  v_id uuid;
  v_msg record;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'not_authenticated';
  END IF;

  -- Normalize inputs
  v_body := NULLIF(btrim(COALESCE(p_text, '')), '');

  IF p_kind = 'text' AND v_body IS NULL THEN
    RAISE EXCEPTION 'text_required';
  END IF;

  IF p_kind = 'image' AND (p_attachment_key IS NULL OR length(btrim(p_attachment_key)) = 0) THEN
    RAISE EXCEPTION 'attachment_key_required';
  END IF;

  -- Membership enforcement + thread creation are centralized here.
  v_thread := public.ride_chat_get_or_create_thread(p_ride_id);

  v_id := COALESCE(p_message_id, gen_random_uuid());

  INSERT INTO public.ride_chat_messages (
    id,
    thread_id,
    ride_id,
    sender_id,
    kind,
    message_type,
    body,
    attachment_bucket,
    attachment_key,
    metadata
  ) VALUES (
    v_id,
    v_thread,
    p_ride_id,
    v_uid,
    p_kind,
    COALESCE(p_kind, 'text'),
    CASE WHEN p_kind = 'text' THEN v_body ELSE NULL END,
    p_attachment_bucket,
    p_attachment_key,
    COALESCE(p_metadata, '{}'::jsonb)
  )
  ON CONFLICT (id) DO NOTHING
  RETURNING
    id,
    thread_id,
    ride_id,
    sender_id,
    kind,
    body,
    attachment_bucket,
    attachment_key,
    metadata,
    created_at
  INTO v_msg;

  IF NOT FOUND THEN
    -- Idempotency path: return the existing message if it matches this caller + ride.
    SELECT
      id,
      thread_id,
      ride_id,
      sender_id,
      kind,
      body,
      attachment_bucket,
      attachment_key,
      metadata,
      created_at
    INTO v_msg
    FROM public.ride_chat_messages
    WHERE id = v_id
      AND ride_id = p_ride_id
      AND sender_id = v_uid;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'message_id_conflict';
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'message', jsonb_build_object(
      'id', v_msg.id,
      'thread_id', v_msg.thread_id,
      'ride_id', v_msg.ride_id,
      'sender_id', v_msg.sender_id,
      'kind', v_msg.kind,
      'body', v_msg.body,
      'attachment_bucket', v_msg.attachment_bucket,
      'attachment_key', v_msg.attachment_key,
      'metadata', COALESCE(v_msg.metadata, '{}'::jsonb),
      'created_at', v_msg.created_at
    )
  );
END;
$$;


ALTER FUNCTION public.ride_chat_send_message(p_ride_id uuid, p_kind public.chat_message_type, p_text text, p_attachment_bucket text, p_attachment_key text, p_metadata jsonb, p_message_id uuid) OWNER TO postgres;

--
-- TOC entry 1583 (class 1255 OID 64997)
-- Name: ride_intent_create_user_v1(double precision, double precision, double precision, double precision, text, text, text, timestamp with time zone, public.ride_intent_source, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_intent_create_user_v1(p_pickup_lat double precision, p_pickup_lng double precision, p_dropoff_lat double precision, p_dropoff_lng double precision, p_pickup_address text DEFAULT NULL::text, p_dropoff_address text DEFAULT NULL::text, p_product_code text DEFAULT 'standard'::text, p_scheduled_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_source public.ride_intent_source DEFAULT 'callcenter'::public.ride_intent_source, p_preferences jsonb DEFAULT '{}'::jsonb, p_intent_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_area_id uuid;
  v_area_name text;
  v_area_governorate text;
  v_intent public.ride_intents;
  v_product text;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  -- Resolve service area from pickup coordinates.
  SELECT sa.id, sa.name, sa.governorate
    INTO v_area_id, v_area_name, v_area_governorate
  FROM public.resolve_service_area(p_pickup_lat, p_pickup_lng) sa;

  IF v_area_id IS NULL THEN
    RAISE EXCEPTION 'outside_service_area';
  END IF;

  -- Normalize product code and validate it's active.
  v_product := lower(left(coalesce(p_product_code, 'standard'), 32));
  IF NOT EXISTS (
    SELECT 1
    FROM public.ride_products rp
    WHERE rp.code = v_product
      AND rp.is_active
  ) THEN
    RAISE EXCEPTION 'invalid_product';
  END IF;

  -- Optional idempotency: if a caller provides p_intent_id and it already exists for
  -- this user, return it instead of inserting a duplicate.
  IF p_intent_id IS NOT NULL THEN
    SELECT * INTO v_intent
    FROM public.ride_intents
    WHERE id = p_intent_id;

    IF FOUND THEN
      IF v_intent.rider_id <> v_uid THEN
        RAISE EXCEPTION 'forbidden';
      END IF;

      RETURN jsonb_build_object(
        'intent', jsonb_build_object(
          'id', v_intent.id,
          'created_at', v_intent.created_at,
          'service_area_id', v_intent.service_area_id,
          'product_code', v_intent.product_code,
          'source', v_intent.source,
          'status', v_intent.status
        ),
        'service_area', jsonb_build_object(
          'id', v_area_id,
          'name', v_area_name,
          'governorate', v_area_governorate
        )
      );
    END IF;
  END IF;

  INSERT INTO public.ride_intents(
    id,
    rider_id,
    pickup_lat,
    pickup_lng,
    dropoff_lat,
    dropoff_lng,
    pickup_address,
    dropoff_address,
    service_area_id,
    product_code,
    scheduled_at,
    source,
    status,
    preferences
  ) VALUES (
    coalesce(p_intent_id, gen_random_uuid()),
    v_uid,
    p_pickup_lat,
    p_pickup_lng,
    p_dropoff_lat,
    p_dropoff_lng,
    p_pickup_address,
    p_dropoff_address,
    v_area_id,
    v_product,
    p_scheduled_at,
    p_source,
    'new'::public.ride_intent_status,
    coalesce(p_preferences, '{}'::jsonb)
  )
  RETURNING * INTO v_intent;

  RETURN jsonb_build_object(
    'intent', jsonb_build_object(
      'id', v_intent.id,
      'created_at', v_intent.created_at,
      'service_area_id', v_intent.service_area_id,
      'product_code', v_intent.product_code,
      'source', v_intent.source,
      'status', v_intent.status
    ),
    'service_area', jsonb_build_object(
      'id', v_area_id,
      'name', v_area_name,
      'governorate', v_area_governorate
    )
  );
END;
$$;


