--
-- TOC entry 1591 (class 1255 OID 39789)
-- Name: ride_requests_set_quote(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_requests_set_quote() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  cfg record;
  v_product text;
  v_total integer;
  v_rider uuid;
BEGIN
  SELECT currency
    INTO cfg
  FROM public.pricing_configs
  WHERE active = true
  ORDER BY created_at DESC
  LIMIT 1;

  IF NEW.currency IS NULL THEN
    NEW.currency := COALESCE(cfg.currency, 'IQD');
  END IF;

  v_product := COALESCE(NEW.product_code, 'standard');
  NEW.product_code := v_product;

  IF NEW.fare_quote_id IS NOT NULL THEN
    SELECT fq.total_iqd, fq.rider_id
      INTO v_total, v_rider
    FROM public.fare_quotes fq
    WHERE fq.id = NEW.fare_quote_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'fare_quote_not_found';
    END IF;

    -- Prevent cross-user quote reuse.
    IF v_rider IS DISTINCT FROM NEW.rider_id THEN
      RAISE EXCEPTION 'fare_quote_rider_mismatch';
    END IF;

    NEW.quote_amount_iqd := COALESCE(v_total, 0);
  END IF;

  IF NEW.quote_amount_iqd IS NULL OR NEW.quote_amount_iqd <= 0 THEN
    RAISE EXCEPTION 'missing_or_invalid_quote';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.ride_requests_set_quote() OWNER TO postgres;

--
-- TOC entry 974 (class 1255 OID 39790)
-- Name: ride_requests_set_status_timestamps(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_requests_set_status_timestamps() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog'
    AS $$
begin
  if tg_op = 'UPDATE' then
    if new.status = 'matched' and old.status = 'requested' and new.matched_at is null then
      new.matched_at := now();
    end if;

    if new.status = 'accepted' and old.status = 'matched' and new.accepted_at is null then
      new.accepted_at := now();
    end if;

    if new.status = 'cancelled' and old.status in ('requested','matched') and new.cancelled_at is null then
      new.cancelled_at := now();
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION public.ride_requests_set_status_timestamps() OWNER TO postgres;

--
-- TOC entry 1612 (class 1255 OID 64981)
-- Name: ride_verify_pickup_pin(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ride_verify_pickup_pin(p_ride_id uuid, p_pin text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_uid uuid;
  r record;
  v_now timestamptz := now();
  v_fail int;
  v_locked_until timestamptz;
  v_secret text;
  v_mac bytea;
  b0 int; b1 int; b2 int; b3 int;
  n bigint;
  v_expected text;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT id, rider_id, driver_id, pickup_pin_required, pickup_pin_verified_at, pickup_pin_fail_count, pickup_pin_locked_until
  INTO r
  FROM public.rides
  WHERE id = p_ride_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ride_not_found';
  END IF;

  IF r.driver_id IS DISTINCT FROM v_uid THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF NOT COALESCE(r.pickup_pin_required, false) THEN
    RETURN jsonb_build_object(
      'ok', true,
      'required', false,
      'verified', r.pickup_pin_verified_at IS NOT NULL,
      'verified_at', r.pickup_pin_verified_at
    );
  END IF;

  IF r.pickup_pin_verified_at IS NOT NULL THEN
    RETURN jsonb_build_object(
      'ok', true,
      'required', true,
      'verified', true,
      'verified_at', r.pickup_pin_verified_at
    );
  END IF;

  v_fail := COALESCE(r.pickup_pin_fail_count, 0);
  v_locked_until := r.pickup_pin_locked_until;

  IF v_locked_until IS NOT NULL AND v_locked_until > v_now THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'PIN_LOCKED',
      'fail_count', v_fail,
      'locked_until', v_locked_until
    );
  END IF;

  v_secret := public._vault_secret('PIN_SECRET');
  IF v_secret IS NULL OR length(v_secret) < 10 THEN
    RAISE EXCEPTION 'missing_pin_secret';
  END IF;

  v_mac := extensions.hmac(
    'ride_pin:' || r.id::text || ':' || r.rider_id::text || ':' || r.driver_id::text,
    v_secret,
    'sha256'
  );

  b0 := get_byte(v_mac, 0);
  b1 := get_byte(v_mac, 1);
  b2 := get_byte(v_mac, 2);
  b3 := get_byte(v_mac, 3);

  n := ((b0::bigint << 24) | (b1::bigint << 16) | (b2::bigint << 8) | b3::bigint);
  n := (n & 4294967295); -- force unsigned 32-bit

  v_expected := lpad(((n % 10000)::text), 4, '0');

  IF COALESCE(trim(p_pin), '') <> v_expected THEN
    v_fail := v_fail + 1;
    v_locked_until := CASE WHEN v_fail >= 5 THEN v_now + interval '10 minutes' ELSE NULL END;

    UPDATE public.rides
    SET pickup_pin_fail_count = v_fail,
        pickup_pin_last_attempt_at = v_now,
        pickup_pin_locked_until = v_locked_until
    WHERE id = p_ride_id;

    RETURN jsonb_build_object(
      'ok', false,
      'code', CASE WHEN v_locked_until IS NOT NULL THEN 'PIN_LOCKED' ELSE 'INVALID_PIN' END,
      'fail_count', v_fail,
      'remaining_attempts', GREATEST(0, 5 - v_fail),
      'locked_until', v_locked_until
    );
  END IF;

  UPDATE public.rides
  SET pickup_pin_verified_at = v_now,
      pickup_pin_fail_count = 0,
      pickup_pin_locked_until = NULL,
      pickup_pin_last_attempt_at = v_now
  WHERE id = p_ride_id;

  INSERT INTO public.ride_events(ride_id, actor_id, actor_type, event_type, payload)
  VALUES (
    p_ride_id,
    v_uid,
    'driver'::public.ride_actor_type,
    'pickup_pin_verified',
    jsonb_build_object('verified_at', v_now)
  );

  RETURN jsonb_build_object(
    'ok', true,
    'required', true,
    'verified', true,
    'verified_at', v_now
  );
END;
$$;


ALTER FUNCTION public.ride_verify_pickup_pin(p_ride_id uuid, p_pin text) OWNER TO postgres;

