-- TOC entry 931 (class 1255 OID 62237)
-- Name: ridecheck_open_event_v1(uuid, public.ridecheck_kind, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ridecheck_open_event_v1(p_ride_id uuid, p_kind public.ridecheck_kind, p_metadata jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  INSERT INTO public.ridecheck_events (ride_id, kind, status, metadata, created_at, updated_at)
  VALUES (p_ride_id, p_kind, 'open', COALESCE(p_metadata,'{}'::jsonb), now(), now())
  ON CONFLICT (ride_id, kind) WHERE status = 'open'
  DO UPDATE SET
    updated_at = EXCLUDED.updated_at,
    metadata = public.ridecheck_events.metadata || EXCLUDED.metadata
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


