--
-- TOC entry 658 (class 1255 OID 64952)
-- Name: ridecheck_respond_user(uuid, public.ridecheck_response, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ridecheck_respond_user(p_event_id uuid, p_response public.ridecheck_response, p_note text DEFAULT NULL::text) RETURNS TABLE(ride_id uuid, event_id uuid, kind public.ridecheck_kind, status public.ridecheck_event_status, already_closed boolean, role public.party_role)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'extensions'
    AS $$
declare
  v_uid uuid;
  v_role public.party_role;
  v_kind public.ridecheck_kind;
  v_status public.ridecheck_event_status;
  v_ride_id uuid;
  v_rider_id uuid;
  v_driver_id uuid;
  v_note text;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'Unauthorized' using errcode = '28000';
  end if;

  select e.ride_id, e.kind, e.status, r.rider_id, r.driver_id
    into v_ride_id, v_kind, v_status, v_rider_id, v_driver_id
  from public.ridecheck_events e
  join public.rides r on r.id = e.ride_id
  where e.id = p_event_id
  for update;

  if v_ride_id is null then
    raise exception 'RideCheck event not found' using errcode = 'P0002';
  end if;

  if v_uid = v_driver_id then
    v_role := 'driver'::public.party_role;
  elsif v_uid = v_rider_id then
    v_role := 'rider'::public.party_role;
  else
    raise exception 'Forbidden' using errcode = '42501';
  end if;

  -- If the event is already closed, treat as idempotent.
  if v_status <> 'open'::public.ridecheck_event_status then
    ride_id := v_ride_id;
    event_id := p_event_id;
    kind := v_kind;
    status := v_status;
    already_closed := true;
    role := v_role;
    return next;
    return;
  end if;

  v_note := nullif(left(coalesce(p_note, ''), 500), '');

  insert into public.ridecheck_responses (event_id, ride_id, user_id, role, response, note)
  values (p_event_id, v_ride_id, v_uid, v_role, p_response, v_note)
  on conflict (event_id, user_id) do update
    set response = excluded.response,
        note = excluded.note;

  update public.ridecheck_events
     set status = case
                    when p_response = 'need_help'::public.ridecheck_response
                      then 'escalated'::public.ridecheck_event_status
                    else 'resolved'::public.ridecheck_event_status
                  end,
         updated_at = now(),
         resolved_at = now(),
         metadata = coalesce(metadata, '{}'::jsonb)
                   || jsonb_build_object('responded_by', v_role, 'response', p_response)
   where id = p_event_id
     and status = 'open'::public.ridecheck_event_status
   returning status into v_status;

  ride_id := v_ride_id;
  event_id := p_event_id;
  kind := v_kind;
  status := v_status;
  already_closed := false;
  role := v_role;
  return next;
end;
$$;


ALTER FUNCTION public.ridecheck_respond_user(p_event_id uuid, p_response public.ridecheck_response, p_note text) OWNER TO postgres;

--
-- TOC entry 769 (class 1255 OID 43880)
-- Name: ridecheck_run_v1(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ridecheck_run_v1() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_now timestamptz := now();
  rec record;
  st record;
  v_dist double precision;
  v_last_dist double precision;
  v_new_streak integer;
  v_moved_m double precision;
  v_last_move timestamptz;
  v_stale boolean;
BEGIN
  FOR rec IN
    SELECT
      r.id AS ride_id,
      r.driver_id,
      r.rider_id,
      rr.dropoff_loc,
      dl.loc AS driver_loc,
      dl.updated_at AS loc_updated_at
    FROM public.rides r
    JOIN public.ride_requests rr ON rr.id = r.request_id
    LEFT JOIN public.driver_locations dl ON dl.driver_id = r.driver_id
    WHERE r.status = 'in_progress'
  LOOP
    v_stale := (rec.loc_updated_at IS NULL) OR (rec.loc_updated_at < v_now - interval '2 minutes');

    IF v_stale THEN
      PERFORM public.ridecheck_open_event_v1(
        rec.ride_id,
        'gps_stale'::public.ridecheck_kind,
        jsonb_build_object('loc_updated_at', rec.loc_updated_at)
      );
      CONTINUE;
    END IF;

    -- Auto-resolve a prior gps_stale once we see fresh updates again
    UPDATE public.ridecheck_events
      SET status = 'resolved',
          resolved_at = COALESCE(resolved_at, v_now),
          updated_at = v_now,
          metadata = metadata || jsonb_build_object('auto_resolved', true, 'reason', 'gps_fresh')
    WHERE ride_id = rec.ride_id AND kind = 'gps_stale'::public.ridecheck_kind AND status = 'open';

    v_dist := extensions.st_distance(rec.driver_loc, rec.dropoff_loc);

    SELECT * INTO st FROM public.ridecheck_state WHERE ride_id = rec.ride_id;

    IF NOT FOUND THEN
      INSERT INTO public.ridecheck_state (ride_id, last_seen_at, last_loc, last_distance_to_dropoff_m, distance_increase_streak, last_move_at, updated_at)
      VALUES (rec.ride_id, v_now, rec.driver_loc, v_dist, 0, v_now, v_now)
      ON CONFLICT (ride_id) DO NOTHING;
      CONTINUE;
    END IF;

    v_moved_m := CASE WHEN st.last_loc IS NULL THEN NULL ELSE extensions.st_distance(rec.driver_loc, st.last_loc) END;
    v_last_move := COALESCE(st.last_move_at, v_now);
    IF v_moved_m IS NULL OR v_moved_m > 30 THEN
      v_last_move := v_now;
    END IF;

    -- Long stop: no movement (>30m) for 3+ minutes
    IF v_now - v_last_move > interval '3 minutes' THEN
      PERFORM public.ridecheck_open_event_v1(
        rec.ride_id,
        'long_stop'::public.ridecheck_kind,
        jsonb_build_object('stopped_since', v_last_move, 'moved_m', COALESCE(v_moved_m, 0))
      );
    END IF;

    v_last_dist := st.last_distance_to_dropoff_m;
    IF v_last_dist IS NOT NULL AND v_dist > v_last_dist + 300 THEN
      v_new_streak := COALESCE(st.distance_increase_streak, 0) + 1;
    ELSE
      v_new_streak := 0;
    END IF;

    -- Route deviation: distance to dropoff increases twice consecutively
    IF v_new_streak >= 2 THEN
      PERFORM public.ridecheck_open_event_v1(
        rec.ride_id,
        'route_deviation'::public.ridecheck_kind,
        jsonb_build_object('distance_m', v_dist, 'prev_distance_m', v_last_dist, 'streak', v_new_streak)
      );
    END IF;

    UPDATE public.ridecheck_state
      SET last_seen_at = v_now,
          last_loc = rec.driver_loc,
          last_distance_to_dropoff_m = v_dist,
          distance_increase_streak = v_new_streak,
          last_move_at = v_last_move,
          updated_at = v_now
    WHERE ride_id = rec.ride_id;

  END LOOP;
END;
$$;


ALTER FUNCTION public.ridecheck_run_v1() OWNER TO postgres;

