--
-- TOC entry 1199 (class 1255 OID 65005)
-- Name: scheduled_ride_cancel_user_v1(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.scheduled_ride_cancel_user_v1(p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  v_uid uuid;
  v_sr public.scheduled_rides;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'unauthorized';
  END IF;

  SELECT * INTO v_sr
  FROM public.scheduled_rides
  WHERE id = p_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'not_found';
  END IF;

  IF v_sr.rider_id <> v_uid THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  IF v_sr.status = 'cancelled'::public.scheduled_ride_status THEN
    RETURN jsonb_build_object(
      'scheduled_ride', to_jsonb(v_sr),
      'already_cancelled', true
    );
  END IF;

  IF v_sr.status <> 'pending'::public.scheduled_ride_status THEN
    RAISE EXCEPTION 'cannot_cancel';
  END IF;

  UPDATE public.scheduled_rides
     SET status = 'cancelled'::public.scheduled_ride_status,
         cancelled_at = now()
   WHERE id = p_id
   RETURNING * INTO v_sr;

  RETURN jsonb_build_object(
    'scheduled_ride', to_jsonb(v_sr),
    'already_cancelled', false
  );
END;
$$;


ALTER FUNCTION public.scheduled_ride_cancel_user_v1(p_id uuid) OWNER TO postgres;

