--
-- TOC entry 741 (class 1255 OID 65016)
-- Name: scheduled_ride_list_user_v1(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.scheduled_ride_list_user_v1(p_limit integer DEFAULT 50) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_user uuid;
  v_limit integer;
  v_rows jsonb;
BEGIN
  v_user := auth.uid();
  IF v_user IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'unauthorized');
  END IF;

  v_limit := greatest(1, least(coalesce(p_limit, 50), 200));

  SELECT COALESCE(jsonb_agg(to_jsonb(sr) ORDER BY sr.scheduled_at ASC), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT *
    FROM public.scheduled_rides
    WHERE rider_id = v_user
    ORDER BY scheduled_at ASC
    LIMIT v_limit
  ) sr;

  RETURN jsonb_build_object('ok', true, 'scheduled_rides', v_rows);
END;
$$;


ALTER FUNCTION public.scheduled_ride_list_user_v1(p_limit integer) OWNER TO postgres;

--
-- TOC entry 822 (class 1255 OID 43575)
-- Name: scheduled_rides_execute_due(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.scheduled_rides_execute_due(p_limit integer DEFAULT 100) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public, extensions'
    AS $$
DECLARE
  r record;
  v_request_id uuid;
  v_count integer := 0;
BEGIN
  FOR r IN
    SELECT *
    FROM public.scheduled_rides
    WHERE status = 'pending'
      AND scheduled_at <= now()
    ORDER BY scheduled_at ASC
    LIMIT greatest(1, least(p_limit, 1000))
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      INSERT INTO public.ride_requests (
        rider_id,
        pickup_lat,
        pickup_lng,
        dropoff_lat,
        dropoff_lng,
        pickup_address,
        dropoff_address,
        product_code,
        preferences,
        service_area_id,
        currency,
        fare_quote_id,
        quote_amount_iqd,
        payment_method,
        payment_status
      ) VALUES (
        r.rider_id,
        r.pickup_lat,
        r.pickup_lng,
        r.dropoff_lat,
        r.dropoff_lng,
        r.pickup_address,
        r.dropoff_address,
        r.product_code,
        r.preferences,
        r.service_area_id,
        COALESCE(r.currency, 'IQD'),
        r.fare_quote_id,
        r.quote_amount_iqd,
        COALESCE(r.payment_method, 'wallet'::public.ride_payment_method),
        COALESCE(r.payment_status, 'unpaid'::public.ride_payment_status)
      )
      RETURNING id INTO v_request_id;

      PERFORM 1 FROM public.dispatch_match_ride(v_request_id, r.rider_id);

      UPDATE public.scheduled_rides
      SET
        status = 'executed',
        executed_at = now(),
        ride_request_id = v_request_id,
        failure_reason = NULL,
        updated_at = now()
      WHERE id = r.id;

      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      UPDATE public.scheduled_rides
      SET
        status = 'failed',
        failure_reason = SQLERRM,
        updated_at = now()
      WHERE id = r.id;
    END;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION public.scheduled_rides_execute_due(p_limit integer) OWNER TO postgres;

--
-- TOC entry 1601 (class 1255 OID 56458)
-- Name: search_catalog_v1(text, integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_catalog_v1(p_query text, p_limit integer DEFAULT 10, p_merchant_id uuid DEFAULT NULL::uuid) RETURNS TABLE(entity_type text, merchant_id uuid, merchant_name text, business_type text, product_id uuid, product_name text, category text, price_iqd integer, score real)
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog, public'
    AS $$
  WITH params AS (
    SELECT NULLIF(btrim(p_query), '') AS q,
           LEAST(GREATEST(COALESCE(p_limit, 10), 1), 50) AS lim,
           p_merchant_id AS mid
  ),
  merchants AS (
    SELECT
      'merchant'::text AS entity_type,
      m.id AS merchant_id,
      m.business_name AS merchant_name,
      m.business_type,
      NULL::uuid AS product_id,
      NULL::text AS product_name,
      NULL::text AS category,
      NULL::integer AS price_iqd,
      GREATEST(
        extensions.similarity(m.business_name::text, (SELECT q FROM params)::text),
        extensions.similarity(COALESCE(m.business_type,'')::text, (SELECT q FROM params)::text)
      )::real AS score
    FROM public.merchants m
    WHERE (SELECT q FROM params) IS NOT NULL
      AND m.status = 'approved'::public.merchant_status
      AND (
        m.business_name ILIKE '%' || (SELECT q FROM params) || '%'
        OR COALESCE(m.business_type,'') ILIKE '%' || (SELECT q FROM params) || '%'
        OR extensions.similarity(m.business_name::text, (SELECT q FROM params)::text) > 0.2
      )
  ),
  products AS (
    SELECT
      'product'::text AS entity_type,
      p.merchant_id,
      m.business_name,
      m.business_type,
      p.id AS product_id,
      p.name AS product_name,
      p.category,
      p.price_iqd,
      GREATEST(
        extensions.similarity(p.name::text, (SELECT q FROM params)::text),
        extensions.similarity(COALESCE(p.category,'')::text, (SELECT q FROM params)::text)
      )::real AS score
    FROM public.merchant_products p
    JOIN public.merchants m ON m.id = p.merchant_id
    WHERE (SELECT q FROM params) IS NOT NULL
      AND p.is_active = true
      AND m.status = 'approved'::public.merchant_status
      AND ((SELECT mid FROM params) IS NULL OR p.merchant_id = (SELECT mid FROM params))
      AND (
        p.name ILIKE '%' || (SELECT q FROM params) || '%'
        OR COALESCE(p.category,'') ILIKE '%' || (SELECT q FROM params) || '%'
        OR extensions.similarity(p.name::text, (SELECT q FROM params)::text) > 0.2
        OR extensions.similarity(COALESCE(p.category,'')::text, (SELECT q FROM params)::text) > 0.2
      )
  )
  SELECT *
  FROM (
    SELECT * FROM merchants
    UNION ALL
    SELECT * FROM products
  ) s
  ORDER BY score DESC, merchant_name ASC NULLS LAST
  LIMIT (SELECT lim FROM params);
$$;


ALTER FUNCTION public.search_catalog_v1(p_query text, p_limit integer, p_merchant_id uuid) OWNER TO postgres;

--
-- TOC entry 1713 (class 1255 OID 62238)
-- Name: set_my_active_role(public.user_role); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.set_my_active_role(p_role public.user_role) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  uid uuid;
begin
  uid := auth.uid();
  if uid is null then
    raise exception 'Not authenticated';
  end if;

  if p_role = 'driver'::public.user_role and not exists (select 1 from public.drivers d where d.id = uid) then
    raise exception 'Driver not setup';
  end if;

  if p_role = 'merchant'::public.user_role and not exists (select 1 from public.merchants m where m.owner_profile_id = uid) then
    raise exception 'Merchant not setup';
  end if;

  update public.profiles
    set active_role = p_role
  where id = uid;
end;
$$;


