CREATE TABLE public.settlement_entries (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    delta_iqd bigint NOT NULL,
    reason text NOT NULL,
    ref_type text,
    ref_id uuid,
    idempotency_key text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE public.settlement_entries OWNER TO postgres;

--
-- TOC entry 1756 (class 1255 OID 63031)
-- Name: settlement_post_entry(public.settlement_party_type, uuid, bigint, text, text, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.settlement_post_entry(p_party_type public.settlement_party_type, p_party_id uuid, p_delta_iqd bigint, p_reason text, p_ref_type text, p_ref_id uuid, p_idempotency_key text) RETURNS public.settlement_entries
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
DECLARE
  acct public.settlement_accounts;
  ent public.settlement_entries;
BEGIN
  -- Idempotency guard
  IF p_idempotency_key IS NOT NULL THEN
    SELECT * INTO ent
    FROM public.settlement_entries
    WHERE idempotency_key = p_idempotency_key
    LIMIT 1;
    IF FOUND THEN
      RETURN ent;
    END IF;
  END IF;

  INSERT INTO public.settlement_accounts (party_type, party_id, currency)
  VALUES (p_party_type, p_party_id, 'IQD')
  ON CONFLICT (party_type, party_id, currency) DO NOTHING;

  SELECT * INTO acct
  FROM public.settlement_accounts
  WHERE party_type = p_party_type AND party_id = p_party_id AND currency = 'IQD'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'settlement_account_missing';
  END IF;

  INSERT INTO public.settlement_entries (account_id, delta_iqd, reason, ref_type, ref_id, idempotency_key)
  VALUES (acct.id, p_delta_iqd, COALESCE(p_reason, ''), p_ref_type, p_ref_id, p_idempotency_key)
  RETURNING * INTO ent;

  UPDATE public.settlement_accounts
  SET balance_iqd = balance_iqd + p_delta_iqd,
      updated_at = now()
  WHERE id = acct.id;

  RETURN ent;
END;
$$;


ALTER FUNCTION public.settlement_post_entry(p_party_type public.settlement_party_type, p_party_id uuid, p_delta_iqd bigint, p_reason text, p_ref_type text, p_ref_id uuid, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 1377 (class 1255 OID 63374)
-- Name: settlement_statement_entries_v1(public.settlement_party_type, uuid, timestamp with time zone, timestamp with time zone, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.settlement_statement_entries_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_start timestamp with time zone, p_end timestamp with time zone, p_limit integer DEFAULT 200, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, created_at timestamp with time zone, delta_iqd bigint, reason text, ref_type text, ref_id uuid, running_balance_iqd bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
WITH acct AS (
  SELECT a.id
  FROM public.settlement_accounts a
  WHERE a.party_type = p_party_type AND a.party_id = p_party_id AND a.currency = 'IQD'
  LIMIT 1
),
opening AS (
  SELECT coalesce(sum(e.delta_iqd), 0)::bigint AS bal
  FROM public.settlement_entries e
  JOIN acct a ON a.id = e.account_id
  WHERE e.created_at < p_start
),
period AS (
  SELECT e.id, e.created_at, e.delta_iqd, e.reason, e.ref_type, e.ref_id
  FROM public.settlement_entries e
  JOIN acct a ON a.id = e.account_id
  WHERE e.created_at >= p_start AND e.created_at < p_end
  ORDER BY e.created_at ASC, e.id ASC
  LIMIT greatest(1, least(coalesce(p_limit, 200), 1000))
  OFFSET greatest(coalesce(p_offset, 0), 0)
)
SELECT
  p.id,
  p.created_at,
  p.delta_iqd,
  p.reason,
  p.ref_type,
  p.ref_id,
  (o.bal + sum(p.delta_iqd) OVER (ORDER BY p.created_at, p.id ROWS UNBOUNDED PRECEDING))::bigint AS running_balance_iqd
FROM period p CROSS JOIN opening o
$$;


ALTER FUNCTION public.settlement_statement_entries_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_start timestamp with time zone, p_end timestamp with time zone, p_limit integer, p_offset integer) OWNER TO postgres;

--
-- TOC entry 672 (class 1255 OID 63373)
-- Name: settlement_statement_summary_v1(public.settlement_party_type, uuid, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.settlement_statement_summary_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_start timestamp with time zone, p_end timestamp with time zone) RETURNS TABLE(opening_balance_iqd bigint, closing_balance_iqd bigint, credits_iqd bigint, debits_iqd bigint, entry_count bigint)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $$
WITH acct AS (
  SELECT a.id
  FROM public.settlement_accounts a
  WHERE a.party_type = p_party_type AND a.party_id = p_party_id AND a.currency = 'IQD'
  LIMIT 1
),
opening AS (
  SELECT coalesce(sum(e.delta_iqd), 0)::bigint AS bal
  FROM public.settlement_entries e
  JOIN acct a ON a.id = e.account_id
  WHERE e.created_at < p_start
),
period AS (
  SELECT e.delta_iqd
  FROM public.settlement_entries e
  JOIN acct a ON a.id = e.account_id
  WHERE e.created_at >= p_start AND e.created_at < p_end
)
SELECT
  (SELECT bal FROM opening) AS opening_balance_iqd,
  ((SELECT bal FROM opening) + coalesce((SELECT sum(delta_iqd) FROM period),0))::bigint AS closing_balance_iqd,
  coalesce((SELECT sum(delta_iqd) FROM period WHERE delta_iqd > 0), 0)::bigint AS credits_iqd,
  coalesce((SELECT -sum(delta_iqd) FROM period WHERE delta_iqd < 0), 0)::bigint AS debits_iqd,
  coalesce((SELECT count(*) FROM period), 0)::bigint AS entry_count
$$;


ALTER FUNCTION public.settlement_statement_summary_v1(p_party_type public.settlement_party_type, p_party_id uuid, p_start timestamp with time zone, p_end timestamp with time zone) OWNER TO postgres;

