--
-- TOC entry 1037 (class 1255 OID 39793)
-- Name: submit_ride_rating(uuid, smallint, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.submit_ride_rating(p_ride_id uuid, p_rating smallint, p_comment text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog'
    AS $$
declare
  v_uid uuid;
  v_ride public.rides%rowtype;
  v_rater_role public.party_role;
  v_ratee_role public.party_role;
  v_ratee_id uuid;
  v_rating_id uuid;
begin
  v_uid := auth.uid();
  if v_uid is null then
    raise exception 'not_authenticated';
  end if;

  select * into v_ride
  from public.rides
  where id = p_ride_id
    and status = 'completed'
    and (rider_id = v_uid or driver_id = v_uid);

  if not found then
    raise exception 'not_allowed';
  end if;

  if v_ride.rider_id = v_uid then
    v_rater_role := 'rider';
    v_ratee_role := 'driver';
    v_ratee_id := v_ride.driver_id;
  else
    v_rater_role := 'driver';
    v_ratee_role := 'rider';
    v_ratee_id := v_ride.rider_id;
  end if;

  insert into public.ride_ratings (ride_id, rater_id, ratee_id, rater_role, ratee_role, rating, comment)
  values (p_ride_id, v_uid, v_ratee_id, v_rater_role, v_ratee_role, p_rating, p_comment)
  on conflict (ride_id, rater_id) do nothing;

  select id into v_rating_id
  from public.ride_ratings
  where ride_id = p_ride_id and rater_id = v_uid;

  return v_rating_id;
end;
$$;


ALTER FUNCTION public.submit_ride_rating(p_ride_id uuid, p_rating smallint, p_comment text) OWNER TO postgres;

--
-- TOC entry 954 (class 1255 OID 65015)
-- Name: support_article_get_public_v1(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.support_article_get_public_v1(p_slug text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_article jsonb;
BEGIN
  IF p_slug IS NULL OR btrim(p_slug) = '' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'missing_slug');
  END IF;

  SELECT to_jsonb(a)
  INTO v_article
  FROM public.support_articles a
  WHERE a.enabled = true
    AND a.slug = btrim(p_slug)
  LIMIT 1;

  IF v_article IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'not_found');
  END IF;

  -- Keep response shape compatible with the previous Edge endpoint.
  RETURN jsonb_build_object('ok', true, 'article', v_article);
END;
$$;


ALTER FUNCTION public.support_article_get_public_v1(p_slug text) OWNER TO postgres;

--
-- TOC entry 990 (class 1255 OID 65014)
-- Name: support_articles_list_public_v1(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.support_articles_list_public_v1() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_sections jsonb;
  v_articles jsonb;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', s.id,
        'key', s.key,
        'title', s.title,
        'sort_order', s.sort_order
      )
      ORDER BY s.sort_order ASC
    ),
    '[]'::jsonb
  )
  INTO v_sections
  FROM public.support_sections s
  WHERE s.enabled = true;

  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', a.id,
        'section_id', a.section_id,
        'slug', a.slug,
        'title', a.title,
        'summary', a.summary,
        'tags', a.tags,
        'updated_at', a.updated_at
      )
      ORDER BY a.updated_at DESC
    ),
    '[]'::jsonb
  )
  INTO v_articles
  FROM (
    SELECT a.*
    FROM public.support_articles a
    WHERE a.enabled = true
    ORDER BY a.updated_at DESC
    LIMIT 200
  ) a;

  RETURN jsonb_build_object('ok', true, 'sections', v_sections, 'articles', v_articles);
END;
$$;


ALTER FUNCTION public.support_articles_list_public_v1() OWNER TO postgres;

