--
-- TOC entry 1140 (class 1255 OID 45083)
-- Name: transition_driver(uuid, public.driver_status, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.transition_driver(p_driver_id uuid, p_to_status public.driver_status, p_actor_id uuid DEFAULT NULL::uuid, p_reason text DEFAULT NULL::text) RETURNS public.drivers
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  d public.drivers;
  v_from public.driver_status;
  v_valid boolean := false;
BEGIN
  -- Lock and fetch current state
  SELECT * INTO d FROM public.drivers WHERE id = p_driver_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'driver_not_found';
  END IF;

  v_from := d.status;

  -- Idempotent: no-op if already in target state
  IF v_from = p_to_status THEN
    RETURN d;
  END IF;

  -- State machine validation
  v_valid := CASE
    -- Going online/offline
    WHEN v_from = 'offline' AND p_to_status = 'available' THEN true
    WHEN v_from = 'available' AND p_to_status = 'offline' THEN true

    -- Matching flow
    WHEN v_from = 'available' AND p_to_status = 'reserved' THEN true
    WHEN v_from = 'reserved' AND p_to_status = 'available' THEN true  -- Match failed/expired
    WHEN v_from = 'reserved' AND p_to_status = 'on_trip' THEN true    -- Accept

    -- Ride completion
    WHEN v_from = 'on_trip' AND p_to_status = 'available' THEN true

    -- Admin suspension (can suspend from any active state)
    WHEN p_to_status = 'suspended' AND v_from IN ('offline', 'available', 'reserved', 'on_trip') THEN true
    WHEN v_from = 'suspended' AND p_to_status = 'offline' THEN true

    -- Legacy: assigned status (treat like reserved for backward compat)
    WHEN v_from = 'assigned' AND p_to_status = 'on_trip' THEN true
    WHEN v_from = 'assigned' AND p_to_status = 'available' THEN true

    ELSE false
  END;

  IF NOT v_valid THEN
    RAISE EXCEPTION 'invalid_driver_transition: % -> %', v_from, p_to_status;
  END IF;


  -- Consistency guard: a driver cannot be set to 'available' while holding an active matched request.
  -- This prevents a state where drivers look available but are blocked by the unique match constraint.
  IF p_to_status = 'available'::public.driver_status THEN
    IF EXISTS (
      SELECT 1
      FROM public.ride_requests rr
      WHERE rr.assigned_driver_id = p_driver_id
        AND rr.status = 'matched'
        AND (rr.match_deadline IS NULL OR rr.match_deadline > now())
    ) THEN
      RAISE EXCEPTION 'driver_has_active_match';
    END IF;
  END IF;

  -- Perform the transition
  UPDATE public.drivers
  SET status = p_to_status,
      updated_at = now()
  WHERE id = p_driver_id
  RETURNING * INTO d;

  -- Audit log (optional, if driver_status_events table exists)
  BEGIN
    INSERT INTO public.driver_status_events (driver_id, actor_id, from_status, to_status, reason, created_at)
    VALUES (p_driver_id, p_actor_id, v_from, p_to_status, p_reason, now());
  EXCEPTION WHEN undefined_table THEN
    -- Table doesn't exist, skip audit logging
    NULL;
  END;

  RETURN d;
END;
$$;


