--
-- TOC entry 1473 (class 1255 OID 56563)
-- Name: trg_mct_set_last_preview(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_mct_set_last_preview() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
  fk_col text;
  v_thread_id uuid;
  v_msg_text text;
  v_created_at timestamptz;
begin
  -- Find FK column on merchant_chat_messages referencing merchant_chat_threads
  select a.attname into fk_col
  from pg_constraint c
  join pg_attribute a
    on a.attrelid = c.conrelid
   and a.attnum = any (c.conkey)
  where c.contype = 'f'
    and c.conrelid = 'public.merchant_chat_messages'::regclass
    and c.confrelid = 'public.merchant_chat_threads'::regclass
  limit 1;

  if fk_col is null then
    -- no FK found; do nothing
    return new;
  end if;

  -- Extract thread id dynamically: NEW.<fk_col>
  execute format('select ($1).%I::uuid', fk_col)
    into v_thread_id
    using new;

  if v_thread_id is null then
    return new;
  end if;

  -- Extract message text without hardcoding column names
  v_msg_text := coalesce(
    to_jsonb(new)->>'content',
    to_jsonb(new)->>'message',
    to_jsonb(new)->>'text',
    to_jsonb(new)->>'body',
    ''
  );

  -- Extract created_at if present; else use now()
  v_created_at := (to_jsonb(new)->>'created_at')::timestamptz;
  if v_created_at is null then
    v_created_at := now();
  end if;

  update public.merchant_chat_threads t
     set last_message_at = greatest(coalesce(t.last_message_at, v_created_at), v_created_at),
         last_message_preview = left(v_msg_text, 160)
   where t.id = v_thread_id;

  return new;
end;
$_$;


ALTER FUNCTION public.trg_mct_set_last_preview() OWNER TO postgres;

