--

CREATE FUNCTION public.trg_wh_interest_seed() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog'
    AS $$
declare
  payload jsonb;
  should_fire boolean := false;
begin
  if tg_op = 'INSERT' then
    should_fire := true;
  elsif tg_op = 'UPDATE' then
    if coalesce(old.enabled,false) = false and coalesce(new.enabled,false) = true then
      should_fire := true;
    end if;
  end if;

  if not should_fire then
    return new;
  end if;

  payload := jsonb_build_object(
    'type', tg_op,
    'schema', tg_table_schema,
    'table', tg_table_name,
    'record', to_jsonb(new),
    'old_record', case when tg_op = 'INSERT' then null else to_jsonb(old) end
  );

  perform public._edge_webhook_post(
    'interest-seed',
    'INTEREST_WEBHOOK_SECRET',
    payload
  );

  return new;
end $$;


