--
-- TOC entry 625 (class 1255 OID 64994)
-- Name: trg_wh_trip_share_auto(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_wh_trip_share_auto() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
DECLARE
  payload jsonb;
  v_enabled boolean;
  v_ttl integer;
BEGIN
  IF TG_OP <> 'UPDATE' THEN
    RETURN NEW;
  END IF;

  IF NEW.status IS DISTINCT FROM 'in_progress'::public.ride_status THEN
    RETURN NEW;
  END IF;

  IF OLD.status IS NOT DISTINCT FROM NEW.status THEN
    RETURN NEW;
  END IF;

  IF NEW.rider_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT auto_share_on_trip_start, default_share_ttl_minutes
  INTO v_enabled, v_ttl
  FROM public.user_safety_settings
  WHERE user_id = NEW.rider_id;

  IF NOT COALESCE(v_enabled, false) THEN
    RETURN NEW;
  END IF;

  payload := jsonb_build_object(
    'type', 'UPDATE',
    'schema', TG_TABLE_SCHEMA,
    'table', TG_TABLE_NAME,
    'record', to_jsonb(NEW),
    'old_record', to_jsonb(OLD),
    'meta', jsonb_build_object('ttl_minutes', COALESCE(v_ttl, 120))
  );

  PERFORM public._edge_webhook_post(
    'trip-share-auto',
    'DISPATCH_WEBHOOK_SECRET',
    payload
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_wh_trip_share_auto() OWNER TO postgres;

--
-- TOC entry 813 (class 1255 OID 64044)
-- Name: trip_claim_pending_broadcasts(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trip_claim_pending_broadcasts(p_limit integer DEFAULT 100) RETURNS TABLE(transition_id uuid, trip_id uuid, new_status text, eta_minutes integer, distance_remaining_m integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog, public'
    AS $$
begin
  return query
  with claimed as (
    select t.id, t.trip_id, t.new_status, t.eta_minutes, t.distance_remaining_m
    from public.trip_status_transitions t
    where t.broadcast_sent = false
    order by t.created_at asc
    limit p_limit
    for update skip locked
  )
  update public.trip_status_transitions ts
  set broadcast_sent = true, broadcast_at = now()
  from claimed c
  where ts.id = c.id
  returning c.id as transition_id, c.trip_id, c.new_status, c.eta_minutes, c.distance_remaining_m;
end;
$$;


ALTER FUNCTION public.trip_claim_pending_broadcasts(p_limit integer) OWNER TO postgres;

