--
-- TOC entry 1147 (class 1255 OID 65008)
-- Name: trip_share_auto_create_v1(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trip_share_auto_create_v1(p_ride_id uuid, p_rider_id uuid, p_ttl_minutes integer DEFAULT 120) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_catalog'
    AS $$
declare
  v_role text := auth.role();
  v_ttl integer;
  v_expires_at timestamptz;
  v_existing record;
  v_token text;
  v_token_hash text;
  v_enabled boolean;
  v_settings_ttl integer;
  v_created boolean := false;
  v_ride_status public.ride_status;
  v_i int;
begin
  -- Only service-role (internal) calls are allowed.
  if v_role is distinct from 'service_role' then
    return jsonb_build_object('ok', false, 'error', 'forbidden');
  end if;

  if p_ride_id is null or p_rider_id is null then
    return jsonb_build_object('ok', false, 'error', 'invalid_args');
  end if;

  -- Validate ride ownership + status.
  select r.status
    into v_ride_status
  from public.rides r
  where r.id = p_ride_id
    and r.rider_id = p_rider_id
  limit 1;

  if not found then
    return jsonb_build_object('ok', false, 'error', 'not_found');
  end if;

  if v_ride_status is distinct from 'in_progress'::public.ride_status then
    -- Defensive: trigger already filters for in_progress.
    return jsonb_build_object('ok', true, 'ignored', true, 'reason', 'not_in_progress');
  end if;

  -- Safety settings (defensive; trigger should already have checked this).
  select uss.auto_share_on_trip_start, uss.default_share_ttl_minutes
    into v_enabled, v_settings_ttl
  from public.user_safety_settings uss
  where uss.user_id = p_rider_id
  limit 1;

  if not coalesce(v_enabled, false) then
    return jsonb_build_object('ok', true, 'ignored', true, 'reason', 'disabled');
  end if;

  v_ttl := greatest(5, least(1440, coalesce(p_ttl_minutes, v_settings_ttl, 120)));
  v_expires_at := now() + (v_ttl * interval '1 minute');

  -- Idempotency: if an active token already exists for this ride + rider, reuse it.
  select t.token_hash, t.expires_at
    into v_existing
  from public.trip_share_tokens t
  where t.ride_id = p_ride_id
    and t.created_by = p_rider_id
    and t.revoked_at is null
    and t.expires_at > now()
  order by t.expires_at desc
  limit 1;

  if found and v_existing.token_hash is not null then
    -- Ensure a notification exists (best-effort; do not spam duplicates).
    if not exists (
      select 1
      from public.user_notifications n
      where n.user_id = p_rider_id
        and n.kind = 'trip_share'
        and (n.data ->> 'ride_id') = p_ride_id::text
        and (n.data ->> 'reason') = 'auto_trip_start'
        and n.created_at > (now() - interval '7 days')
      limit 1
    ) then
      insert into public.user_notifications(user_id, kind, title, body, data)
      values (
        p_rider_id,
        'trip_share',
        'Trip started â€” share link ready',
        'Your trip has started. Share this private link with trusted contacts.',
        jsonb_build_object(
          'ride_id', p_ride_id,
          'token', v_existing.token_hash,
          'expires_at', v_existing.expires_at,
          'reason', 'auto_trip_start'
        )
      );
    end if;

    return jsonb_build_object(
      'ok', true,
      'token_created', false,
      'token', v_existing.token_hash,
      'expires_at', v_existing.expires_at
    );
  end if;

  -- Create a new token (safe retry; extremely low collision probability).
  v_i := 0;
  while v_i < 3 loop
    v_i := v_i + 1;
    v_token := encode(extensions.gen_random_bytes(32), 'hex');
    v_token_hash := encode(extensions.digest(v_token, 'sha256'), 'hex');

    begin
      insert into public.trip_share_tokens(ride_id, created_by, token_hash, expires_at)
      values (p_ride_id, p_rider_id, v_token_hash, v_expires_at);
      v_created := true;
      exit;
    exception
      when unique_violation then
        -- retry token generation
        null;
    end;
  end loop;

  if not v_created then
    return jsonb_build_object('ok', false, 'error', 'token_collision');
  end if;

  -- Event row (dedupe by existence).
  if not exists (
    select 1
    from public.trusted_contact_events e
    where e.user_id = p_rider_id
      and e.ride_id = p_ride_id
      and e.event_type = 'auto_share_token_created'
    limit 1
  ) then
    insert into public.trusted_contact_events(user_id, ride_id, event_type, status, payload)
    values (
      p_rider_id,
      p_ride_id,
      'auto_share_token_created',
      'ok',
      jsonb_build_object('ttl_minutes', v_ttl, 'expires_at', v_expires_at)
    );
  end if;

  -- In-app notification (will enqueue existing notifications outbox via trigger).
  insert into public.user_notifications(user_id, kind, title, body, data)
  values (
    p_rider_id,
    'trip_share',
    'Trip started â€” share link ready',
    'Your trip has started. Share this private link with trusted contacts.',
    jsonb_build_object(
      'ride_id', p_ride_id,
      'token', v_token_hash,
      'expires_at', v_expires_at,
      'reason', 'auto_trip_start'
    )
  );

  return jsonb_build_object(
    'ok', true,
    'token_created', true,
    'token', v_token_hash,
    'expires_at', v_expires_at
  );
end;
$$;


ALTER FUNCTION public.trip_share_auto_create_v1(p_ride_id uuid, p_rider_id uuid, p_ttl_minutes integer) OWNER TO postgres;

--
-- TOC entry 10023 (class 0 OID 0)
-- Dependencies: 1147
-- Name: FUNCTION trip_share_auto_create_v1(p_ride_id uuid, p_rider_id uuid, p_ttl_minutes integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.trip_share_auto_create_v1(p_ride_id uuid, p_rider_id uuid, p_ttl_minutes integer) IS 'Service-role only: idempotently create a trip share token for the rider when a ride enters in_progress and auto-share is enabled; emits a user notification.';


--
-- TOC entry 927 (class 1255 OID 65006)
-- Name: trip_share_create_user_v1(uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trip_share_create_user_v1(p_ride_id uuid, p_ttl_minutes integer DEFAULT 120) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'extensions', 'pg_catalog'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_ttl integer;
  v_expires_at timestamptz;
  v_token text;
  v_token_hash text;
  v_is_participant boolean;
begin
  if v_user_id is null then
    return jsonb_build_object('ok', false, 'error', 'unauthorized');
  end if;

  -- Validate ride membership (rider/driver). We return NOT_FOUND (not FORBIDDEN)
  -- to avoid leaking ride existence.
  select exists(
    select 1
    from public.rides r
    where r.id = p_ride_id
      and (r.rider_id = v_user_id or r.driver_id = v_user_id)
  ) into v_is_participant;

  if not v_is_participant then
    return jsonb_build_object('ok', false, 'error', 'not_found');
  end if;

  v_ttl := greatest(5, least(1440, coalesce(p_ttl_minutes, 120)));
  v_expires_at := now() + (v_ttl * interval '1 minute');

  -- Revoke any still-active tokens created by this user for this ride.
  update public.trip_share_tokens
    set revoked_at = now()
  where ride_id = p_ride_id
    and created_by = v_user_id
    and revoked_at is null
    and expires_at > now();

  -- Generate a new random token and store only the SHA-256 hex hash.
  v_token := encode(extensions.gen_random_bytes(32), 'hex');
  v_token_hash := encode(extensions.digest(v_token, 'sha256'), 'hex');

  insert into public.trip_share_tokens (ride_id, created_by, token_hash, expires_at)
  values (p_ride_id, v_user_id, v_token_hash, v_expires_at);

  return jsonb_build_object(
    'ok', true,
    'token', v_token,
    'expires_at', v_expires_at
  );
end;
$$;


