--
-- TOC entry 1138 (class 1255 OID 64685)
-- Name: webauthn_create_challenge(text, uuid, text, text, bytea); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.webauthn_create_challenge(p_challenge_type text, p_user_id uuid DEFAULT NULL::uuid, p_session_id text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text, p_challenge bytea DEFAULT NULL::bytea) RETURNS TABLE(challenge_id uuid, challenge bytea, expires_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_challenge bytea;
begin
  v_challenge := coalesce(p_challenge, gen_random_bytes(32));

  insert into public.webauthn_challenges (challenge_type, user_id, session_id, user_agent, challenge, expires_at)
  values (p_challenge_type, p_user_id, p_session_id, left(p_user_agent, 500), v_challenge, now() + interval '5 minutes')
  returning id, challenge, expires_at
  into challenge_id, challenge, expires_at;
end;
$$;


ALTER FUNCTION public.webauthn_create_challenge(p_challenge_type text, p_user_id uuid, p_session_id text, p_user_agent text, p_challenge bytea) OWNER TO postgres;

