-- TOC entry 587 (class 1259 OID 64820)
-- Name: ops_dispatch_metrics_15m; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.ops_dispatch_metrics_15m WITH (security_invoker='true') AS
 SELECT date_trunc('minute'::text, (created_at - ('00:01:00'::interval * floor((date_part('minute'::text, created_at) / (15)::double precision))))) AS bucket,
    status,
    count(*) AS request_count
   FROM public.ride_requests rr
  GROUP BY (date_trunc('minute'::text, (created_at - ('00:01:00'::interval * floor((date_part('minute'::text, created_at) / (15)::double precision)))))), status;


