--
-- TOC entry 553 (class 1259 OID 63769)
-- Name: ops_fraud_metrics_15m; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.ops_fraud_metrics_15m AS
 SELECT (date_trunc('minute'::text, now()) - make_interval(mins => ((EXTRACT(minute FROM now()))::integer % 15))) AS bucket_start,
    ( SELECT count(*) AS count
           FROM public.fraud_events e
          WHERE (e.created_at >= (now() - '00:15:00'::interval))) AS events_15m,
    ( SELECT count(*) AS count
           FROM public.fraud_cases c
          WHERE ((c.created_at >= (now() - '00:15:00'::interval)) AND (c.status = 'open'::public.fraud_case_status))) AS open_cases_created_15m,
    ( SELECT count(*) AS count
           FROM public.fraud_enforcement_actions a
          WHERE ((a.expired_at IS NULL) AND (a.resolved_at IS NULL) AND ((a.expires_at IS NULL) OR (a.expires_at > now())))) AS active_actions;


ALTER VIEW public.ops_fraud_metrics_15m OWNER TO postgres;

--
-- TOC entry 586 (class 1259 OID 64816)
