--

CREATE VIEW public.ops_webhook_metrics_15m WITH (security_invoker='true') AS
 SELECT date_trunc('minute'::text, (created_at - ('00:01:00'::interval * floor((date_part('minute'::text, created_at) / (15)::double precision))))) AS bucket,
    job_kind AS event_type,
    count(*) AS total_count,
    count(*) FILTER (WHERE (status = 'succeeded'::public.webhook_job_status)) AS success_count,
    count(*) FILTER (WHERE (status = 'failed'::public.webhook_job_status)) AS error_count,
    avg(EXTRACT(epoch FROM (updated_at - created_at))) AS avg_latency_sec
   FROM public.webhook_jobs w
  GROUP BY (date_trunc('minute'::text, (created_at - ('00:01:00'::interval * floor((date_part('minute'::text, created_at) / (15)::double precision)))))), job_kind;


