CREATE POLICY cash_collections_insert ON public.cash_collections FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1
   FROM public.rides r
  WHERE ((r.id = cash_collections.ride_id) AND (r.driver_id = ( SELECT auth.uid() AS uid))))));


--
